INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tiān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/天_tiān.mp3", "天才 天空 天桥 明天 今天 天平,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指自然界，生成的：天然。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间，一昼夜，一段时间：一天。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高处，顶部：天窗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迷信者所谓的“神、佛、仙人或他们的住地”：天意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"气象：天气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高空：太阳出来满天红。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"季节，时节：秋天。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"最，极：天好，就这么办。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50118_蓑_34001.gif","13","上下","艹","蓑","","");
