INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在状语和中心词之间：天气渐渐地冷了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"还用于状语后或补语前：相看月未坠，白地断肝肠。——唐·杜甫《越女词》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"又表示动态，相当于“着”。常附在立、卧、坐等不及物动词的后头。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/23/地_dì.mp3", "土地 地面 菜地 圣地 草地 营地 地点 地形,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地位：易地以处。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"路程：二十里地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地步：置之死地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地面：水泥地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"土地；田地：荒地。");
