INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"花纹或文字的衬托面：白地红花儿的大碗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地方：无地自容。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地球；地壳：地质。");
