INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指别人，他人：助人为乐。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指人的品质、表现：那个人挺好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指人的身体：人不舒服。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指人格或面子：真丢人。");
