INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/3/你_nǐ.mp3", "你们 你的 你好,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称对方（一个人）。有时也指称‘你们’：你军。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指任何人，也可以包括说话人自己：他的生硬态度，叫你不得不生气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与\"我\"、\"他\"配用：同学们你看看我，我看看你，谁也没能答出老师提出的问题。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/31476_髻_39675.gif","16","上下","髟","髻","Bun","http://cdn.ococci.com/dict_ali/2022-02-24/1645715484183085754_1539578f-23dd-9605-30bd-e113396bfc09.mp3");
