INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wǒ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/50/我_wǒ.mp3", "我们 自我 忘我 我方 我国 我军 故我 我行我素,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示泛指(常常是\"你\"、\"我\"对举)：你一言，我一语，说个不停。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词。A. 称说话人自己：我失骄扬君失柳。B. 我们；我们的：我国是一个人口大国。C. 泛指自己的一方：敌我双方力量太悬殊了，要想办法冲出去。");
