INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"位置在高处的，跟\"\"下\"\"相对：上面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"按规定时间进行活动：上课。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指物体表面：脸上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从低处到高处：上山。");
