INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"增添，安装：上菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"登载，登记：上报纸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指时间、处所、部位、范围等：早上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拧紧：上闹钟。⑾〈表〉动作趋向或达到、完成：爬上来。⑿达到一定程度或数量：成千上万。⒀旧时乐谱记音符号之一，相当于简谱的\"\"1\"\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"涂，擦：涂上。");
