INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像雨一样降落得多而密：枪林弹雨。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/80784_溅_28293.gif","12","左右","氵","溅","Splash","http://cdn.ococci.com/dict_ali/2022-02-24/1645715329299350985_40f965de-d5c2-4cbb-8607-fbfb73f65c57.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/81/溅_jiàn.mp3", "溅落 溅射 溅湿 溅水 飞溅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"液体受冲击向四外飞射。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/81/溅_jiān.mp3", "溅溅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔溅溅〕流水声。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"见“浅”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22665_风_39118.gif","4","半包围","风","风","Wind","http://cdn.ococci.com/dict_ali/2022-02-25/1645771943433236959_3cb31d26-23ba-51fb-972d-a126b4425644.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/风_fèng.mp3", "风民,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"被风吹，受风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刮风；吹：春风风人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引申为乘凉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"显扬，表彰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"教育，感化：风民。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fěng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/风_fěng.mp3", "风规 风谏 风谕,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指劝说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"讽刺；委婉劝告。通“讽”：而王与任王后以此使人风止李太后，李太后内有淫行，亦已。——《史记·梁孝王世家》");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"讽诵。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/风_fēng.mp3", "作风 东风 冷风 顺风 风暴 风波 风云,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"举止：我们能够去掉不良作风，保持优良作风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟地面大致平行的流动着的空气，是由于气压分布不均而形成的：一个欲绽的花苞，在风中摇着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"风俗：学雷锋，做好事，已在学校蔚然成风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像风那样快或那样普遍的：当时《生活》周刊风行海内外，声势日大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消息；情况：会议刚结束，就不知谁露了风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"景象：乌龙潭风景最好，三面依山，一面临水。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63066_揉_25545.gif","12","左右","扌","揉","Knead","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"róu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/揉_róu.mp3", "揉搓 揉面 揉眼 揉手 揉磨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"她一面揉着面，一面和我聊着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抓挠：给我揉一揉背吧。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两手来回地搓：他把纸揉烂了，放进炉子里。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/62834_花_33457.gif","7","上下","艹","花","Flower","http://cdn.ococci.com/dict_ali/2022-02-25/1645772381274143679_55d84d62-531e-bdd4-cb40-4be9d066b85b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/花_huā.mp3", "花卉 花灯 花茶 花消 花甲 泪花 浪花 雪花儿 天花 印花,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有花纹的：这件衣服很花，适合年轻人穿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"种子植物的有性繁殖器官，有各种的形状和颜色，由花瓣、花萼、花托、花蕊组成，一般花谢后结果。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻指容貌秀丽的女孩子：同学们都戏称她\"校花\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"烟火燃放时能喷出许多火花，供人观赏：绽开的礼花把节日的夜晚装点得更加绚丽多彩。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用来迷惑人的；不真实的：不要用花言巧语欺骗别人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在战斗中受伤：战斗非常激烈，不少战士挂了花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"精华：齐白石的国画，堪称艺术之花。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/1831_舀_33280.gif","10","上下","臼","舀","Scoop","http://cdn.ococci.com/dict_ali/2022-02-22/1645535847029396703_e52dbec1-a4d6-af38-a9a8-9d1f2fc9f7af.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/130/舀_yǎo.mp3", "舀水 舀子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用瓢、勺等取东西（多指流体）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/51070_鸟_40479.gif","5","独体","鸟","鸟","Bird","http://cdn.ococci.com/dict_ali/2022-02-25/1645774411646923163_91309fba-dfdd-cfeb-8ee8-b5e61933e2be.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/201/鸟_diǎo.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人、畜雄性生殖器。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"niǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/201/鸟_niǎo.mp3", "鸟  益鸟 鸟语 鸟巢 鸟群 鸟瞰  候鸟,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脊椎动物的一类。温血，卵生，用肺呼吸，全身有羽毛，后肢能行走，前肢多变为翼，能飞，也有的两翼退化，不能飞行。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/8785_揩_25577.gif","12","左右","扌","揩","Wipe","http://cdn.ococci.com/dict_ali/2022-02-24/1645712154058529853_1c31b69c-3982-000c-6350-769c9a85d41c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kāi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/揩_kāi.mp3", "揩抹 揩油 揩拭 揩擦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"擦，抹：揩背；揩油；揩鼻涕；揩眼泪。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/67105_虫_34411.gif","6","独体","虫","虫","Worm","http://cdn.ococci.com/dict_ali/2022-02-25/1645773243272447483_5f62f612-a340-547d-daef-c5c623b69094.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/虫_chóng.mp3", "虫子 虫灾 昆虫 蛀虫 害虫 懒虫 益虫 蚊虫,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫；虫子：地里的庄稼遭了虫害。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90625_碟_30879.gif","14","左右","石","碟","Dish","http://cdn.ococci.com/dict_ali/2022-02-25/1645754315883024480_e41a8bfd-1d1f-259e-6764-3de90f25916d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/107/碟_dié.mp3", "碟子 飞碟 光碟 影碟,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"盛食物等的器具，比盘子小，扁而浅。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34329_六_20845.gif","4","上下","八","六","Six","http://cdn.ococci.com/dict_ali/2022-02-25/1645774371805760143_1aa4ba0e-a804-eb9b-1a8c-298aa179dae3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/六_liù.mp3", "六书 六合 六指 六神 六畜 六亲 六月飞雪 六亲不认 六神无主,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数词。五加一的和：春风杨柳万千条，六亿神州尽舜尧。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/六_lù.mp3", "六安 六合,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"六安：地名，在中国安徽省。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"六合：地名，在中国江苏省。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/66535_捆_25414.gif","10","左右","扌","捆","Bundle","http://cdn.ococci.com/dict_ali/2022-02-24/1645700941360525200_7989a301-31c5-2469-6ee9-92d40908b507.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kǔn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/53/捆_kǔn.mp3", "捆扎 捆柴 捆绑 捆紧,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用绳把东西缠紧打结。他被绳子捆着手，肩上流着血，脸上有着一块块搏斗的伤痕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。相当于\"束\"：这捆旧报纸没用了，把它拿去卖了吧!");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/95051_七_19971.gif","2","独体","一","七","Seven","http://cdn.ococci.com/dict_ali/2022-02-25/1645769098423711747_243b468c-948c-298b-bcbb-1ac6777740d3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/七_qī.mp3", "七夕 七彩 七窍 七上八下,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数词。六加一后所得：一周有七天。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39432_巅_24005.gif","19","上下","山","巅","Top","http://cdn.ococci.com/dict_ali/2022-02-24/1645709236753591519_e80d18ed-2376-491f-8c54-32c39433e103.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/39/巅_diān.mp3", "巅峰 顶巅 危巅 巅越 山巅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"山顶：巅峰；山巅。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/41151_八_20843.gif","2","独体","八","八","Eight","http://cdn.ococci.com/dict_ali/2022-02-25/1645768852948606622_1cef4620-a714-a61e-d935-ab35e2836af5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/八_bā.mp3", "八方 八哥 八卦 八角 八宝粥 八路军 八面威风,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数目字：开调查会每次人不必多，七八个人即够。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87642_劈_21128.gif","15","上下","刀","劈","Split","http://cdn.ococci.com/dict_ali/2022-02-25/1645758247684506390_8ec3d094-8821-6f10-9411-b3c5d7b69160.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/pǐ.mp3", "劈柴 劈叉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分开：劈柴。劈成三股。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分裂，使从原物上分开：把菜帮儿劈下来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"腿或手指等过分叉开：劈叉。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/11/劈_pī.mp3", "劈叉 劈柴 劈成 劈账,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用刀斧或强力破开。雷电击坏或击毙。冲着，正对着。两个斜面合成的纵截面呈三角形的简单机械，刀、斧、楔子等各种切削工具的刃都属于这一类（亦称“尖劈”）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98433_九_20061.gif","2","独体","丿","九","Nine","http://cdn.ococci.com/dict_ali/2022-02-25/1645774446594970641_599f09b2-e5db-8dcc-d205-72cc424a1163.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/九_jiǔ.mp3", "九族 九鼎 三九 九流三教 九回肠断 九霄云外 九死一生,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时令名。数九，从冬至起，每九天为一个\"九\"，共九个\"九\"：头九、二九不算九，冷在三九和四九。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数目：隔壁房里的钟声传过来，是九下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示多次或多数：我失骄杨君失柳，杨柳轻茤直上重霄九。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54949_捂_25410.gif","10","左右","扌","捂","Cover","http://cdn.ococci.com/dict_ali/2022-02-25/1645758107160495518_c6aee4b5-a6ad-36f1-2a28-38a57940b992.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/53/捂_wǔ.mp3", "捂住 捂盖子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"严密地遮盖住或封闭起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“迕”，逆，对面。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35177_十_21313.gif","2","独体","十","十","Ten","http://cdn.ococci.com/dict_ali/2022-02-25/1645768887231607069_0f993280-5902-c810-4635-3b81fa7af9e6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/13/十_shí.mp3", "十分 十拿九稳 十全十美,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数名，九加一：十羊九牧。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"完全，〈表〉到达顶点：十足。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87146_踱_36401.gif","16","左右","足","踱","Pace","http://cdn.ococci.com/dict_ali/2022-02-23/1645587984888198760_4389b302-36ed-348d-6410-aa570848bba3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"duó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/161/踱_duó.mp3", "踱步 踱方步 踱来踱去,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"慢步行走：我在梅林里踱了许久，思考着我究竟该怎么办。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52648_爸_29240.gif","8","上下","父","爸","Dad","http://cdn.ococci.com/dict_ali/2022-02-25/1645766108950040606_5375b498-9924-91af-98f4-b67b8f82471e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/爸_bà.mp3", "爸爸 老爸 阿爸,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"父亲：咱爸是缴过敌人一挺机关枪的战斗英雄。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63706_碾_30910.gif","15","左右","石","碾","Crush","http://cdn.ococci.com/dict_ali/2022-02-20/1645337487491403734_01588ce3-0af8-b26d-b0ac-d415d6416058.mp3");
