INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/妈_mā.mp3", "妈妈 干妈 奶妈 姑妈 舅妈 姨妈 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指母亲，常叠用：不错，那女人曾说过要当他的好妈妈。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称长一辈或年长的已结婚的妇女：姑妈与我们分别了近30年。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧时连着姓称中年或老年的女仆：小姐是张妈一手带大的，所以从不把她看作仆人。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/9529_搁_25601.gif","12","左右","扌","搁","Put aside","");
