INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"禁（jīn）受，承受。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/搁_gē.mp3", "搁笔 搁浅 搁置 耽搁 搁起,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放置，引申为停滞。");
