INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/192/马_mǎ.mp3", "马上 驸马 快马 河马 下马 骑马 马力,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物，颈上有鬃，尾生长毛，四肢强健，善跑，供人骑或拉东西：马匹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大：马蜂。");
