INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/23/土_tǔ.mp3", "国土 沙土 土产 土地 尘土 土邦 土豆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"故乡，本地的：乡土。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地域：国土。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"民间生产的，出自民间的：土产。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不开通，不时兴：土里土气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"五行（金木水火土）之一。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"沙泥等的混合物：土壤。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43912_脐_33040.gif","10","左右","月","脐","Umbilicus","");
