INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"肚子上脐带脱落的痕迹。脐带是胎儿肚子中间连结母体胎盘以吸取营养的管子：肚脐。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"螃蟹腹部下面的甲壳：尖脐（雄性）；团脐（雌性）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73485_不_19981.gif","4","独体","一","不","Nope","http://cdn.ococci.com/dict_ali/2022-02-23/1645598931615370020_71c9a8f8-bd36-a038-ab3a-9a270981b304.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/不_bù.mp3", "不适 不安 不幸 不必 不便 力不从心 赞不绝口,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示否定的意义：他不来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示否定地方的话：这话说得不对。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟\"就\"搭用，表示选择：他在休息的时候，不是看书，就是看报。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在肯定句末，构成问句：他来不？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/95184_蹬_36460.gif","19","左右","足","蹬","Pedal","http://cdn.ococci.com/dict_ali/2022-02-19/1645275976873692435_93f74800-b963-eb4c-cd88-ec61538441d7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹬_dèng.mp3", "蹭蹬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蹭蹬:路途险阻难行。比喻困顿不顺利。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹬_dēng.mp3", "蹬踏 踢蹬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"踩，踏：小王蹬在阳台上想伸手摘朵玫瑰花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"穿（鞋、裤子等）：蹬上裤子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"腿或脚向脚底方向狠狠用力：翠鸟蹬开苇杆，像箭一样飞过去叼起小鱼。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32395_画_30011.gif","8","半包围","田","画","Painting","http://cdn.ococci.com/dict_ali/2022-02-25/1645773235478791619_ae7f45a3-7bd2-174b-9931-0ad7db3052fb.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/98/画_huà.mp3", "画报 画布 画册 画家 画出 字画 画幅 绘画 画押 年画儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"图；画成的艺术品：走廊拱形天花板上是勒勃兰的巨幅油画，展现出一幅幅风起云涌的历史画面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"绘画；作图：元朝著名书画家赵孟兆页所画山水、人物、鞍马、花鸟，无不精细传神。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比画：竖起大拇指霍地在空中画了个半圆形。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"签署；做记号为凭证：她含泪在卖身契上画押。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"汉字的一笔叫一画：这个字共有多少画？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/19475_绷_32503.gif","11","左右","纟","绷","Tense","http://cdn.ococci.com/dict_ali/2022-02-21/1645446294273279942_c3bf5210-130e-3b47-5f6c-5ff6e3a13a98.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/bèng.mp3", "绷瓷儿 绷硬 绷亮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"裂开：绷瓷儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言，用在某些形容词前面，有“很”的意思：绷硬。绷亮。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"běng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/绷_běng.mp3", "绷脸 绷着脸,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用尽(如自己的全力)。如：咬住牙，绷住劲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"板着。如：绷脸。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/绷_bēng.mp3", "绷子 绷索 绷紧 绷带,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"张紧，拉紧。当中用藤皮、棕绳等物绷紧的竹木框。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（物体）猛然弹起。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种缝纫方法，粗粗缝上或用针别上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"束，包扎。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"勉强支持。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言，骗财物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43758_打_25171.gif","5","左右","扌","打","Hit","http://cdn.ococci.com/dict_ali/2022-02-25/1645751633243490519_a2e13871-9282-93a4-d063-2cd499ceaaf8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dá", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/打_dá.mp3", "一打火柴 一打鸡蛋 一打铅笔,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"12个构成的一组。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/打_dǎ.mp3", "打扮 打人 打蜡 打醋 拍打 扑打 双打 打铁 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"攻击：此役宜先打锦州，再围沈阳。打一枪，换一个地方。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"发出：他那完全是歪打正着。⑾编织。妈妈教我打毛衣。⑿注入：她今天去打针了。⒀举；提：看看你，打起精神来。⒁捆扎：他把自己的东西打包好，准备离开了。⒂使破裂或穿透：他们把隧道打通了。⒃搅拌：打浆。⒄从事某种工作：他一直在打听他女儿的工作状况。⒅人的某种特定动作：他总是一副无精打采的样子。⒆进行文体活动：他们在打拳。⒇采用某种手段或方式：你这是趁火打劫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"捕捉；猎取：渔夫们忙着下网打鱼，任小船随意漂流。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"制作(器物)：李师傅打的这把刀锋利无比。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"除去：花农们常常为一些花树打杈，以便花能更好地生长。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计算：张老师告诫我们，写作文打草稿也得认真。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因撞击而破碎：早就劝你不要那么冲动，好好考虑下再做，现在好了，鸡飞蛋打一场空。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"殴打；吵架：他们俩经常大打出手。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"涂抹：这辆已使用多年的汽车经工人打蜡后，又焕然一新了。");
