INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/妹_mèi.mp3", "阿妹 姐妹 妹妹 表妹 姊妹 堂妹 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同父母或只同父、只同母的比自己年纪小的女子：妹妹你再跟我耍贫嘴，我可真火了啊!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对比自己年纪小的同辈女性的称呼：他和表妹在同一所大学深造。");
