INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"倚仗势力或抓住人的弱点强迫人服从：要挟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用胳膊夹着：挟持。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"心里怀着（怨恨等）：挟恨。");
