INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/奶_nǎi.mp3", "牛奶 奶茶 奶粉 奶酪 奶妈  奶油,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"婴幼儿时期的：他还不到四个月，就长出两颗奶牙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"乳房，哺乳的器官：女人们垂下头去，拿奶子往小孩子嘴里塞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"乳汁的通称：她因为爱孩子，不愿意雇别的女人给孩子喂奶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用母乳喂孩子：姑娘就是张妈奶大的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7417_溺_28346.gif","13","左右","氵","溺","Drowning","http://cdn.ococci.com/dict_ali/2022-02-24/1645706219522629481_5792b831-604f-1471-8458-98edbb990f06.mp3");
