INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"淹没在水里，水淹：她用湿的手把飞着的蝴蝶打下来，一个落到盆中溺死了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"沉迷不悟，过分：溺爱；溺信。");
