INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排行最末：他是我的小舅舅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"体积、面积、数量或力量等都不如一般的或不及比较的对象。与\"大\"相对：杜甫比李白小11岁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间短：我到广东从化温泉小住了几天。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对小辈的爱称：小明明，你上哪里去?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"他在科研方面小有作为。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年幼小的：你们这一老一小真有意思，都是从别人身上汲取力量!");
