INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xuě", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/183/雪_xuě.mp3", "雪花 雪莲 雪冤 雪耻 雪亮 雪豹 雪原 雪崩 雪糕 下雪 洗雪 昭雪 雪上加霜 雪中送炭,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像雪一样白的：雪浪拍长空，阴森疑鬼怒。");
