INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，指一束理顺了的丝，线、须、发等：一绺青丝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丝缕的组合物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衣服因下垂而起直皱：打绺儿。");
