INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ér", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/儿_ér.mp3", "儿女 儿孙 儿歌 儿童 幼儿 儿戏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"雄性的：这是一匹儿马。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小孩子：儿童是祖国的未来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年轻的男性：好男儿志在四方。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"少数动词的后缀：我到同学家去玩儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词。用于名词词尾。A. 表示微小：他用一个小盆儿当饭盒。B.表示词性变化：我的工资和他的收入相比，简单是零碎儿。C. 表示具体事物抽象化：这汤没一点油水儿。D. 表示词义变化：这不是白面，而是白面儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"父母对儿女的统称：儿啊!你一定要为祖国争光。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3968_鬈_39688.gif","18","上下","髟","鬈","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"quán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/194/鬈_quán.mp3", "鬈须 鬈心 发鬈 虿鬈 鬈髻 鬈毛 鬈曲 鬈首 鬈笄,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"头发卷曲：鬈发（弯曲的头发）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"头发好，引申为美好：鬈，发好也。——《说文》。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52813_白_30333.gif","5","独体","白","白","White","http://cdn.ococci.com/dict_ali/2022-03-09/5423671000000061_1646805101020.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bái", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/101/白_bái.mp3", "白天 白色 白花 明白 对白 白桦 苍白 银白,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"没有效果：白干了一天。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"陈述、表白说明。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清楚明白：真相大白。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"没有加上什么东西：白开水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亮：东方发白。");
