INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/134/草_cǎo.mp3", "花草 甘草 水草 青草 芳草 山草 草率 草地 草坪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"草本植物的统称：荒山野岭，寸草不生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"马虎：作文要字迹清楚，不要潦草。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"初稿：誊写之前最好先打草稿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"汉字字体的一种名称：他楷书还没写好就要练草书。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/62534_娄_23044.gif","9","上下","女","娄","Lou","http://cdn.ococci.com/dict_ali/2022-02-24/1645689934925752470_d79b3dae-11ce-163f-a738-d9e1942f462b.mp3");
