INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"星名，二十八宿之一。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（身体）虚弱：他的身体可娄啦。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（某些瓜类）过熟而变质：西瓜娄了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/83664_家_23478.gif","10","上下","宀","家","Home","http://cdn.ococci.com/dict_ali/2022-02-25/1645767095202620693_215377eb-ae84-2c42-1349-1183d606bbc1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/34/家_jiā.mp3", "家庭 家务 大家 家乡 家常 当家 作家 家访,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"我们提倡百家争鸣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"家庭；人家：你想家吗?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由人喂养的禽兽：这个村多数农户靠发展农禽家畜致富。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"谦辞。对人称自家的年长者或辈分高的；家父是一个憨厚的庄稼人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"家庭所在的地方：让战争期间逃亡的人回家，恢复原有的田宅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：这个独院住有八家人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在词尾(读jia)，指一类人：你老人家好吗？");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jie", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/34/家_jie.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"词尾，同“价”：整天家；成年家。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jia", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/家_jia.mp3", "老人家,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"词尾，指一类的人：老人家。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在男人的名字或排行后面，指他的妻：水生家。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/9986_猝_29469.gif","11","左右","犭","猝","Burst","http://cdn.ococci.com/dict_ali/2022-02-25/1645763301617334206_d7e65d75-4be3-4c8b-6ce8-05e67e0488e6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/93/猝_cù.mp3", "猝不及防 猝倒 猝尔 猝发 猝然 猝死,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"突然：猝死（突然发生的非暴力死亡）；猝故（突然发生的事变）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85848_是_26159.gif","9","上下","日","是","Yes","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647480711179.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/60/是_shì.mp3", "不是 可是 是的 是非 是否 实事求是,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对，正确，合理，跟\"\"非\"\"相对：是的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"这，这个，这样：是可忍，孰不可忍。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉解释或分类：她是学生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉答应：是，我马上去办。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉存在：遍街都是人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉让步，含\"\"虽然\"\"之义：这椅子旧是旧，但很结实，还能用。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉赞同，认为对：是的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉凡是，一切：是重活他都抢着干。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉适合：他走的是时候。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉加重语气：惟你是问。⑾〈表〉判断：共产主义是人们的最高理想。⑿用于问句：你是坐火车还是坐飞机？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/89128_镭_38253.gif","18","左右","钅","镭","Radium","http://cdn.ococci.com/dict_ali/2022-02-09/1644409232055991197_6acb7340-2185-e3f7-d002-63d4e39382d0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"léi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/180/镭_léi.mp3", "镭疗 镭射气 镭疗器,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"为碱土族的一个强放射性的金属元素，以化合状态极少量地存在于沥青铀矿、钾钒铀矿以及其他铀矿中，质量数为226的同位素：镭疗。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76469_车_36710.gif","4","独体","车","车","Vehicle","http://cdn.ococci.com/dict_ali/2022-02-25/1645769246187494123_ba6079ba-e904-e379-7831-1ac472a547c9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/车_chē.mp3", "我刚才看见一辆汽车往村长家方向去了。,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用水车取水：他俩车了一天的水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在陆地上用轮子转动前进的交通工具：集市上车水马龙，人来人往，热闹非凡。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"利用轮轴旋转的器具：这是一辆旧式纺车。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用车床切割东西：把这个零件再车圆一点。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/车_jū.mp3", "舍车保帅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"国际象棋中的一种棋子，它可以顺着平行于棋盘边的路随便走多少方格，假如没有其它棋子阻挡的话。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国象棋棋子的一种。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43712_钋_38027.gif","7","左右","钅","钋","Polonium","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/177/钋_pō.mp3", "钋元素,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种放射性金属元素，在铀矿及锡石中有微量存在。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/19979_路_36335.gif","13","左右","足","路","Road","http://cdn.ococci.com/dict_ali/2022-02-25/1645767908563541314_73ad0929-73c8-57b1-9567-99ed25f5bd16.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/161/路_lù.mp3", "道路 迷路 思路 铁路 走路 筑路 路口,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"道，来往的通道：路途。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"种类：头路货。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方面，地区：几路进攻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈古〉车：筚路（柴车）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宋、元时代行政区域名称。宋代的\"\"路\"\"相当于现代的\"\"省\"\"；元代的\"\"路\"\"相当于现代的\"\"地区\"\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方向，条理，途径：出路。");
