INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"慢步行走：我在梅林里踱了许久，思考着我究竟该怎么办。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39398_灯_28783.gif","6","左右","火","灯","Light","http://cdn.ococci.com/dict_ali/2022-02-25/1645761692249409851_e218c235-1401-a711-48fa-019581a84b94.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/86/灯_dēng.mp3", "电灯 吊灯 宫灯 花灯 幻灯 灯具 尾灯 路灯 提灯,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"俗称电子管收音机：爷爷家里有一种早期的熊猫牌五灯收音机。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"照明或做其他用途的发光器具：他顺手把灯打开。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/70741_迂_36802.gif","6","半包围","辶","迂","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/165/迂_yū.mp3", "迂回 迂缓 迂腐 迂论,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"言行或见解陈旧不合时宜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"曲折，绕远。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24738_走_36208.gif","7","上下","走","走","Go","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/159/走_zǒu.mp3", "行走 奔走 走样 走向 走失 溜走  慢走 走廊 走路,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"步行：其实地上本没有路，走的人多了也便成了路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排动：亲戚越走越亲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"下棋有下棋的规矩，各人有各人的走法。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泄漏：快把瓶盖盖好，不要让它走了气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经过：咱们走这个门进去吧!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"离开：明天再谈吧，我今天要走了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/2530_拭_25325.gif","9","左右","扌","拭","Wipe","http://cdn.ococci.com/dict_ali/2022-02-24/1645712154058529853_1c31b69c-3982-000c-6350-769c9a85d41c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/52/拭_shì.mp3", "拭除 拭目倾耳 拭子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"揩擦。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/61801_秋_31179.gif","9","左右","禾","秋","Autumn","http://cdn.ococci.com/dict_ali/2022-02-25/1645763294022768549_2264e2ed-7b85-0665-569e-3d1c72238608.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/110/秋_qiū.mp3", "秋风 秋凉 秋天 中秋 深秋,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"秋季，一年四季中的第三季：到了秋天，树叶黄了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"庄稼成熟或成熟时节：我去时，正是孟夏麦秋时节。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"秋天成熟或秋天播种的作物：支部大会决定集中力量种秋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指一整年的时间：千秋万代之后，我们的祖国该有多么美啊!");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48156_搀_25600.gif","12","左右","扌","搀","Adulterate","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/搀_chān.mp3", "搀杂 搀假 搀和 搀扶 搀兑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用手轻架住对方的手或胳膊。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"混合、搀和。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73124_气_27668.gif","4","独体","气","气","Qi","http://cdn.ococci.com/dict_ali/2022-02-25/1645768612469224184_df6e08b2-4aa3-e203-351d-0079528d45b7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/75/气_qì.mp3", "天气 气候 气象 才气 勇气 朝气 大气,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人的精神状态、作风、风度、力量等：朝气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"欺负，欺压：受气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"怒，使人发怒：生气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"无一定形状，能自由散布的物体：气体。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"气势，气氛：喜气洋洋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"自然界冷、热等现象：天气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迷信者所谓的\"\"命运\"\"：气数。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中医指体内具有某种功能的物质：气虚。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"呼吸：气息。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闻到的味儿：气味。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32806_箸_31672.gif","14","上下","竹","箸","Chopsticks","http://cdn.ococci.com/dict_ali/2022-02-24/1645710970172761896_47c29729-a61a-d1c5-31c4-53f4881677e2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/115/箸_zhù.mp3", "杯箸 土箸 筹箸 元箸 前箸 竹箸 白箸 渊箸 失匕箸 火箸 闻雷失箸 运筹借箸 沙箸 食箸,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"筷子，又作“筯”：停杯投箸不能食。——唐· 李白《行路难》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"撰写，写作，后作“著”：箸《论衡》八十五篇，二十余万言。——《后汉书》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“著”，显明，显示：知命者也，箸是者也。——《荀子·非十二子》。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/5124_了_20102.gif","2","独体","乛","了","Here we go","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"le", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/了_le.mp3", "走了 下雨了 回家了 去了,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，用在句子末尾或句中停顿的地方，表示变化，表示出现新的情况：刮风了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放在动词或形容词后，表示动作或变化已经完成：写完了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/了_liǎo.mp3", "了解 了却 完了 末了 了结 了然 了得,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结束：此事已了，别再纠缠。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清楚；明晰：他的一举一动，别人都了如指掌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。这一带埋着他们的骨肉，只是埋葬不了他们的记忆。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7757_乍_20045.gif","5","独体","丿","乍","Chad","http://cdn.ococci.com/dict_ali/2022-02-22/1645537836185083612_2772218c-9c18-9e43-e178-35cb224a14dc.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/乍_zhà.mp3", "新来乍到  乍看 乍然,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刚，开始，起初：这马样子也不好看，玻璃眼睛，乍一看去，便瞎了似的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"忽然：这是一个乍冷乍热的季节。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"张开，鼓起：乍着胆子（勉强鼓起勇气）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33761_树_26641.gif","9","左中右","木","树","Tree","http://cdn.ococci.com/dict_ali/2022-02-25/1645771941861156669_0fcae629-cfa8-8968-58f7-7e0835a1b927.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/树_shù.mp3", "树丛 树立 树林 树阴 树木 树梢 建树,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"木本植物的总称：树木。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竖立，建立：树立。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"种植，栽培，培养：十年树木，百年树人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。株，棵：种甘桔千树。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/21286_釉_37321.gif","12","左右","采","釉","Glaze","http://cdn.ococci.com/dict_ali/2022-02-23/1645618968620138920_f9dfcbf4-8bc7-1bb3-1b2b-8e62e5b5df7c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/釉_yòu.mp3", "釉料 釉彩 瓷釉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"覆盖在陶瓷、搪瓷表面的玻璃质薄层：釉子。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/86423_叶_21494.gif","5","左右","口","叶","Leaf","http://cdn.ococci.com/dict_ali/2022-02-25/1645767041571325925_c3ea447a-34cc-5cfa-7084-bb34717c510f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/叶_xié.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"和洽，合：叶韵。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/叶_yè.mp3", "茶叶 枫叶 荷叶 叶酸 枝叶 叶公好龙 落叶归根 红花绿叶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物的叶子：黑背鲲的叫声如风刮树叶，沙沙作响。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像叶子一样的东西：这家商店专门出售百叶窗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时期：二十世纪中叶。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22871_竿_31487.gif","9","上下","竹","竿","Pole","http://cdn.ococci.com/dict_ali/2022-02-25/1645753280884282147_21652388-13d4-f84a-ecb8-9d00cd0f77b6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/113/竿_gān.mp3", "竿子 钓竿 滑竿 爬竿 竹竿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细长的棍子：小猫放下钓鱼竿就去捉蜻蜓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38259_片_29255.gif","4","独体","片","片","Piece","http://cdn.ococci.com/dict_ali/2022-02-25/1645763442539996892_27fd4208-9265-89f3-b3b0-f5b6ce7dc92f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"piàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/片_piàn.mp3", "图片 片段 片刻 片面 卡片 名片  照片,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"切薄成片：片猪肝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"偏而不全：主观片面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大范围内再划分小范围：分片。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"少、短、零星：片刻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。指面积、范围或成片的东西等：一大片麦田。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"破开的木或草：木片。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"piān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/piān.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"义同（一），用于“相片儿”、“电影片儿”等。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93371_轧_36711.gif","5","左右","车","轧","Rolling","http://cdn.ococci.com/dict_ali/2022-02-25/1645772038059062017_8ba76afb-20ef-8670-649c-339d14818677.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/轧_yà.mp3", "轧棉 碾轧 倾轧 轧场 轧道车 轧辊 轧轧,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象声词，形容机器开动时发出的声响：工厂里传出一片轧、轧的织布声。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"压；碾：他过马路时，不幸被汽车轧断了双腿。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhá", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/轧_zhá.mp3", "轧钢 轧机 轧制 轧钢厂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把金属坯压成一定形状。如:轧钢。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55787_大_22823.gif","3","独体","大","大","Big","http://cdn.ococci.com/dict_ali/2022-02-25/1645771329116067787_c0cada07-9e5d-86de-1fbe-4e256c6d6ae7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/大_dà.mp3", "大家 大人 大款 大典 大概  大方 大地 大道 大合唱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"前天或后天的前一天或后一天：表哥到外地出差去了，听说要大后天才能回来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（辈分、职位）高的，有影响的：他爷爷是古代的大臣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在某些季节或时间前，表示强调。他大年初一就摔了一跤。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示与比较的事物粗略相当的程度：她倘一看见两三岁的小孩子，就说：\"唉唉!我们的阿毛如果还在，也就有这么大了。\"");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬辞：请问您的大名是？⑾不是很详细；不很准确：他只知道事情的大概。⑿志向、气度等超过一般：大丈夫有所为有所不为。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在面积、体积、容量、数量、力量、强度、年龄等方面超过一般或超过所比对象：在我们姐妹中，还是小三块头最大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"超出事实，过分：他有点大言不惭。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排行第一的或年纪长的：他是家里的大少爷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"重要的；主要的：你不要因小失大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"程度、规模、声势、时间等超过一般或超过所有的对象：天已经大亮了，你赶快去公司汇报工作吧。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/大_dài.mp3", "大夫 大王,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国戏曲、旧小说中对大帮强盗首领的称呼：大王。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"医生：大夫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用同“代”，世代：陵家历大为军将，世世从军为国征。——《敦煌变文集·李陵变文》");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38537_鳍_40141.gif","18","左右","鱼","鳍","Fins","http://cdn.ococci.com/dict_ali/2022-02-25/1645742191232759553_b5234936-299f-b592-e160-444a55d80f53.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/198/鳍_qí.mp3", "胸鳍、腹鳍、脊鳍、臀鳍、尾鳍,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鱼类的运动器官，由薄膜和硬刺组成，按它所在部位，可分为胸鳍、腹鳍、脊鳍、臀鳍、尾鳍。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37330_飞_39134.gif","3","独体","飞","飞","Fly","http://cdn.ococci.com/dict_ali/2022-02-25/1645768581808757361_fae1d17f-df92-3d77-b7b5-0385ba0e2007.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fēi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/飞_fēi.mp3", "飞机 飞行 飞翔 飞快 飞扬 飞溅 飞驰 飞奔 飞车,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸟在空中展翅行动：树林中有小鸟飞来飞去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"游动：风雨送春归，飞雪迎春到。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形容极快：汽车在高速公路上飞驰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"突然：她被眼前飞来的横祸惊呆了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/12283_蚋_34443.gif","10","左右","虫","蚋","Simulium","http://cdnmu.gurobot.cn/saodubi/dict/audio/Simulium.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ruì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚋_ruì.mp3", "蚁出蚋飞 蚊蚋 蚋序 蚋眦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫，体长二、三毫米，头小，色黑，胸背隆起，吸人畜的血液，幼虫栖于水中。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/61336_会_20250.gif","6","上下","人","会","Will","http://cdn.ococci.com/dict_ali/2022-02-25/1645772780684885385_5dbf5cec-0507-4b40-7bef-f3423a15174a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/2/会_huì.mp3", "开会 会谈 会议 会见 机会 领会 会车,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"聚合；革命雄师会井冈，集中力量更坚强。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"彼此见面：今天，他是来会钱先生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有一定目的聚会或集会：周末，单位组织了一场舞会。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/2/会_kuài.mp3", "会计 会计师 财会,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计算；总计：他在那家小厂当会计。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27272_钹_38073.gif","10","左右","钅","钹","Cymbal","http://cdn.ococci.com/dict_ali/2022-01-26/1643201514460857206_0cbe8e34-2096-3e49-1ddb-138ee2d8bb36.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/钹_bó.mp3", "铜钹 水钹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"铜质圆形的打击乐器，两个圆铜片，中心鼓起成半球形，正中有孔，可以穿绸条等用以持握，两片相击作声：在古代人们用铜钹奏乐。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/82102_个_20010.gif","3","独体","人","个","A","http://cdn.ococci.com/dict_ali/2022-03-30/5423671000000092_1648624380384.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/个_gè.mp3", "个头 个体 个别 个性 各个 逐个 挨个 整个,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"单独的：他是个体劳动者。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指示代词。表示\"此\"、\"这\"：他不愿告诉个中的真意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。A.表示单独的人或物：盘子里放着一个大西瓜。B.指一次动作行为：你好好睡个觉。C.用于动词和补语之间，使补语略带宾语的性质：他一直滔滔不绝地说个不停。今个是你爷爷过90大寿，一定要给他老人家庆贺一下。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gě", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/个_gě.mp3", "自个儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"自己。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54181_绢_32482.gif","10","左右","纟","绢","Silk","http://cdn.ococci.com/dict_ali/2022-02-25/1645765760633164539_d2a8fab2-05fb-b53c-9e9b-837884385532.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"juàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/绢_juàn.mp3", "绢子 绢丝 绢花 绢本,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种薄而坚韧的丝织物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55881_的_30340.gif","8","左右","白","的","Yes","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647480711179.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"de", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/102/的_de.mp3", "美丽的 唱歌的,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在定语后，表示词与词或短语之间的修饰关系：红色的气球，小小的进步。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“得”，后面带补语：那知进了园门，园子里已结坐的满满的了。——《老残游记》");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"<代>，附着在词或短语之后，构成“的”字结构，代替所指的人或物：卖菜的，吃的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“地”(de)。用在状语后，表示状语和中心词之间的修饰关系。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在定语后，表示定语和中心词之间的领属关系：中国的水稻，农民生活的提高。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在两个数量词中间。[口]表示相乘：这间房子是五米的三米，合十五平方米；[方]表示相加：两个的三个，一共五个。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词。“的”字前后用相同的动词、形容词等，连用这样的结构，表示有这样的，有那样的：推的推，拉的拉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在两个同类的词或词组之后，表示“等等、之类”的意思：破铜烂铁的，他捡来一大筐。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在谓语动词后面，强调这动作的施事者或时间、地点、方式等：谁买的书？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在陈述句的末尾，表示肯定的语气：这件事儿我是知道的。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/102/的_dí.mp3", "的确 的当 的款,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"真实；确实；实在：这件事的确是真的。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/102/的_dì.mp3", "目的 中的 端的 有的放矢 无的放矢,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"箭靶的中心；目标：他的这一正确主张，在当时成了众矢之的。");
