INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落叶乔木，木质坚硬，用于制家具、乐器（亦称“青檀”）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浅绛色。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～香〕常绿乔木，产在热带及亚热带，木质坚硬，有香气，可制器物及香料，又可入药。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔紫～〕常绿乔木，木材坚硬，带红色，可制贵重家具或工艺品。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57749_两_20004.gif","7","独体","一","两","Two","http://cdn.ococci.com/dict_ali/2022-02-25/1645768723677126485_340b6f8c-3749-c30c-cce0-3ed08713e6d2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/两_liǎng.mp3", "两面 两旁 两头 两用 银两 两厢情愿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示不定的数目，相当于\"几\"：我过两天再到你那儿去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数目(一个加一个)：那朱红与亮蓝两种颜色鲜明极了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"重量单位。一斤等于十两，一两等于十钱：老王买了四两干饭、一碗汤和一碟咸菜独自吃着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"双方(指相对的两个方面)：你们何必要搞得两败俱伤呢!");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/18421_冗_20887.gif","4","上下","冖","冗","Redundancy","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"rǒng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/冗_rǒng.mp3", "迁冗 烦冗 赘冗 百冗 浮冗 疏冗 顽冗 愚冗 闲冗 贱冗 匆冗 靡冗,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"忙，繁忙的事：拨冗（忙中抽出时间）；冗务缠身。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闲散的，多余无用的：冗长（cháng）；冗员。");
