INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接近：事到临头。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"词尾（读轻声）：石头。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脑袋，人体的最上部分或动物体的最前部分：头颅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。指牲畜、像头的、不定数量等：五头猪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"以前，在前面的：头三年。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物体的顶端、前端或事情的起点、终点：山头。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"第一，开初的：头等舱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"为首的（多用于贬义）：头领。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方面：他们几个是一头的。");
