INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"让视线接触人或物：看书看报的时候，遇到有关桥的资料，他都仔细收集起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"观察判断：你看他像不像一个好人?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"诊治：下午你带他去看一下病。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"照应：一连三天他都在医院照看病人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"访问，拜望：我得去看我的朋友。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"看待：他露了这一手后，人们不得不对他另眼相看了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词。你仔细想想看，到底把它搁哪儿呐?");
