INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/150/见_jiàn.mp3", "看见 见机 见面 见解 见怪 见到,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"看得出，显现出：吃了好多的药，病仍不见好转。");
