INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"会晤：他在等待皇上的召见。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在表体积、长度等数量后面，表分数：这扇门六尺见高，二尺五见宽。");
