INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"是，对，允许：认可。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"认为，感到，够得上：可耻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能：可吃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"加重语气：她做事可真快。");
