INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"采地，古代士大夫的封邑，又叫采邑，食邑，采地。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/采_cǎi.mp3", "开采 采购 采矿 采煤 采取 采办 采用 采访,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"掘取：大学毕业之后，他主要从事采矿工作。");
