INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多年生草本植物，生在浅水中，地下茎肥大且有节，叶圆形，花大，呈白色或浅红色，有香味。生在地下的茎叫藕，可鲜吃，也可以制成藕粉。种子叫莲子，是滋补的好食品。藕节、荷叶及莲子均可入药：莲，花之君子者也。");
