INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"四季中的第一个季节：一排排绿树迎春风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指男女情欲：青年男女容易春心萌动。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻生机：他的医术真称得上是妙手回春。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年岁：爷爷已届70春。");
