INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧时指地位卑下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"谦辞，旧称与自己有关的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"骂人的话。指撒娇或不尊重、不知好歹。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/78956_青_38738.gif","8","上下","青","青","Qing","http://cdn.ococci.com/dict_ali/2022-02-25/1645772514860055820_10f9d5ef-6822-6655-0e88-9444f73580d8.mp3");
