INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"深绿色的东西，多指嫩苗的庄稼、花草等：踏青。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"原指写在竹简上的记事，后指史书：青史。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈喻〉年轻，也指青年：青春。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"颜色：a.深蓝色：青，取之于蓝，而胜于蓝。b.深绿色：青草。c.黑色：青线。");
