INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lái", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/来_lái.mp3", "来回 来宾  来历 来信 来源 从来 来临,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"现在以后：今年冬天下了大雪，来年一定是好收成。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由其他地方到说话人所在的地方：唐朝时期，日本其他官员和留学生来唐最多的一次达五六百人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示发生，来到：问题来了，要冷静地想办法解决。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"干：回到家里，煮饭、洗碗拖地板......他什么活都来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，在数词“一”“二”“三”后，表示列举：父亲死后，我就辍学了，一来可以帮助母亲做些家务，二来也可以将这笔费用省下。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/25560_多_22810.gif","6","上下","夕","多","many","http://cdn.ococci.com/dict_ali/2022-02-25/1645772832136351016_f608b9e3-4922-cd00-0451-c17d973f12a3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"duō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/多_duō.mp3", "多少 多年 多么 许多 顶多 多谢 多余 居多 众多,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数量大：语言的丰富多彩，往往就是思想的丰富多彩的反映。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数目增加：上次我多给了他一包货，今天他专程赶来补钱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词：不管有多大困难，我们都能完成任务。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在感叹句里，表示程度很高：还不快进来？外头多冷！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示有零头：一般都把编定距今二千五百多年前的《诗经》看作我国诗歌史的起点。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在疑问句里，询问程度、数量：你知道他祖母多大年纪？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90596_少_23569.gif","4","上下","小","少","Less","http://cdn.ococci.com/dict_ali/2022-02-24/1645714806549862702_bcc9fbf1-e9bd-699e-ae09-30fc34f091c7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/少_shǎo.mp3", "少量 少许 多少 少数 少刻 少不了,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丢失，遗失：办公室的文件少了几份。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稍微，短时间：少安勿躁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"缺，不足，数量小，不经常，跟\"\"多\"\"相对：缺少。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"削减：减少。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98420_黄_40644.gif","11","上中下","黄","黄","Yellow","http://cdn.ococci.com/dict_ali/2022-02-25/1645774879830671341_d8e59e05-1b63-f07f-b85f-7feea3e12871.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/203/黄_huáng.mp3", "黄色 黄河 黄昏 黄山 黄花 黄金 黄豆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事情失败或计划不能实现。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指黄河：一过黄泛区，水茫茫；陷泥过膝及腰腹，人马欲渡川无梁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指黄金：黄货。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"\"黄帝\"的简称：我们都是炎黄的子孙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象征腐化堕落不健康的：扫黄打非工作应常抓不懈。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像金子或向日葵花的颜色：积云一朵朵分散着，映着温和的阳光，云块四周散发出黄色的光辉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事情失败：这门亲事就这样黄了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54516_牛_29275.gif","4","独体","牛","牛","Cattle","http://cdn.ococci.com/dict_ali/2022-02-24/1645709753343617944_563eb6b8-ece1-3ecb-3026-a66bfe9ea3b5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"niú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/牛_niú.mp3", "牛群 牛排 牛皮 牛郎 牛筋 牛奶 水牛 黄牛,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"固执或倔强：这孩子，怎么这么牛!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物。牛科，身体大，头有两角，趾端有蹄，尾巴尖端有长毛，草食反刍，气力大，能耕田或拉车，肉、乳可食，角、皮、骨可作器物。我国常见的有水牛、黄牛、牦牛等：横眉冷对千夫指，俯首甘为孺子牛。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91491_只_21482.gif","5","上下","口","只","Only","http://cdn.ococci.com/dict_ali/2022-02-25/1645765436075871461_d53e54ff-2781-6315-95ad-2e919b17596e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/14/只_zhǐ.mp3", "只有 不只  只好 只要 只会 只是 只得 只顾 只管,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"仅有；惟有：我只有这么一个妹妹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。A．我只到过上海。B．记忆中，妈妈只骂过我一次。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/14/只_zhī.mp3", "只身 一只,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"单独的：只身一人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：一只鸡。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98954_猫_29483.gif","11","左右","犭","猫","Cat","http://cdn.ococci.com/dict_ali/2022-02-25/1645778455584954792_9c4b9812-55da-f2e1-c39c-3b8b1b6ed2ed.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"máo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/máo.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔猫腰〕弯腰。亦称“毛腰”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"māo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/93/猫_māo.mp3", "野猫 花猫 雄猫 白猫 猫哭老鼠 猫鼠同眠,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"家畜。面部略圆，脚有利爪，行动敏捷，善长捕鼠。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"<方>躲藏。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46383_边_36793.gif","5","半包围","辶","边","Edge","http://cdn.ococci.com/dict_ali/2022-02-24/1645669683797053651_bb236372-d82c-c79b-0918-b5f4cfe5e185.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"biān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/165/边_biān.mp3", "边际 边疆 外边 边沿 海边  边防 边界 边区,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"边境；边界：在当时的汉与匈奴的边境线上到处都发现了汉代的钱币和工艺品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"镶在或画在边缘上的条状装饰：这框镶上金边儿，显得更漂亮了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"边缘；近旁：路边是悬崖，虽然不是很深，但也够怕人的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两个或几个“边”字分别用在动词的前面，表示动作同时进行：文中有的地方以破为主，破中有立；有的地方以立为主，边破边立。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"界限；尽头：汽车在望不到边际的高原上奔驰。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59770_鸭_40493.gif","10","左右","鸟","鸭","Duck","http://cdn.ococci.com/dict_ali/2022-02-25/1645774623462702035_f03540af-64ca-328a-d650-0e9f08902f23.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/201/鸭_yā.mp3", "鸭子 鸭舌 鸭毛 鸭蛋 鸭黄 野鸭 烤鸭 填鸭 鸭步鹅行,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"属鸟类一科，嘴扁腿短，有蹼，善游泳，肉可食：市场上鸡、鸭、鱼、肉应有尽有。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/89993_苹_33529.gif","8","上下","艹","苹","Ping","http://cdn.ococci.com/dict_ali/2022-02-25/1645767355071871368_f1442c50-a967-1c55-e652-72469be4fdaf.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"píng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/133/苹_píng.mp3", "苹果 苹果花 苹果树,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"苹果。落叶乔木，叶子椭圆形，果实圆形，味甜或略酸，是普通的水果，品种很多。它的果实也叫苹果：苹果落地，是一件很平常的事情。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/16197_果_26524.gif","8","独体","木","果","Fruit","http://cdn.ococci.com/dict_ali/2022-02-25/1645755595684481251_c506fe15-7b60-a3fb-a81c-383bdce28f88.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guǒ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/果_guǒ.mp3", "果实 果树 果园 果真 果汁 果脯 恶果 后果 水果,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。相当于“果然”、“果真”：果不出我所料，天真的下起雪来了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结果，事情的结局或成效：它是社会的果，也是促进社会进步的因。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物结的果实：这个时候，橘子才刚刚挂果。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/25252_杏_26447.gif","7","上下","木","杏","Apricot","http://cdn.ococci.com/dict_ali/2022-02-24/1645707139735643678_bb510c53-6412-c3b1-fd85-5a9bf417c911.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/杏_xìng.mp3", "杏子 杏仁 杏树 杏眼 杏脯 杏花喜雨 杏脸桃腮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"杏树结的果实：他抓起一把杏子，津津有味地吃起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"木名。落叶乔木。叶子宽卵形且有尖。花单性，白带红色。果实圆形或扁形，成熟后呈黄红色，向阳部分还有红晕和斑点，味酸而淡甜，可生吃，也可制成杏干、杏脯，甜杏仁可炒食，苦杏仁可入药：放学后，她常坐在这棵杏树底下做作业。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36394_桃_26691.gif","10","左右","木","桃","Peach","http://cdn.ococci.com/dict_ali/2022-02-25/1645766057830832022_1c2ecb13-1221-63b0-759d-e8f64e8b8d6a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"táo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/桃_táo.mp3", "桃花 桃红 桃树 寿桃 核桃 樱桃 桃僵李代,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"桃树的果实：奶奶从集市回来，带给我们一人一只水蜜桃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形态像桃的其他果实：看着又大又白的棉桃，他心里乐极了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落叶小乔木。蔷薇科，春季开花，花淡红、粉红或白色，果实略呈球形，表面有毛茸，花可供观赏，果味甜，可生食，果核可入药：到龙泉驿桃花沟去玩!");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/8937_书_20070.gif","4","独体","乛","书","Books","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647480835075.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/书_shū.mp3", "书包 书法 书信 书店 教书 读书 书桌,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"装订成册的著作：书籍。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"字体：楷书。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"信：家书。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"写，记载：书写。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"《尚书》的简称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文件：证书。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文字：读书破万卷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称某些曲艺：说书。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38018_包_21253.gif","5","半包围","勹","包","The bag","http://cdnmu.gurobot.cn/saodubi/dict/audio/The_bag.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/12/包_bāo.mp3", "包括 包围 包办 包含 包工 包厢 包容 包装 皮包,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指包扎好的物件：他从左腋窝里，摸出了一个硬硬的纸包。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"装东西的口袋：妈妈要求我自己整理书包。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"裹；裹扎：她还给了他一包香烟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(物体或身体上)鼓起来的疙瘩：他脑袋上撞了个包。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"货物量词。用于成包的东西：这次只到了三包，不到两天就卖完了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"容；含：社会主义现代化建设包括经济建设、民主建设、文化建设。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"包围：在怀玉山，蒋介石的军队包围了北上抗日的红军。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"约定的，专用的：我们全家包了一辆车出去春游。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7843_尺_23610.gif","4","独体","尸","尺","Ruler","http://cdn.ococci.com/dict_ali/2022-02-25/1645773477290505939_5ec46b0c-9b76-c10a-ce06-b8397233599e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chě", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/chě.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国古代乐谱的记音符号，相当于简谱的“2”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/尺_chǐ.mp3", "钢尺 角尺 市尺 标尺 方尺 尺度 皮尺 折尺,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量长度或画图的器具：请把你旁边的卷尺给我。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"长度单位：这条裤子有三尺长。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像尺的东西：他从外地给我带了一把镇尺。");
