INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"习惯上指思想的器官和思想情况，感情等：我晓得你的心不在我们公馆里头。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人和脊椎动物身体内脏之一。在胸腔的中部稍偏左方，呈圆锥形，大小约与本人的拳头相等，内部有四个空腔，上部两个是心房，下部两个是心室。心房和心室的舒张、收缩推动血液的循环：他的心在剧烈地跳着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中央：船划到湖心，突然漏水了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/51512_升_21319.gif","4","独体","十","升","Liter","http://cdn.ococci.com/dict_ali/2022-02-25/1645756978454250481_30e94c42-262f-19e5-b1a7-d039939d155f.mp3");
