INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量粮食的器具：拿～来量米。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"登，向上，登上：上升。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"提高：升官。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"容量单位：他又到邻居那里借了2升米。");
