INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈古〉我国诸侯或王侯的封地：楚国。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"国家：抗美援朝，保家卫国。");
