INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旗子。用纸、布、绸等做成的标帜：五星红旗在天安门广场迎风飘扬。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清代满族的军队组织或户口编制：老舍是正红旗人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"属于八旗的；属于满族的：她穿上旗袍更显得清秀端庄。");
