INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/中_zhòng.mp3", "中毒 中伤 中暑 中选,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"受到；遭受：中了一枪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"正对上；恰恰合上：中了头奖。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/中_zhōng.mp3", "中医 初中 当中 高中 中枢 中原 中文 山中,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"内部；里面。与\"外\"相对：待到山花烂漫时，她在丛中笑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国的简称：古今中外，许多大学问家都十分重视目录学。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不偏不倚：中庸之道是儒家学说的内容。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"和四方、上下或两端距离同等的地位：：房子的中央放着一张大方桌。");
