INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“工”，指妇女的生产作业，纺织、缝纫、刺绣等。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/红_hóng.mp3", "红色 火红 绯红 鲜红 通红 分红 紫红,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象征顺利、成功：今年元月购销两旺，真可谓开门红。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象征革命或政治觉悟高：红军。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"红利：除每月固定工资外，每年底公司还要分红。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像鲜血一样的颜色：晚上在圣马克广场的河边上，看见河中有红绿的纸球灯，便是唱夜曲的船。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指受人宠信：她是厂长的红人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喜庆：她在居委会中分管红白大事。");
