INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"唱：黑人大多能歌善舞，有表演艺术才华。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"颂扬：可歌可泣。");
