INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"善；好；淳良：助人为乐是一种社会美德。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"味道甘美可口：把鲜嫩的菜下在玉米糊里，再放上点盐，真是美味啊!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"得意；喜欢；乐意：让你美吧，总有一天，你会后悔!");
