INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nián", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/年_nián.mp3", "年代 新年 童年 少年 青年 年华 年级,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间的单位，指地球绕太阳运行一周的时间，有春夏秋冬四季，一般为365天：那里日照时间特别长，一年达到三千小时。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"每年的：年会订于下月初召开。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一生中按年龄划分的阶段：我们的童年是美好幸福的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"岁数；年纪：\"难老泉\"，听听名字就给人一种年轻的感觉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"庄稼的收成：大叔常说，丰年要当歉年过。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年节：新年之后有元宵，这千千万万的繁灯，作树下廊前的点缀，何等灿烂!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35930_影_24433.gif","15","左右","彡","影","Shadow","http://cdn.ococci.com/dict_ali/2022-02-25/1645765345146291722_8d33f7a7-ce98-e961-7208-e8bc26e52a50.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/43/影_yǐng.mp3", "影子 影像 电影 影视 影响,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"如果光在传播过程中遇到不透明的物体，在物体后面光不能达到的地方就产生影。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亦指不真切的形象或印象。形象。描摹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指“电影”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/18001_前_21069.gif","9","上下","刂","前","Front","http://cdn.ococci.com/dict_ali/2022-02-25/1645761193046568570_1c97ab07-b913-9008-95e7-0e1b021d1b03.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qián", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10/前_qián.mp3", "前面 前边 前锋 前进 前途 前景  前所未闻,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"前面的道路。〈喻〉未来的光景：前途。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟“后”相对。a.方向，方位：前方。b.时间：前天。c.次序：前排。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧事，过去的事迹：前尘。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"行进：前进。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"前辈，过去的人们：前人。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36131_后_21518.gif","6","半包围","口","后","After","http://cdn.ococci.com/dict_ali/2022-02-25/1645766738314462003_a7a26afa-7e80-cfa7-671a-9c34a5e2e129.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/后_hòu.mp3", "后天 后方 后盾 后面 后勤 先后 以后 后背,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指空间，在背面的：村民们在房前屋后都栽上了果树。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"较晚的(指时间)：在我国先后有四人担任联合国副秘书长的职务。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"后代，子孙：阿Q是孤人，无后。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"君主的妻子：中国有一位慈禧太后。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指次序：几年来他的成绩一直拖后。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43023_黑_40657.gif","12","上下","黑","黑","Black","http://cdn.ococci.com/dict_ali/2022-02-25/1645768569352807746_55b82e07-adcf-b2e3-f2f0-2e6354baef41.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hēi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/203/黑_hēi.mp3", "乌黑 焦黑 黑夜 黑暗 黑布 黑色 黑头发,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"光线暗：天黑得伸手不见五指。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脸色阴沉；他为被人捉弄恼怒，脸顿时黑了下来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"隐秘的；这帮土匪，连抢带诈，黑钱弄了不少。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坏；狠毒：法西斯分子心黑手毒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻反动的非法：坚决取缔黑社会组织。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"五色之一，像煤或墨的颜色：大熊猫的一双眼圈又圆又黑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/77821_狗_29399.gif","8","左右","犭","狗","Dog","http://cdn.ococci.com/dict_ali/2022-03-23/542367100000007a_1648045049575.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/92/狗_gǒu.mp3", "小狗 狗腿子 狗洞 猎狗 狗屁 狗獾 狗窝,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物。人类最早驯化的家畜之一，其嗅觉、听觉都很灵敏，特别训练后可以看家、打猎和警卫：从小到大，她都怕狗。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98730_左_24038.gif","5","半包围","工","左","Left","http://cdn.ococci.com/dict_ali/2022-02-25/1645769503430739207_102a7462-2d0d-6b8b-e759-e77df9b88c2b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zuǒ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/左_zuǒ.mp3", "左手 左边 左脚 左翼 左右 左顾右盼 左面,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方位词。面向南时靠东的一边：他悄悄地从左侧门溜走了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"政治思想属于较激进或进步的；革命的：左派。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"错；不对头：你又想左了，我不是这个意思。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不协调：他俩意见常常相左。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/4748_右_21491.gif","5","半包围","口","右","Right","http://cdn.ococci.com/dict_ali/2022-02-25/1645773239166788289_1f75c19a-6c30-b54d-d355-691e381e6acd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/右_yòu.mp3", "右手 右边 往右 右派 右倾 右面 左右 右方 右翼 左顾右盼,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"面对南时靠西的一边：站在我右边的那个人就是我妹妹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻保守的或反动的：既要反左，也要反右。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/97180_它_23427.gif","5","上下","宀","它","It","http://cdn.ococci.com/dict_ali/2022-03-18/5423671000000085_1647586291790.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/34/它_tā.mp3", "它们,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词。指人以外的事物。我们应该爱护地球，不让它受到污染和破坏。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/92217_好_22909.gif","6","左右","女","好","OK","http://cdn.ococci.com/dict_ali/2022-02-25/1645769256685029626_dc2e288f-f0f2-255b-dd19-dd025cdfd94a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/好_hǎo.mp3", "好人 和好 良好 问好 友好 好处 幸好 好比,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在形容词、动词前，表示程度深，并带感叹语气：好漂亮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在数量词、时间词前面，表示多或久：好多。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在动词前，表示使人满意的性质在哪方面：好吃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在动词后头，表示完成或达到完善的地步：计划订好了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示赞许、同意或结束等语气：好了，不要再说了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"容易：今天的数学题太好做了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"优点多的；使人满意的：好事情。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"友爱；和睦：好朋友。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"便于：地整平了好种庄稼。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"健康：他的病好了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/好_hào.mp3", "强 好胜 好动 好客 好哭 爱好 好高骛远 好大喜功,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"爱，喜欢：他有点好高骛远。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/49781_朋_26379.gif","8","左右","月","朋","Peng","http://cdn.ococci.com/dict_ali/2022-02-24/1645708570473995404_c466456b-a591-1289-ea5f-b79a032d9b81.mp3");
