INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比画：他连说带比地费了好大劲，才把整个事情的前因后果讲清楚。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数学名词。比较两个同类数量的倍数关系，其中一数是另一数的几倍或几分之几：种子发芽率是指萌发种子的百分比。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"仿照：干这件事，就像比着葫芦画瓢，太简单了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"够得上：他现在已不比从前了。");
