INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wěi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/尾_wěi.mp3", "尾巴 船尾  结尾 收尾 首尾 末尾 扫尾 尾随 尾灯 尾花,");
