INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"末端：文章有时被检查官删去，弄得有头没尾，不成样子了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟随：他尾在村长的背后，走进了那结着彩绸的大门。");
