INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"期待：他巴不得父亲能早点回来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挨着：这地方前不巴村，后不巴店。");
