INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"优点：在工作中，我们两人一定要取长补短。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特别善于做某种事：他长于书法。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两点间的间隔距离大。A. 指空间：这条渠很长。B. 指时间：冬季昼短夜长。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/180/长_zhǎng.mp3", "生长 成长 班长 局长 科长 厂长 处长 部长 厅长,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生长；成长：现在，她已经长成大姑娘了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生：山上长满了青翠的树木。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"领导人：部长。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"增进；增加：长见识。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年纪较大：他比我长两岁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"辈分大：长辈们只希望他们的孩子能够在苦难中平平安安地长大。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88366_短_30701.gif","12","左右","矢","短","Short","http://cdn.ococci.com/dict_ali/2022-02-25/1645774745028396386_316bef11-ad74-7e2e-01cd-a08df365c9cb.mp3");
