INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"缺少；不足：所有人的钱全部拿出来，都还短七元，不够买三张车票。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两端之间的距离小。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指时间：冬季昼短夜长。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指空间或物体：大熊猫的尾巴很短，全身的毛又厚又光滑。");
