INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zuì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/62/最_zuì.mp3", "最大 最多 最近 最初 最后 最佳 最终,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"居首要地位的：世称唐宋八家，实以韩、柳、欧、苏为最。");
