INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丈夫的父亲：十多年来，是她照顾公婆和孩子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"国家或集体的：几十年来，他都是大公无私的。");
