INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"公正合理：大家应该做到公买公卖。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使公开，让大家都知道：他公开了他和这个男子的关系。⑾公事；公务：他现在在办公。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"公共的；大家的：他带他儿子在公园里玩。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"公务：因为路途劳顿，他第二天不办公也不会客。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"雄性的：公畜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"公平；公正：公道自在人心。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对祖辈或年长男子的称呼：叶公好龙。");
