INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/87/点_diǎn.mp3", "重点 点播 指点 点燃 点头 雨点 缺点 特点 点缀,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"汉字的一种笔画：字是由点画构成的，汉字八法就是八种点画的写法。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细小的痕迹：为什么纸上会出现麻点呢?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指定：今天的晚宴由父亲来点菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"液体的小滴：听着雨点打在窗外的芭蕉叶上，心里十分惬意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"触到物体：他拿起桨在河滩的树根上轻轻一点，小船就离岸了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一定的地点：人生的终极点只有一个，然而起点却有许多。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计时：正当12点时，他来找我了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"上下稍动：他总是在点头。⑾使液体一滴滴的落下或使物体逐个发出：点射、点发。⑿引着火：你别再煽风点火了。⒀装饰：点缀、装点⒁表示少量：他只知道一点点。⒂数量单位：你来补充几点建议吧。⒃指点；启发：心有灵犀一点通。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方面或者部分：每个人都有缺点。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用笔加上点子：这一笔，是画龙点睛的一笔。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55478_要_35201.gif","9","上下","覀","要","Want","http://cdn.ococci.com/dict_ali/2022-02-25/1645765634746180048_2bafe0b0-2b21-9c01-1f16-636780253475.mp3");
