INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在方位词前，表示时间、方位、数量的界限：以上；以前。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"为了；目的在于：努力学习，以提供自身修养。");
