INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chéng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/50/成_chéng.mp3", "成功 成效 成绩 成果 成长 成熟 成就 收成 成日 一成,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"成就；成果：他这些年来，辛辛苦苦地干，自信必有所成。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"十分之一叫一成：他已完成了工作的八成。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"变为：通过努力学习，她终于成了一个合格的大学生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"办好了；做好了：事成后，我一定会感谢你的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"撮合，使人达到目的；帮助别人：他待人热心，常常成人之美。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"成熟，发育到完备的、定型的阶段：在这些方面，小孩子怎么能和成年人相比？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"已定的；固定的：对任何人都要有正确的评价，不要抱有成见。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在时间、数量词的前面，强调时间长或数量多：他成天就知道玩。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38100_彩_24425.gif","11","左右","彡","彩","Color","http://cdn.ococci.com/dict_ali/2022-02-25/1645765732596575977_2391d3b2-566e-a981-fc0b-abb51ab33633.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/43/彩_cǎi.mp3", "色彩 云彩 油彩 水彩 精彩 喝彩 彩霞 彩虹 彩票,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指负伤流血：在这场战斗中，他挂了彩。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"出色：这场杂技表演十分精彩。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"彩色饰物：几名工人搭着梯子在厂门口扎彩。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多种颜色：赤、橙、黄、绿、青、蓝、紫，谁持彩练当空舞？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赞美别人的欢呼声：她刚演唱完，场内就响起了雷鸣般的喝彩声。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/62298_半_21322.gif","5","独体","十","半","Half","http://cdn.ococci.com/dict_ali/2022-02-25/1645767204772421149_0aa86d90-2fd5-9517-e2e4-5023b43fa596.mp3");
