INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"绿林。原指西汉末年王匡、王凤等领导的农民起义军，后泛指聚集在山林里反抗官府或打劫财物的团伙：此系绿林豪客所为。");
