INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"躺卧：他们吃饱了，睡在躺椅上，捧着书看。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91012_那_37027.gif","6","左右","阝","那","That","http://cdn.ococci.com/dict_ali/2022-02-25/1645767159368798627_6a1361f0-99e0-deda-8da7-67c37e63dc24.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/167/那_nà.mp3", "那些 那里 那人 那个 那天 那儿 那样,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词。指代比较远的人或事物，同\"这\"相对。A. 那个戴眼镜的医生是外科主任，手术做得很好。B. 她那一哭，可把我们老师吓坏了。C. 给老年人让座，那是我们应该的。D. 这也不好，那也不对。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。如果你认为是对的，那你就应坚持到底。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/nā.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/nèi.mp3", "那个 那五年,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"义同（一），“那”和“一”连读的合音，但指数量时不限于一：那个。那五年。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/那_nǎ.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“哪”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疑问代词，如何；怎么。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疑问代词。哪里；何处。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/20115_海_28023.gif","10","左右","氵","海","Sea","http://cdn.ococci.com/dict_ali/2022-02-25/1645768973577209027_4829aad1-2676-d588-acce-f1f02af1bdf8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/78/海_hǎi.mp3", "大海 上海 林海 深海 海外 海燕 海岛 海报 海域,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于湖泊的名称：阴山下面是一片清澄见底的大湖，匈奴人把它叫\"海子\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻数量多：举首一望，前后左右，竟是一大片浩森苍茫，无边无际的花海。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"靠近陆地比洋小的水域：地面某个地点高出海平面的垂直距离，叫做海拔或绝对高度。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从外国来的：如海榴、海红花、海棠之类。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"上海的略称：当时，明显地分为京(北京)派和海(上海)派。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32868_真_30495.gif","10","上下","目","真","Really","http://cdn.ococci.com/dict_ali/2022-02-25/1645767104051874833_dcf7b8fd-eada-0832-4967-c5f0a9a229d6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/真_zhēn.mp3", "真实 真正 真诚 逼真 传真 认真 天真 果真 真迹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"本原；本性：\"真\"就是自然。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与客观事实相符合，与“假”、“伪”相对：他是有真才实学的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"的确：今夜真冷啊!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指楷书：他擅长真书和草书。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/79158_老_32769.gif","6","上下","耂","老","Old","http://cdn.ococci.com/dict_ali/2022-02-25/1645774449045333548_aa91ceef-3a7e-6d8e-73df-4284def51b88.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/125/老_lǎo.mp3", "老人 老师 老实 老话 老练 老虎 老翁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年龄大：老奶奶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衰竭，疲怠：楚师老矣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在词头：老兄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"很，极：老早。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间长：老地方。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"老子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排行在末尾的：老妹子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"诚实，坦率：老实。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93311_师_24072.gif","6","左右","巾","师","Teacher","http://cdn.ococci.com/dict_ali/2022-02-25/1645769931194591781_fd2c7492-6495-0b54-d825-4b49d5c3b0f4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/师_shī.mp3", "老师 教师 师傅 师长 工程师,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指老师，导师：教师。〈引〉榜样：师表。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"效法，学习：师其所长。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军队：出师。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由师徒关系而产生的：师弟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军队的编制单位。一般是军的下一级，团的上一级。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指擅长某种技术的人，又指技术职称：医师。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/31670_吗_21527.gif","6","左右","口","吗","Yeah","http://cdn.ococci.com/dict_ali/2022-02-25/1645767133722721233_b0904604-639c-b8ad-a0da-c41f78b6a2c1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"má", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吗_má.mp3", "晚上干吗？,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈方〉什么：干吗？");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吗_mǎ.mp3", "吗啡,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吗啡：医学上用作镇痛剂，它是鸦片制成的有机化合物。能止咳、镇痛、抑制肠蠕动等。需经高级医师处方慎重使用，且不能连续使用，避免成瘾、中毒。孕妇、乳母、婴儿等禁用。吗啡及其毒品，严禁私造、贩卖、私购、使用等，违法者严惩。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/78407_同_21516.gif","6","半包围","口","同","Same as","http://cdnmu.gurobot.cn/saodubi/dict/audio/Same_as.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/同_tóng.mp3", "同学 同桌 同意 同伴 同窗 同情 相同 合同,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"介词。A. 引进动作的对象，相当于“跟”：把马克思主义基本原理同中国实际相结合，找出自己的前进道路。B. 进行比较的事物，与\"跟\"相同：今年的气候同往年不一样。C. 方言。表示替人做事，相当于“替”：别着急，我同你给老师说说情。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"和谐；安定：他没有也不可能找到一条到达大同的路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一起；一齐；一道：与群众同甘共苦，不只是个人的生活小事，而是每个干部的基本道德。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一样：这是因为水陆的吸热和放热情况不同。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。表示并例，相当于“与”、“和”：他同小王都落选了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/同_tòng.mp3", "胡同,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"胡同：小街道，巷子。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35283_什_20160.gif","4","左右","亻","什","What","http://cdn.ococci.com/dict_ali/2022-02-25/1645771594052282709_e00d3f70-5c1b-bda3-45d3-171eed05ffe5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shén", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/什_shén.mp3", "什么,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词，指不确定的事物：你别逼他，他什么都不怕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词，表示疑问：这盒子里究竟装了什么?");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/什_shí.mp3", "什锦 什物,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同‘十’（多用于分数或倍数）：什一。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多种的；杂样的：什物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38964_才_25165.gif","3","独体","扌","才","Just","http://cdn.ococci.com/dict_ali/2022-02-25/1645766862887656417_a1b847a0-29b4-c8c2-a5a4-c0444f55f7e1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cái", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/才_cái.mp3", "人才 天才 全才 才干 才华 才能 奇才 英才,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能力：他口才不好，面对陌生人不能流畅地讲话。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有能力的人：他在哲学领域里称得上是一个奇才。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。A. 桌子是从家具商场才买来的。B. 这场雨一直下到晚上才停。C. 只有创造幸福的人，才知道生活可爱。D. 就是因为这个原因，我才受了不少气。E. 我才不信中国足球冲不出亚洲。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75287_亮_20142.gif","9","上下","亠","亮","Bright","http://cdn.ococci.com/dict_ali/2022-02-25/1645771555811885502_132ad007-1ca5-c13c-5361-1d5ea2ab7757.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/亮_liàng.mp3", "响亮 月亮 明亮 亮光 亮相 亮堂 豁亮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"明，光线，发光：天快亮了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"显示出来：亮相。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坚贞的节操：高风亮节。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"声音响亮：嘹亮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使声音大：小姑娘亮开了嗓门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"明朗，清楚：明亮。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48311_时_26102.gif","7","左右","日","时","Time","http://cdn.ococci.com/dict_ali/2022-02-25/1645773106087243381_2640d7b0-37aa-2c81-4bc3-d9ec51ee64e6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/59/时_shí.mp3", "时间 时候 时代 时光 时机 时刻 时而,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时势；时机：一定要注意适时播种，按期施肥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"按照规定的或一定的时间：他每天都按时上班，从不迟到。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时候；时间：12世纪时，蒙古族发展起来，和周围民族加强了联系。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"季节：我们得抓紧机会播种，千万别误了农时。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"当时；现在：每个人都应该关心时事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计时的单位：A. 时辰：一觉醒来，已快辰时了。B. 小时：他每天早晨6时起床。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时时；时常：他时时干出一些傻事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有时候：最近一段时期，天气变化大，时阴时晴，容易使人感冒。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/92885_候_20505.gif","10","左右","亻","候","Wait","http://cdn.ococci.com/dict_ali/2022-02-25/1645758619610610777_119eb803-bdbf-049a-f99e-d3c3764c3ed7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/5/候_hòu.mp3", "时候 等候 气候 守候 恭候 火候 候审 迎候,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"问好；问安：请代我问候老师。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"等待：她礼貌地对我们说：\"请稍候，先生马上就下来。\"");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时节：地形和海拔高度对气候有重大影响。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物在变化中的情状：工人炼钢很注意火候。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/9243_觉_35273.gif","9","上下","见","觉","Sleep","http://cdn.ococci.com/dict_ali/2022-02-25/1645768594296491140_5a6deaf8-b7c8-a6bc-9640-37bed55bc1b1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/150/觉_jiào.mp3", "午觉 困觉 睡觉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"睡眠：近来老是加班，觉总是睡不够。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。睡着到睡醒为一觉：他已睡醒一觉了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jué", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/150/觉_jué.mp3", "感觉 觉悟 听觉 视觉 自觉 发觉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"醒悟；明白：这不是虚荣心，这是责任心的觉醒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"感知；意识到：我抚她的额，只觉触手的热。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/74027_得_24471.gif","11","左右","彳","得","Got it","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"de", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/44/得_de.mp3", "要得 跑得快,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在动词和补语中间，表示可能：我拿得动，那办得到。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在动词后面，表示能够或可以：我们可粗心不得。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在动词或形容词后面，连接表示程度或结果的补语：笑得肚子痛。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dé", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/44/得_dé.mp3", "懂得 得到 得当 得力 难得 取得 心得,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与\"失\"相对：他总是患得患失，计较个人的利益。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"适当：恰好他办事稳当，也很得体。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"演算产生的结果：3乘2得6。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于某种语气：得了，别说了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在别的动词前，表示许可。(常见于法令)：这辆车非经同意，不得擅自开走。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"děi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/44/得_děi.mp3", "得亏 非得 总得 必得,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"意志：在现代社会中，一个人非得有点口才不可。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"需要：这幢28层高的大楼得一年多才能造好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"揣测的必然：表天快黑了，要不快走，就得在野外过夜了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36106_自_33258.gif","6","独体","自","自","From","http://cdn.ococci.com/dict_ali/2022-02-25/1645767379169340944_1ef21736-de11-468a-1538-abe219553c99.mp3");
