INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"休闲：我自退休以来，一直呆在家里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"当然：他这样做，自有他的道理。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"本身；自身：全文除引子外，共分九节，各节互相联系，又各自成篇。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/6742_己_24049.gif","3","独体","己","己","Self","http://cdn.ococci.com/dict_ali/2022-02-24/1645712003343807480_c721d4af-3727-86c3-f448-57dcc8da1f8e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/己_jǐ.mp3", "知己 克己 利己 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"天干的第六位，用作顺序第六的代称：甲乙丙丁戊己庚辛壬癸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对别人称本身、自己：这件事还是我自己来做吧。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88512_很_24456.gif","9","左右","彳","很","Very","http://cdn.ococci.com/dict_ali/2022-02-25/1645772585961251786_541c155a-b1e2-feef-4783-163a68fb4b46.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hěn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/44/很_hěn.mp3", "很多 很好 很怪 很快 很喜欢 坏得很,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。非常，表示程度加深：很快，陈然得到党组织的通知。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54499_穿_31359.gif","9","上下","穴","穿","Wear","http://cdn.ococci.com/dict_ali/2022-02-25/1645768520171923129_8b8a470e-528b-519c-f811-a5809d46c289.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chuān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/112/穿_chuān.mp3", "穿衣 揭穿 穿插 穿梭 看穿 拆穿 贯穿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弄破：别把窗户纸弄穿了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通过：通过这条街穿过去就到了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把物体串到一起来：他小心翼翼地把珍珠穿成串。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"捅透或揭开：他揭穿了他的阴谋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把衣服、套在身上：外面冷，别忘了穿皮衣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39377_衣_34915.gif","6","上下","衣","衣","Clothes","http://cdn.ococci.com/dict_ali/2022-02-25/1645756802720754926_1afbfadd-267d-0085-225d-39adb92a69c5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/147/衣_yī.mp3", "衣服 衣着 衣衫 衣食 衣钵 布衣 冬衣 便衣 单衣 更衣 青衣 蓑衣,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"披或包在物体外面的东西：这种药丸后来做成了糖衣的，小孩子服用时就容易得多了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人或哺乳动物的胎衣：牛的身子微微地在动，出来了一点灰色透明的东西，那是胞衣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衣服：衣食住行是人的基本需求。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29065_服_26381.gif","8","左右","月","服","Take it","http://cdnmu.gurobot.cn/saodubi/dict/audio/Take_it.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/62/服_fú.mp3", "衣服 说服 佩服 克服 服役 驯服 服务 折服 婚礼服,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吞；吃(药物)：他服了药，睡上十多天才渐渐地好起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"承受处罚：他因酒后开车，酿成较大车祸，法院判他服刑六个月。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"信服；佩服：我不仅佩服他的坚强和勇敢，更佩服他那超人的智慧和才能。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使接受：以理服人是处理问题解决矛盾的好方法。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"适应：新到一个地方，会有水土不服的感觉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衣裳：街中聚集了一大群人，有着各样的身材，各样的衣服。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/62/服_fù.mp3", "一服药,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"车厢：凡服耜，斩季材，以时入之。——《周礼·山虞》");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"负载；负荷：车为服重致远，乘之则安，引之则利。——《墨子》");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，用于称中药剂量。一剂称一服。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/71251_门_38376.gif","3","独体","门","门","The door","http://cdnmu.gurobot.cn/saodubi/dict/audio/The_door.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mén", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/181/门_mén.mp3", "门票 门槛  门诊 门道 门板 门卫,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"建筑物的进出口，设在进出口能开关的装置，泛指进出口：城门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：三门大炮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"诀窍，途径，方法：窍门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宗教或学术思想的派别：佛门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状或作用像门的：球门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分类：门类。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"家，家族：双喜临门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟师傅有关的：门徒。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85213_快_24555.gif","7","左右","忄","快","Hurry up","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/45/快_kuài.mp3", "飞快 快车 快活 愉快 快乐 快门 快速,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"费时短：他跑得飞快。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"锐利：这刀并不快，怎么可能伤得了他呢?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"爽快，直截了当：她是一个心直口快的人。");
