INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示并列：用这种方法演算又快又准。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示范围之外另有补充：他除了送衣服给我之外，又给了我一百元钱当路费。");
