INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计策，办法：没着儿了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"下棋时下一子或走一步：一着儿好棋。");
