INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，表示祈使：你听着！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，表示动作正在进行或状态的持续：上着课呢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，表示程度深：好着呢！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，用在某些动词后，使变成介词：照着办。");
