INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使接触别的事物，使附在别的物体上：着色。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"穿（衣）：穿着打扮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"派遣：着人前来领取。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"下落，来源：着落。");
