INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不分胜负：这盘棋最终成了和棋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连带：和盘托出。");
