INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"介词，表示相关、比较等。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/和_hè.mp3", "唱和 和酬 一唱一和,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"以诗歌酬答；依照别人诗词的题材作诗词：和答。");
