INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"某些幼小的动物：猪娃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧称美女：娇娃。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7840_挂_25346.gif","9","左右","扌","挂","Hang","http://cdn.ococci.com/dict_ali/2022-02-24/1645716075693929564_65428d85-0b2f-1761-73ad-2bcfff6b86d9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/52/挂_guà.mp3", "挂彩 挂名 挂失 记挂 挂念 挂钩 挂钟 挂漏 牵挂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"联系：他觉得这些都是干部们的事，和自己挂不到一块。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"搁置：他们对我也不放过，长期挂在一边不安排工作。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"担心：你不必牵挂他，他自己会保重的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悬挂：三味书屋的北墙正中，挂着一幅古画。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"说到：别看他嘴上经常挂着四维八德，实际上是个奴才汉奸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/78880_活_27963.gif","9","左右","氵","活","Live","http://cdn.ococci.com/dict_ali/2022-02-25/1645772663375280666_90ba95e3-3113-922e-60e5-1942a34639ff.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/78/活_huó.mp3", "生活 活力 活动 活跃 活泼 灵活,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"维持生命：养家活口。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"活动；灵活：活水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生存；有生命的：活人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"真正；简直：活现。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"工作：庄稼活。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生动活泼；不死板：活跃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在活的状态下：活捉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"产品：这批活儿做得既快又好。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34942_金_37329.gif","8","独体","金","金","Gold","http://cdn.ococci.com/dict_ali/2022-02-25/1645743270718300618_48a2240a-b0b3-c83b-7d83-6fd5f7717d7c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jīn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/金_jīn.mp3", "黄金 白金 奖金 储金 押金 资金,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"金属，通常指金、银、铜、铁、锡等：这是两扇铝合金玻窗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"金子或黄金的通称。金属元素，符号Au。黄赤色，质软，是一种贵重的金属：她花八百元买了一根金项链。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"钱币：银行里为兑付国债，准备金非常充足。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻尊贵：你就免开金口了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像金子的颜色：江随壁转，前面天空上露出一片霞光，像横着一条金带。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7277_哥_21733.gif","10","上下","口","哥","Elder Brother","http://cdnmu.gurobot.cn/saodubi/dict/audio/Elder_Brother.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哥_gē.mp3", "表哥 堂哥 帅哥 八哥,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哥哥：大哥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称呼年纪跟自己差不多的男子(含亲热意)：李二哥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亲戚中同辈而年纪比自己大的男子：表哥。");
