INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种常绿多年生植物，茎空，有节，可做建筑材料及制器物，也可作造纸原料：造纸术发明以前，人们把文字主要写在竹、木简和帛上。");
