INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使人或物发挥其功能：兄弟俩用压岁钱给爷爷买了一块怀表。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"花费：父亲把钱递给母亲，说：\"这是这个月的家用。\"");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用处：虽然钱并不多，但多少对你会有点用。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"需要：时间还很早，不用着急。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吃、喝的敬词：时间不早了，请大家到饭厅用饭吧!");
