INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小或矮的桌子：茶几儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"苗头：知几其神乎。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"将近，差一点：几乎。");
