INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"境地：他终于弄明白了，落到这一步都是自己造成的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"行走时两脚之间的距离：即使要跟很长的路，她也不会落下半步。");
