INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"被：从前线回来的人说到白求恩，没有一个不佩服，没有一个不为他的精神所感动。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"变成；成：一分为二。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"做：这事我会尽力而为的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"充当；作为：横眉冷对千夫指，俯首甘为孺子牛。");
