INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"送出：文件已下发到各单位。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引起：他的话发人深省。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"产生：电机发热了。");
