INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"起作用：对学习，要多动脑筋，想一想\"是什么\"、\"为什么\"等等。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"触动：这件事让我很感动。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"起；开始：这栋大楼五月份就动工修建了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经常：你别动不动就哭。");
