INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"单，只，全：满地净是树叶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清洁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"空，什么也没有。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国传统戏剧扮演男人的角色名：净角（亦称“花脸”、“黑头”）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"单纯，纯粹的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使干净。");
