INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"预料：不虞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"忧虑：无冻馁之虞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"欺骗：尔虞我诈。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国周代诸侯国名，在今山西省平陆县东北。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/31702_阴_38452.gif","6","左右","阝","阴","Yin","http://cdn.ococci.com/dict_ali/2022-02-25/1645766595269433082_987e6b82-cb3d-f86b-9d8c-35e88d39e591.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yīn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/阴_yīn.mp3", "阴暗 阴沉 阴冷 阴影 阴凉 阴沟 阴森,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不光明磊落：我们一定能够挫败西方敌对势力的和平演变的阴谋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"隐藏的：阴沟太脏了，散发出阵阵臭味。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"我国古代哲学概念：我国古人认为，万事万物都由阴、阳两个方面组成。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"没有阳光：这是个多雨的深秋，天刚晴了一会儿，便又阴了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/20488_雷_38647.gif","13","上下","雨","雷","Ray","http://cdn.ococci.com/dict_ali/2022-02-24/1645714257659504629_c72d6c65-596a-b8e5-5b86-cacc1a3e6f35.mp3");
