INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"带异性电的两块云相触碰时发出的响声：在一个雷雨交加的夜晚，爷爷含冤离开了我们。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军事上用的爆炸武器：在朝鲜战场上，哥哥在一次排雷时，不幸牺牲了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/184/雷_lèi.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敲击。通“擂”");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94040_电_30005.gif","5","独体","田","电","Electricity","http://cdn.ococci.com/dict_ali/2022-02-24/1645710369096951315_91e1c816-d064-a29f-8314-13fbb6d91ca4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/98/电_diàn.mp3", "充电 触电 传电 雷电 用电 闪电 发电 电话 静电,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种很重要的能源，广泛地用在生产和生活各方面，可发光、发热、产生动力等：这个小型发电站专门供给商场铺面的租户和附近一两条街的店铺用电。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闪电：正午时分，天气忽变，窗外电闪雷鸣，大雨滂沱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"触电：赶快把落下来的电线收拾一下，让它电了人可不得了！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"电报：许多国家的领导人发来唁电，对周恩来总理的逝世表示深切哀悼。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/14614_阵_38453.gif","6","左右","阝","阵","Array","http://cdn.ococci.com/dict_ali/2022-02-22/1645511211465755622_37e17f2b-01f8-b8b1-5faa-4581284d1d46.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhèn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/阵_zhèn.mp3", "阵势 阵地 阵营 阵亡 阵雨 阵容 阵地战 上阵 布阵 对阵,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"战场：经过两昼夜的血战，他们终于夺回了被占的阵地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军队作战的阵势、排列与组合形式：布阵已毕，只待命令。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。A．这阵儿有点忙。B．几阵凉风过去，阳光不那么强了。");
