INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把东西和冰或冷水放在一起使变凉：汽水已冰过了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水在摄氏零度或零度以下凝结成的固体：邮轮\"泰坦尼克\"号在赴美国首航途中跟冰川相撞而沉没。");
