INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"受冷或感到冷：冻醒了的同志们围着火堆小声地谈着话。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"液体或含水分的东西遇冷凝结：天气太冷，水已经冻了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"固体或半固体：餐桌上摆着一碟鱼冻和一碗蛋汤。");
