INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"双层的(衣被等)：夹衫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"次，副贰：夹辂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衬，在里面托上层：夹囊。");
