INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"夹子：文件夹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从两个相对的方面加压力，使物体固定不动：夹菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"夹杂；搀杂：夹在人群里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"处在两者之间：把信夹在书本里。");
