INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吃_chī.mp3", "吃苦 吃饭 吃亏 吃喝 吃紧 好吃 吃惊 吃香 吃透,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"依靠某种事物或条件生活：俗话说：\"靠山吃山，靠水吃水\"，我们为什么不能利用这条河流呢？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"咀嚼食物并咽下去：我是北方人，不敢吃辣的东西。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吸收：沙土吸水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消灭(多用于军事、棋戏等)：我拿\"车\"吃你的\"炮\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"领会：你先把文件精神吃透后，再向群众传达。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"承受；经受：宁愿国家受损失，也不能让群众吃亏。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接受：吃请。");
