INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jǐng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/井_jǐng.mp3", "打井 投井 油井 水井 矿井 井水 井然,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"星名。二十八宿之一。也称“东井”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状跟井相像的：第一次下矿井，他很兴奋也很好奇。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人工挖凿的能取出水的深洞，洞壁多用砖石修砌：吃水不忘挖井人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有秩序的：他把一切都安顿得井然有序。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
