INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"粗俗：他就以村夫俗子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"村落；村庄：大到一个省，小到一个村，变化都是显而易见的。");
