INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"招唤：请你叫他快来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称为，称呼：这叫电视机。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"呼喊：呼叫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"介词。被，让：几个敌人叫我们活捉了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使，令：要叫人听得懂。");
