INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"我国货币\"\"角\"\"的别称：五毛钱。⑾姓。⑿我国少数民族之一：毛难族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"动植物的皮上所生的丝状物：羽毛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像毛的东西：很久没见太阳，皮鞋上都长～了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"皮的，毛织品：毛线衣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指头发：鬓毛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"惊慌，恐惧：她吓毛了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小，细：毛孩子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"粗略，估计的：毛重。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"粗糙，没有加工的：毛糙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"慌忙，急躁：毛里毛躁。");
