INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"当家的人：他是一家之主，当然应该让他拿出办法来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"预兆：我前日说你气色好，主有贵人相照。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接待宾客的人：当主客谈笑之间，午饭已摆好了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"所有者：没收的东西又分配给他了，真可谓物归原主。");
