INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用竹篾、芦苇、蒲草等编成的坐卧铺垫用具或用以搭棚子的片状物：那时家里很穷，到冬天床上还铺着凉席。");
