INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"很一般；普通：他是一个很平常的人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"某种伦理道德标准：封建社会所谓五常指仁、义、礼、智、信。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时常；长久不变的：他常为青年们改稿、作序。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98512_壮_22766.gif","6","左右","士","壮","Strong","http://cdn.ococci.com/dict_ali/2022-02-25/1645771428149535430_302d8122-6910-b0f5-88e0-8577c18c450b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/27/壮_zhuàng.mp3", "壮大 壮年 豪壮 强壮 健壮 粗壮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国少数民族，主要分布于广西壮族自治区及云南、四川、贵州等省（旧作“僮”）：壮族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大，有力，强盛：强壮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"增加勇气和力量：壮胆。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7008_观_35266.gif","6","左右","见","观","View","http://cdn.ococci.com/dict_ali/2022-02-25/1645749729529680337_470192b4-a2d3-8704-bf93-86291060c5de.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/150/观_guàn.mp3", "观寺 观宇 观台 观阁 观阙,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代天子、诸侯宫门外张示法令的地方。同“阙”：出游于观之上。——《礼记·礼运》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古国名：观国(在今顿丘卫县)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"台榭：大王见臣列观。——《史记·廉颇蔺相如列传》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"道教的庙宇：白云观。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"京观：筑观(建筑京观)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。春秋楚有观射父。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/150/观_guān.mp3", "乐观 美观 奇观 主观 壮观 外观 观点 观摩 观众,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"看：例如观花，植物学家以植物学的角度去审视它，而画家却以美学的角度去欣赏它。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"欣赏：农历八月十八日，是一年一度的观潮日。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"景象；样子：木制的店门上涂着暗绿色的油漆，相当美观。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"仔细考察：观察现象、思考本质、深化认识，是一切科学认识的必由之路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对事物的认识、看法：一般说来，世界观在中学阶段已基本形成。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33727_接_25509.gif","11","左右","扌","接","Pick up","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/接_jié.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“捷”。迅速，敏捷");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/接_jiē.mp3", "接受 接待 接触 接替 连接 接风 接火 接济,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连接：大运河接通了南北之间的漕运。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"收到：船长接到报告后便迅速将船开赴出事地点。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"靠近；接触：战斗中，我们与敌军短兵相接，打得很艰苦。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"继续；连续：他开始在锅里动着汤瓢，接着盛了一点汤起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接替：培养和造就千百万社会主义事业的接班人，是一项神圣而艰巨的任务。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"嫁接：他既会种花，又会接果树。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50085_再_20877.gif","6","上下","冂","再","Again","http://cdn.ococci.com/dict_ali/2022-02-25/1645767050644365317_9887e55a-60d2-7efc-87d7-72bacfc42bbb.mp3");
