INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示一次又一次：许多观众一而再，再而三地要求他表演。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"重复；继续：明天再去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连接两个动词，表示先后的关系：写完作业再看电视。");
