INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/各_gè.mp3", "各个 各自 各色 各界 各种 各位 各式各样 各行其是,");
