INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指示代词。A. 表示每个：各人只拿各人的东西，不要乱动人家的。B. 表示不止一个，并且是彼此不同的：节日期间，有各种新鲜蔬菜上市。");
