INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高大：太空。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"最，极：太伟大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对高一辈或两辈的人之尊称：太公。");
