INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代哲学概念：古人认为一切事物都由阴、阳组合而成。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"山的南面；水的北面。山里人建房时，喜欢把房建在阳坡上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"太阳；阳光：几盆花草迎着朝阳，呈现出勃勃生机。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"外露的：顽固派们总是阳奉阴违，千方百计破坏抗日统一战线的团结。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/20019_道_36947.gif","12","半包围","辶","道","Tao","http://cdn.ococci.com/dict_ali/2022-02-25/1645743353456979514_8314966c-39d2-4633-05cd-16b1232717db.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/167/道_dào.mp3", "道贺 道别 渠道 正道 厚道 道破 道谢 道义 道歉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"道教，我国主要宗教之一：他经常在道观里闲逛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"路：这条羊肠小道直通山顶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"说：我来给您道喜了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细长的痕迹：墙壁上被人画了两条长长的横道儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"途径：这幢楼的下水道已经堵塞过好几次了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"道德：我国对别国的支持有政治上的，也有道义上的，还有物质上的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"技艺；技能：他道行高深。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方法；道理：很多人尽管口头上讲得头头是道，但实际做起来有时又不是那么回事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"线条：桌上有铅笔道儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。人民解放军一鼓作气突破敌人的两道防线。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3523_送_36865.gif","9","半包围","辶","送","Send","http://cdn.ococci.com/dict_ali/2022-02-25/1645721377028193746_792a2b0a-02b3-ffb2-00c6-f8091616db7c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/送_sòng.mp3", "送别 送礼 送信 送行 保送 断送 发送,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"陪着离去的人一块走：送行。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"运输，传递：送信。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赠给：送给。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/12761_忙_24537.gif","6","左右","忄","忙","Busy","http://cdn.ococci.com/dict_ali/2022-02-25/1645748033816726857_93ba51de-e0fa-a0f7-efb8-6ac55fe1c9d5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"máng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/45/忙_máng.mp3", "忙活 忙乱 忙碌 匆忙 慌忙 急忙 连忙,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"急促；赶紧去做：吴吉昌连忙拔了几株棉苗作为标本。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事情多，没有空闲：他从早忙到晚，很少在家陪母亲。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34248_尝_23581.gif","9","上下","小","尝","Taste","http://cdn.ococci.com/dict_ali/2022-02-25/1645756821989772971_956957ab-0a3b-e8d1-a7f7-69225af8c1ee.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cháng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/尝_cháng.mp3", "尝一尝 尝试 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"基本义：(动)吃一点儿试试；辨别滋味。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)曾经。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)比喻经历过。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/77093_香_39321.gif","9","上下","香","香","Incense","http://cdn.ococci.com/dict_ali/2022-01-26/1643180327991032130_26542977-3c2c-79b7-24f3-e26b4c60977a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/190/香_xiāng.mp3", "香水 香皂 香味 芳香 清香 香料 香气 真香,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"祭祖、敬神所烧的用木屑搀上香料做成的细条：香烛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"味道好：我一向觉得芥末的香味难得。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亲吻：香她的面孔。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"气味好闻，与“臭”相对：那时能用香皂洗脸，也算是富裕的家庭了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"受欢迎：这种货物在农村香得很。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"舒服：他起床时，儿子睡得正香。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/21674_甜_29980.gif","11","左右","甘","甜","Sweet","http://cdn.ococci.com/dict_ali/2022-02-25/1645763509899339519_5a875598-59ab-3615-b42c-df5552b0a540.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tián", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/98/甜_tián.mp3", "香甜 甘甜 甜蜜 甜头 甜美 甜睡 甜食,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"舒适；愉快：他睡得很甜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像糖或蜜的味道：今年雨水太多，水蜜桃不太甜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33591_温_28201.gif","12","左右","氵","温","Wen","http://cdn.ococci.com/dict_ali/2022-02-25/1645772584087409728_e0d70ac2-f137-4373-41fe-d2ae4ef7381e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/80/温_wēn.mp3", "保温 气温 温和 高温 体温 温度 温存 温差 降温,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"性情柔和、平顺：柔和的脸上虽然有那么厚的泥，可是那点笑意教大家仿佛看到一个温善白净的脸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"温度：低矮的南岭山脉，岭南岭北的温差也是很大的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稍微加热：柜里面预备着热水，可以随时温酒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中医指温热病：春季是温病的高发季节，应及早做好预防工作。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不冷不热：天山成为我国中温带和暖温带的分界线。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"复习：温故而知新。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35094_暖_26262.gif","13","左右","日","暖","Warm","http://cdn.ococci.com/dict_ali/2022-02-25/1645771769141463951_a9a33dfe-5d79-72d9-a102-824f045edc9f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nuǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/61/暖_nuǎn.mp3", "暖气 暖流 暖和 冷暖 取暖,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"暖和；不冷；温和：做人应该像一块煤，发热发光，给人温暖。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使温暖：姐姐把弟弟的脚拉到自己怀里说：\"放在姐这儿暖暖。\"");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29397_该_35813.gif","8","左右","讠","该","This","http://cdn.ococci.com/dict_ali/2022-02-25/1645771973821214579_fbc1040f-f1fc-c7c5-c8b0-6e5305115241.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gāi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/该_gāi.mp3", "该打 该死 该账 本该 应该 该书 活该 该当,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"当；应当：通过的正文要写清楚在什么地方，什么时间，有什么事情，请谁参加，该注意什么等。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"理应这样：你该下点功夫把学习搞好才行。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"欠：该给几块钱。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35351_颜_39068.gif","15","左右","页","颜","Yan","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/颜_yán.mp3", "颜面 颜色 笑颜 厚颜 汗颜 颜料 喜笑颜开 五颜六色,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"体面，面子：他自己觉得无颜见爹娘。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"面容；脸色：想着奶奶往日的容颜，不觉眼泪流了下来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"颜色：他不用颜料不用笔，以食指代笔，几分钟就画成一幅画。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/96639_因_22240.gif","6","全包围","囗","因","Because","http://cdn.ococci.com/dict_ali/2022-02-25/1645740131577590516_5501e02d-9fe2-a143-6c2c-d8d8378c8e2e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yīn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/因_yīn.mp3", "病因 因为 因果 内因 起因 原因 因循守旧 因人成事 因素,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"原故，原由，事物发生前已具备的条件：原因。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"理由：因为（wéi）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"依，顺着，沿袭：因此。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/96096_辆_36742.gif","11","左右","车","辆","A car","http://cdnmu.gurobot.cn/saodubi/dict/audio/A_car.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/165/辆_liàng.mp3", "车辆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。多用于车：阿Q被抬上了一辆没有宾篷的车。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43631_匹_21305.gif","4","半包围","匚","匹","Horse","http://cdn.ococci.com/dict_ali/2022-02-25/1645771213944186412_ae2372b7-76f1-c809-a2c3-f18554ce2f27.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/13/匹_pǐ.mp3", "匹配 匹夫 马匹 匹夫之勇,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"单独：匹马单枪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"相当；相配；比得上：他俩实在不匹配。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。A. 用于马、骡等牲口：这匹马膘肥腿壮。B. 用于成捆的绸和布等：他买了一匹布。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/18501_册_20876.gif","5","独体","丿","册","Book","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647480835075.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/册_cè.mp3", "注册,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"装订好的简册：这是一本计算机操作手册。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：这套丛书一共有五册。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7618_支_25903.gif","4","上下","支","支","Branch","http://cdn.ococci.com/dict_ali/2022-02-24/1645712462200675089_12396536-6764-329c-48b7-09d33550af1e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/58/支_zhī.mp3", "支持 支出 支撑 收支 分支 开支 支票 支点 支付,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"撑持，伸出，竖起：支撑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"附属于总体的一个部分：总支。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：一支笔。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"领款或付款：支付。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔地支〕历法中用的十二个字：子丑寅卯辰巳午未申酉戌亥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"受得住：乐不可支。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"调度，指使：支使。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46057_铅_38085.gif","10","左右","钅","铅","Lead","http://cdn.ococci.com/dict_ali/2022-02-25/1645762021108772326_0155ee75-c4e8-d57b-4b1f-0b69b0d75b68.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/铅_qiān.mp3", "铅笔 铅弹 铅球,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种金属元素，可用作耐硫酸腐蚀、防丙种射线、蓄电池等的材料。其合金可作铅字、轴承、电缆包皮等之用：铅球。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指用石墨等制成的书写工具：铅笔。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/铅_yán.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"铅山〕地名，在中国江西省。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36432_棵_26869.gif","12","左右","木","棵","A tree","http://cdnmu.gurobot.cn/saodubi/dict/audio/A_tree.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/棵_kē.mp3", "一棵 两棵,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。一般用于植物：这棵树已快死了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/97188_架_26550.gif","9","上下","木","架","Rack","http://cdn.ococci.com/dict_ali/2022-02-20/1645357486534372815_5d60c3ab-bc39-91d9-30d5-36bd3cd55af2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jià", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/架_jià.mp3", "架子 吵架 绑架 绞架 骨架 打架 拉架,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于有支架或有机械的东西：屋里面有一架木头梯子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"架子：它的车架、轮子、锭子跟一般的手摇纺车没有什么两样。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"搭起；构筑：河面上又架了一座大桥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"支承；支撑：这物件挺单薄的，哪架得住摔打。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用暴力挟持：犯罪团伙绑架了小孩后，便向其家长索要钱财。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"争吵：他态度粗暴，常与客吵架。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38351_块_22359.gif","7","左右","土","块","Block","http://cdn.ococci.com/dict_ali/2022-02-25/1645760990407353374_aba264cc-d851-2e97-bf14-db8e7dddd3bd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/23/块_kuài.mp3", "块头 块体 块儿 块规 块根,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"成疙瘩或成团的东西。量词，用于块状或某些片状的东西。量词，用于银币或纸币，等于“圆”。");
