INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"焦躁:一会儿毛卷拧成绳了，一会棉纱打成结了，急得人满头大汗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"匆促：究竟是啥事体呀?这么急，连电话上也不肯讲。");
