INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"容易发怒；急躁：急性子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"匆促：鲁迅先生立刻带着纸包和那封信，急步赶回家里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对大家的事或别的困难赶快帮忙：我们的领导干部要想人民之所想，急人民之所急。");
