INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"正直；公正的：他理直气壮地说：“我没错。”");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坦率；爽快：你嘴巴很直，便是骂我一顿，我也不见怪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挺直；伸直：孔乙己直起身又看一看豆。");
