INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"首都。全国最高行政机关所在地：公元1004年秋，辽军大举进攻北宋，兵锋直抵黄河岸边的澶城下，威胁宋的都城。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大城市：这里不仅是元朝的政治中心，还是闻名世界的商业大都市。");
