INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10619_静_38745.gif","14","左右","青","静","Quiet","http://cdn.ococci.com/dict_ali/2022-02-25/1645766856104336815_1fb4c8c1-a8ee-1bdb-8131-586c8d75b517.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/184/静_jìng.mp3", "安静 寂静 宁静 恬静 文静 静止 静悄悄,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"没有声音；寂静：夜很静。月亮已经偏西了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停止不动：风墙动，龟蛇静，起宏图。");
