INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"唯一：村边的那座独木桥是二十多年前我爷爷带领大伙儿修的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"单独；独自：他再也不能大权独揽了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年老没有儿子的人：村里那些鳏寡孤独的老人在政府的关怀下，安度幸福的晚年。");
