INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数学名词。以半圆的直径为轴，使半圆旋转一周而成的立体；由中心到表面各点距离都相等的圆形立体：球的中心与球面各点距离相等。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"球类活动：爸爸是个球迷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"球形或接近球形的东西：点点昏黄的火球，就是那无数的电灯。");
