INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与床相似的东西：他的牙床不知什么原因肿了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。多用于被褥等：他送了我一床毛巾被。");
