INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"空；尽；一点不剩：农会权力无上，把地主的威风扫光。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬辞：欢迎光临寒舍。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(一般指)照射在物体上，使人能看见物体的那种物质：大气从太阳那里得到光和热，这是人人都能感觉到的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"景色：在春光明媚的季节，人们可以欣赏遍地盛开的野花。");
