INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有名声：名望。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拜访：看望。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"埋怨，责怪：怨望。");
