INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"俯下；垂下：她听了这话，默默地低下头。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从下到上的距离小，离地面近：小白兔问小燕子：\"你为什么飞得这样低?\"");
