INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"药末：健胃散。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文体名。篇幅不长，形式自由，不用韵，字句不求整齐。抒情、叙事、议论均可，一般又可分为杂文、小品、游记、速写等：散文。");
