INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"东西的最下部：墙角。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人和动物身体最下部接触地面的肢体：难道她没有脚，自己还会走路吗？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指跟体力搬运有关的：脚夫。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/71595_蜻_34619.gif","14","左右","虫","蜻","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/144/蜻_qīng.mp3", "蜻蜓 蜻蜓点水,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫，捕食小飞虫，是益虫：这里有一只大蜻蜓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7411_蜓_34579.gif","12","左右","虫","蜓","Dragonfly","http://cdn.ococci.com/dict_ali/2022-02-25/1645757578593154362_3a7242c7-e71b-f2ef-b0f1-bb486f91bebf.mp3");
