INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"见“蜻”");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/2842_迷_36855.gif","9","半包围","辶","迷","Confused","http://cdn.ococci.com/dict_ali/2022-02-25/1645766823491122578_4b62ed3e-d1b5-850f-6b38-79c46045f924.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/迷_mí.mp3", "迷路 迷糊 迷茫 迷信 迷漫 迷失 迷途,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"入迷于某种事物的人：球迷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分辨不清；失去判断能力：敌人在山口迷了路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"神智昏乱：迷糊。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"诱惑，陶醉：迷惑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"沉醉，对某种事物产生特殊的眷恋：迷恋。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75573_藏_34255.gif","17","上下","艹","藏","Hide","http://cdn.ococci.com/dict_ali/2022-02-25/1645741845905345593_051442fc-2a26-f467-f6cb-f7668f995af9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/140/藏_cáng.mp3", "珍藏 收藏 隐藏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"躲藏起来；不让人发现：你们厂人才济济，真是个藏龙卧虎之地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"收存；储存：这件古董他珍藏了整整30个春秋。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/140/藏_zàng.mp3", "宝藏 藏历 藏青 藏香 藏族 道藏 三藏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"西藏的简称：川藏线上的英雄运输队。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"佛教、道教经典的总称：明朝正统、万历年间分别编印《正统道藏》、《万历续道藏》共5485卷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"贮存财物地方：中国的地下宝藏十分丰富。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"藏族。我国少数民族之一：新年晚会上，我们学校的汉、藏同学欢聚一堂。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50807_造_36896.gif","10","半包围","辶","造","Make","http://cdn.ococci.com/dict_ali/2022-02-25/1645768603402590254_5c1fefe0-8aa5-f97d-a939-8cecbbfe5771.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/造_zào.mp3", "造句 造反 造谣 造福 制造 创造 酿造 深造 铸造,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"培养：从他完成的论文来看，是一个可造之才。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"制作：南宋所造的船，上面已装有指南针。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"到：到了清末，梁启超先生的\"新文体\"可算登峰造极了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"成就：他在妇产科学方面有极高的造诣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/5364_蚂_34434.gif","9","左右","虫","蚂","Ma","http://cdn.ococci.com/dict_ali/2022-02-25/1645772940079398235_6c2e517f-260d-fd64-4d46-84fde7f16a01.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚂_mà.mp3", "蚂蚱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚂蚱：蝗虫的俗称，亦指蚱蜢。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚂_mǎ.mp3", "蚂蚁 蚂蟥,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚂蟥。又名水蛭，环节动物，体形扁长，暗绿色，尾端有吸盘，生活在水田沼泽中，能刺伤人、畜皮肤并吸血：刚下田就遭蚂蟥叮了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚂蚁。昆虫，体小，长形，黑色或褐色，头大，有一对复眼，触角长，腹部卵形。雌蚁和雄蚁有翅膀，工蚁没有。在地下筑巢，成群穴居：墙角有一个蚂蚁出入的洞穴。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚂_mā.mp3", "蚂螂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚂螂：蜻蜓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/53631_蚁_34433.gif","9","左右","虫","蚁","Ant","http://cdn.ococci.com/dict_ali/2022-02-25/1645768001566945548_db2e6408-1063-3305-c1e2-7c3280361505.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚁_yǐ.mp3", "蚂蚁 白蚁 蚕蚁 蝼蚁 蚁穴 蚁附 蚁丘 蚁醛 蚁巢,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫名。体小，有黑、红、褐等色，触角成丝状或棒状，腹部呈球状，腰细，群居。分雄蚁、雌蚁、工蚁及兵蚁。工蚁担任筑巢、采食物、抚养幼蚁等工作，兵蚁则负责守卫：天快下雨了，小蚂蚁们纷纷忙着搬家。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像蚂蚁一样：蚁聚。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64534_食_39135.gif","9","上下","飠","食","Food","http://cdn.ococci.com/dict_ali/2022-02-25/1645757279495357200_898f6e10-4669-577a-f1f3-f218133a520a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/食_sì.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拿东西给人吃：食母。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/食_shí.mp3", "食管 食具 食品,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吃：食肉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吃的东西：食品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"日月亏缺或完全不见的现象：日食。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"俸禄：“君子谋道不谋食”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/188/食_yì.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于人名：郦食其（jī）（中国汉代人）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37867_粮_31918.gif","13","左右","米","粮","Grain","http://cdn.ococci.com/dict_ali/2022-02-24/1645669454396035883_edf78c4b-09c3-1096-5b69-b314b826bd41.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/117/粮_liáng.mp3", "粮站 粮栈 粮饷 粮食 粮库 粮荒 粮店,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"可吃的谷类、豆类等。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"作为农业税的粮食。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/25758_蜘_34584.gif","14","左右","虫","蜘","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/143/蜘_zhī.mp3", "蜘蛛 蜘蛛网,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蜘蛛。节肢动物，种类很多。身体呈圆形或长圆形，能分泌粘液，凝成细丝，结网捕食昆虫，生活在屋檐或草木间：蚊子被小小的蜘蛛消灭了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/72404_蛛_34523.gif","12","左右","虫","蛛","Spider","http://cdn.ococci.com/dict_ali/2022-02-25/1645757947284344089_4bfac1bd-4a34-655d-271d-b2a01fb4135c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/143/蛛_zhū.mp3", "蛛丝 蜘蛛 蛛网尘封 蛛丝马迹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蜘蛛。节肢动物，种类很多。身体呈圆形或长圆形，能分泌粘液，凝成细丝，结网捕食昆虫，生活在屋檐或草木间：茫然中，他忽然发现墙角处有一只蜘蛛在风中拼力结网。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84830_网_32593.gif","6","半包围","冂","网","Net","http://cdn.ococci.com/dict_ali/2022-02-25/1645761637397087584_0cc47df2-67d4-dde1-7be1-35679ca087b0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/124/网_wǎng.mp3", "网罗 网络 网球 天网 法网 漏网 落网,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用网捕捉：网鸟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状像网的：网兜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用绳线结成的渔猎工具：撒网。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像网那样的组织或系统：通讯网。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30081_圆_22278.gif","10","全包围","囗","圆","Circle","http://cdn.ococci.com/dict_ali/2022-02-25/1645773146824086171_db70057c-6083-d3ee-380b-9923a68aaf62.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yuán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/圆_yuán.mp3", "团圆 椭圆 方圆 半圆 圆滑 圆满 复圆 桂圆 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"圆形：在她那圆而微黑的面庞上，有着一双大而黑的眼睛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"掩饰矛盾；使周全：他根本不能自圆其说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"我国的货币单位：十角人民币等于一圆。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22481_严_20005.gif","7","半包围","一","严","Yan","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/严_yán.mp3", "严格 严厉 严紧 严寒 严办 严肃 严重 严酷 严词,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“疠”、“癞”，恶疮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"严肃：声色俱严。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"严格：严禁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凶猛：严害。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"磨，使锋利：严兵秣马。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64005_寒_23506.gif","12","上下","宀","寒","Cold","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647481103157.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/寒_hán.mp3", "寒潮 寒冷 寒风 寒带 寒流 寒土 寒酸 胆寒 严寒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"害怕；畏惧：猫头鹰在耳朵边不住地啭，我的心被它叫寒起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"穷困:那些地主婆娘和地主媳妇，故意装着一副贫寒相给人看。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"谦词：倘若各位不嫌弃，请到寒舍奉茶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中医术语，指因受寒而引起的机能衰退的病症：这贴膏药，舒筋活血，驱寒散热。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"冷：我冒着严寒，回到相隔二千余里，别了二十余年的故乡去。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48368_酷_37239.gif","14","左右","酉","酷","Cool","http://cdn.ococci.com/dict_ali/2022-02-25/1645763474926262900_58f27218-4515-a66b-e564-99863537f834.mp3");
