INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中医学“六淫”之一。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"热。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/67989_凉_20937.gif","10","左右","冫","凉","Cool","http://cdn.ococci.com/dict_ali/2022-02-25/1645763474926262900_58f27218-4515-a66b-e564-99863537f834.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/凉_liáng.mp3", "凉快 凉爽 冲凉 冰凉 乘凉 悲凉 世态炎凉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"冷；温度较低：刚一立秋，天气就渐渐凉了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"失望；灰心：一听领导不同意，我们的心都凉了。");
