INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人、动物的全身：身体。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物质存在的状态或形状：固体。");
