INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物的本身或全部：物体。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与“用”相对。“体”与“用”是中国古典哲学的一对范畴，指“本体”和“作用”。一般认为“体”是最根本的、内在的；“用”是“体”的外在表现。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亲身经验、领悟：体知。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物的格局、规矩：体系。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文章或书法的样式、风格：体裁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"设身处地为人着想：体谅。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/3/体_tī.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔体己〕ａ．家庭成员个人的私蓄的财物；ｂ．亲近的，如“己话”，亦作“梯己”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/17349_之_20043.gif","3","独体","丶","之","Of","http://cdn.ococci.com/dict_ali/2022-02-25/1645770790031270780_8cc65910-2a7f-b7b4-209d-e7641ba3fe3f.mp3");
