INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词，这，那：“之二虫，又何知”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，表示领有、连属关系：赤子之心。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在主谓结构之间，使成为句子成分：“大道之行也，天下为公”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，表示修饰关系：缓兵之计。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"虚用，无所指：久而久之。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"往，到：“吾欲之南海”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词，代替人或事物：置之度外。");
