INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对某事熟悉：曹操虽然有数量上的绝对优势，但不习水战，水军实力不如孙、刘联军。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"行为：他这个人真是恶习不改。");
