INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"néng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/128/能_néng.mp3", "能力 能源 才能 功能 本能 全能 万能 智能,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能力；才干：清王朝腐败无能，签订了丧权辱国的《马关条约》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有才能的：他们可以说是\"能才多劳\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示有能力做某事具备某种技巧、功用：她能成为我们时代的语言艺术大师。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能量。度量物质运动的一种物理量，一般解释为物质做功的能力。能的基本类型有势能、动能、热能、电能、光能、化学能和原子能：液体蒸发时，飞出去的是动能比较大的分子。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63934_饱_39281.gif","8","左右","饣","饱","Be full","http://cdnmu.gurobot.cn/saodubi/dict/audio/Be_full.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/190/饱_bǎo.mp3", "饱和 饱学 饱受,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吃足了，与“饿”相对：我吃得很饱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"足、充分：这个稻穗很饱满。");
