INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"角色；演员：她现在已是团里的名角了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竞争；较量：我不能不留意，他们是我正在暗中角斗的主要敌手。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/2252_珠_29664.gif","10","左右","王","珠","Bead","http://cdn.ococci.com/dict_ali/2022-02-22/1645533790855747642_9c989742-aad7-db02-aa90-0e425682ff54.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/95/珠_zhū.mp3", "珠宝 珠子 珠泪 珠算 明珠 泪珠 水珠 珍珠 露珠 夜明珠 珠光宝气 珠联璧合 珠辉玉映,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蛤蚌壳内由分泌物产生成圆形而有光泽的东西。可入药，也可做装饰品：不下汪海洋，难得夜明珠。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像珠子一样的东西：它那两颗小黑豆似的眼珠，一直在我心里装着。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59681_摇_25671.gif","13","左右","扌","摇","Shake","http://cdn.ococci.com/dict_ali/2022-02-24/1645716750322379084_4c75472e-ad93-7c31-0854-9ad1a1adfa33.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yáo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/55/摇_yáo.mp3", "摇动 摇摆 摇晃 摇篮 摇曳 动摇 招摇 飘摇 摇身一变 摇头摆尾 摇摆不定 摇头晃脑 摇旗呐喊 摇摇欲坠 摇尾乞怜 风雨飘摇,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物体来回摆动：她在平衡木上摇晃了几下，还是站稳了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/72126_躺_36538.gif","15","左右","身","躺","Lie down","http://cdnmu.gurobot.cn/saodubi/dict/audio/Lie_down.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/163/躺_tǎng.mp3", "躺下 躺椅 躺卧 躺倒 平躺,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"睡；平卧：他正躺在床上休息。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/45973_晶_26230.gif","12","品字","日","晶","Crystal","http://cdn.ococci.com/dict_ali/2022-02-25/1645766042924417877_85de2cff-b02d-f3d0-1c92-df91ac80ac1f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/61/晶_jīng.mp3", "晶莹 晶亮 晶粒 水晶 结晶 冰晶 液晶 亮晶晶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水晶的简称：茶晶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"光亮；明亮：一条条晶亮的泉流和瀑布，迅速地在我们眼前闪过。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"成果：这些血汗的结晶不正是时间与生命的光辉记录吗?");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29667_停_20572.gif","11","左右","亻","停","Stop","http://cdn.ococci.com/dict_ali/2022-02-25/1645753368506550001_3b6afb95-1b29-a5a4-c921-3684153eb10c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tíng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/5/停_tíng.mp3", "停靠 停留 不停 停止 停课 停电 停办,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"止住，止息：停止：");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放置，泊船：停放。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中断：停电。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"妥当：停妥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"滞留：停留。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24996_机_26426.gif","6","左右","木","机","Machine","http://cdn.ococci.com/dict_ali/2022-02-25/1645751742683109163_e9ccc5eb-f9eb-b2b7-46be-dc14f3072255.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/机_jī.mp3", "飞机 机场 机动 机灵 机器 客机 战机 专机,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"飞机：空战中，我们击落三架敌机。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计策；计谋：这本书的重点是渲染诸葛亮的神机妙算。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"机会：机不可失，时不再来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"重要的事务：日理万机。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"机械；器械：车间里，机声隆隆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"灵巧：他灵机一动，计上心来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/45101_展_23637.gif","10","半包围","尸","展","Exhibition","http://cdn.ococci.com/dict_ali/2022-02-25/1645766626720744920_f8291770-9157-f6df-1597-5599fb7daa02.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/展_zhǎn.mp3", "展示 展现 发展 扩展 开展 伸展 舒展 展览 展翅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"延缓，放宽期限：展延。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"陈列：展品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"察看，省（xǐng）视：展墓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“辗”，辗转。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"张开，舒张开：展开。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"施行，发挥（能力）：展拜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54942_透_36879.gif","10","半包围","辶","透","Thorough","http://cdn.ococci.com/dict_ali/2022-02-22/1645493997845641212_1143df1c-c0fd-d167-53a2-7c7676dad4ff.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/透_tòu.mp3", "透亮 透明 穿透 湿透 透风 透彻 透底,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"彻底，深入：透彻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"穿过；通过：阳光可以透过云层照到地面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"饱满的，充分的：雨已下透。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"显露，泄漏，暗中告诉：白里透红。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"极度：熟透了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/44192_翅_32709.gif","10","半包围","羽","翅","Wings","http://cdn.ococci.com/dict_ali/2022-02-25/1645771609961251689_5d96c512-6bab-7b7c-cab2-726dc96f702b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/125/翅_chì.mp3", "展翅 鞘翅 鱼翅 振翅 鼻翅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫的飞行器官，通常又指鸟类的飞行器官：蓝天白云，鸽子展翅高飞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鱼翅。即鲨鱼鳍经过加工后的软骨条，是十分珍贵的食品：席上有龙虾、翅子和海蟹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“啻”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物体形状或像翅膀：飞机如果没有机翅，就不可能在天空飞翔。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/58339_膀_33152.gif","14","左右","月","膀","The shoulder","http://cdnmu.gurobot.cn/saodubi/dict/audio/The_shoulder.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/膀_bàng.mp3", "吊膀子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吊膀子");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/膀_bǎng.mp3", "肩膀 膀子 翅膀 臂膀,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"胳膊上部靠肩的部分：天阴，我膀子疼得厉害。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"páng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/膀_páng.mp3", "膀胱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"许多脊椎动物供暂时贮存尿液的可膨胀膜性囊。人类的膀胱位于盆腔内、直肠的前面，收集来自输尿管的尿液，并通过由括约肌开闭的口间歇性地将尿液排出体外。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/膀_pāng.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浮肿：我头脸也膀了，腰腿也断了。——《野叟曝言》");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指嘴或脸向外突出、鼓起：这王簪儿登时把那付奴脸，膀的有房梁高，也不搽脸了。——《金瓶梅词话》 ");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63281_唱_21809.gif","11","左右","口","唱","Sing","http://cdn.ococci.com/dict_ali/2022-02-25/1645769171993227243_605fe9b1-a39d-2fa8-0bc6-b5817483fd8c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/18/唱_chàng.mp3", "唱歌 说唱 会唱 合唱 齐唱 对唱 伴唱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"唱歌或依照乐曲发出声音：我们一齐唱《国歌》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高声呼叫：时间还早，鸡刚唱三遍。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"歌词；歌曲：在这出戏里，旦角的唱儿不多。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37628_朵_26421.gif","6","上下","木","朵","Duo","http://cdn.ococci.com/dict_ali/2022-02-23/1645618359036372742_bc99b70d-e427-29dc-a48c-17cbb75c1235.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"duǒ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/朵_duǒ.mp3", "花朵 云朵 一朵花 耳朵 骨朵 红霞万朵,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物的花或苞：树上开满了花朵。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于花朵或云彩等：葱翠的令箭似的叶状枝上，四朵花竞相开放。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94626_腰_33136.gif","13","左右","月","腰","Waist","http://cdn.ococci.com/dict_ali/2022-02-20/1645343810980655388_99c0aa17-a3fa-72ac-eac1-ed51a13f2b9a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/腰_yāo.mp3", "腰包 腰鼓 腰身 腰椎 叉腰 拦腰 伸腰 撑腰 腰缠万贯 点头哈腰 虎背熊腰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"胯上胁下的部分，在身体的中部：腰围。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"东西的中段，中间：半山腰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中间狭小像腰部的地势：土腰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"裤、裙等围在腰上的部分：裤腰。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/41312_坡_22369.gif","8","左右","土","坡","Poe","http://cdn.ococci.com/dict_ali/2022-02-22/1645511552058266441_24a3367d-5bc8-1554-67bb-a2208e22dde9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/23/坡_pō.mp3", "坡度 坡道 坡坎 山坡 陡坡 缓坡 斜坡,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地形倾斜处：老者的背影消失在山坡的绿丛里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"倾斜：这里的坡度大约有30度。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/15193_沉_27785.gif","7","左右","氵","沉","Sink","http://cdn.ococci.com/dict_ali/2022-02-24/1645708629090656340_117cc060-a143-357d-6cdb-1bf1e9049698.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chén", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/76/沉_chén.mp3", "沉闷 下沉 沉重 沉积 沉淀 沉浸 沉浮 沉思 沉甸甸 沉着,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分量大，重：树上挂满了沉甸甸的果实。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"感觉沉重：怪不得我这腿有点沉呢!原来是快下雨了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稳定：他遇事总能沉着冷静。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"没入水中。与\"浮\"相对：敌人那只大船被击沉了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使降落：落日徐徐沉没，周围雪峰上的红光逐渐消退。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分量重：这个箱子很沉。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/51141_伸_20280.gif","7","左右","亻","伸","Shim","http://cdn.ococci.com/dict_ali/2022-02-22/1645534090587988187_84f7a285-8213-da04-1503-5ac137a4c996.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/2/伸_shēn.mp3", "伸张 张开 伸出,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"舒展开：～直。～手（ａ．伸出手；ｂ．喻向别人或上级要东西、荣誉、照顾；ｃ．指插手）。～张（扩大，如“～张正义”）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/26652_潮_28526.gif","15","左中右","氵","潮","Tide","http://cdn.ococci.com/dict_ali/2022-02-23/1645630684490273426_7b1eb0ad-1c79-30be-7586-d25192d6688f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cháo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/83/潮_cháo.mp3", "潮水 思潮 高潮 受潮 来潮 潮流 潮气,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻像潮水般汹涌起伏的：把酒酹滔滔，心潮逐浪高。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"湿：冬天，衣服很容易受潮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"成色差，技术不精的状态：经过一个假期，他的足球技术已回潮了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"海水因日月引力作用而定期出现的涨落现象：渔民利用落潮的间歇抢修渔船。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63112_湿_28287.gif","12","左右","氵","湿","Wet","http://cdn.ococci.com/dict_ali/2022-02-23/1645613385458249868_e599d96d-26ec-0f0f-33b1-634b3e0159d2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/81/湿_shī.mp3", "潮湿 湿度 湿润 打湿 浸湿 淋湿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水分多或沾了水：在已开垦的热带草原地区，湿季的降水及时，雨量充足，田地里就能得到好收成。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/82409_呢_21602.gif","8","左右","口","呢","Where's","http://cdnmu.gurobot.cn/saodubi/dict/audio/Where%27s.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ne", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/呢_ne.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉疑问语气：他在哪儿呢？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉确定语气：早呢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉动作正在进行：他们在学习呢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在句中，〈表〉停顿：现在呢，生活可比过去好多了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ní", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/呢_ní.mp3", "呢子 呢衣 呢绒 呢喃 毛呢 花呢 厚呢,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"呢子。一种较厚较密的毛织物，多用来做冬装或春秋装：他又买了一件呢子大衣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/47649_闷_38391.gif","7","半包围","门","闷","Stuffy","http://cdn.ococci.com/dict_ali/2022-01-15/1642246159875931133_7c42d291-db92-33dc-6da6-e8f8310a07b2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mèn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/181/闷_mèn.mp3", "苦闷 沉闷 解闷 纳闷 烦闷 闷闷不乐,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"密闭；使不透气：大家坐在闷罐车里，昏昏欲睡，也不知车到了什么地方。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"心情不舒畅；烦恼：比赛输了，心里闷得慌。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/181/闷_mēn.mp3", "闷气 闷死 闷热 闷声闷气,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"气压低或空气不流通等引起的不舒服：闷热。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不出门：闷在家里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"紧闭，不让出气：刚泡的茶闷一闷再喝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不出声或声音不响亮：闷声闷气。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34180_消_28040.gif","10","左右","氵","消","Eliminate","http://cdn.ococci.com/dict_ali/2022-02-24/1645696058609023368_70032b31-3ad8-395f-06bd-8299f71714d7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/79/消_xiāo.mp3", "消灭 消失 消化 消除 消息 消亡 消耗 消费 消毒 消炎,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"去掉：除去：他们正在忙着给病人消毒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消失；完全不存在：她已经是五十岁左右的人了，但红颜未消。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52988_息_24687.gif","10","上下","心","息","Interest","http://cdn.ococci.com/dict_ali/2022-02-25/1645752914144005003_b179462f-f98a-25ab-23d1-b5745d370aa1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/46/息_xī.mp3", "休息 气息 生息 信息 叹息 出息 消息,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"信息：得到母亲去世的消息，我很悲痛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"呼吸时进出的气：他还来不及喘息，又投入了更紧张的战斗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"休息：过去人们日常生活，一举一动，一作一息，都要选择时日。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"利钱；利息：这种年息12%的集资吸引了不少人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停止：震耳之声还没有息，空气里已经散满了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/81416_搬_25644.gif","13","左中右","扌","搬","Move","http://cdn.ococci.com/dict_ali/2022-02-25/1645750000534214360_dea90aa2-80f6-c3f0-9e19-16422485075c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/55/搬_bān.mp3", "搬动 搬迁 搬弄 搬运 照搬 搬弄是非,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"移动物体的位置（多指笨重的或较大的）：搬砖。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迁移：搬家。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"请出：他把厂长搬来，希望厂长能为自己做主。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46521_响_21709.gif","9","左右","口","响","Ring","http://cdn.ococci.com/dict_ali/2022-02-25/1645719144468557245_2c4fe5af-719b-21bb-6a49-f71d1ad64705.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/响_xiǎng.mp3", "响亮 响声 响应 回响 响起 反响,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"嘶哑：父子俩你一句我一句地抬起杠来，喉咙也响了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"回声：边区军民热烈响应毛主席的“自己动手，丰衣足食”的伟大号召。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"发出声音：风吹得树枝呼呼作响。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。鸣炮十响以庆祝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"声音大：号声真响。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/80695_棍_26829.gif","12","左右","木","棍","Stick","http://cdn.ococci.com/dict_ali/2022-02-24/1645711456657449005_365ac9b7-3c44-e6ef-886d-c5526bf6ce47.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gùn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/棍_gùn.mp3", "棍子 棍棒 木棍 光棍 竹棍 铁棍 恶棍 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"棒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称坏人。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǔn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/棍_gǔn.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能够转动，用以缠绕线、弦的旋纽。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/40152_汤_27748.gif","6","左右","氵","汤","Soup","http://cdn.ococci.com/dict_ali/2022-02-25/1645761550126438774_af3c43d4-d77c-9f7b-3bbf-8130ac52573b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/76/汤_shāng.mp3", "浩浩汤汤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔汤汤〕大水急流的样子，如“河水汤汤”，“浩浩汤汤”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/76/汤_tàng.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"触，碰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"遇上，碰上。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/76/汤_tāng.mp3", "汤包 汤圆 汤匙,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"热水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"烹调后汁特别多的食物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"专指温泉（现多用于地名）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中药的剂型。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"煮东西的汁液。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33201_砧_30759.gif","10","左右","石","砧","Anvil","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/106/砧_zhēn.mp3", "砧骨 砧基簿 砧鈇 砧声 砧锧 砧架 砧杵 砧基,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"捶、砸或切东西的时候，垫在底下的器具，有铁的、石头的、木头的：我家里的砧板很结实的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状和作用像砧子的：砧骨。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29658_扇_25159.gif","10","半包围","户","扇","Fan","http://cdn.ococci.com/dict_ali/2022-02-25/1645772179658541764_46a2f9a1-5de4-a412-7444-7cb171fd08f2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扇_shàn.mp3", "扇子 扇形,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，用于门窗等：一扇门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摇动生风取凉的用具：扇子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指板状或片状的屏：门扇。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扇_shān.mp3", "扇动 扇风机,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用手掌打：扇耳光。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鼓动别人去做不应该做的事：扇动。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摇动扇子或其它东西，使空气加速流动成风：用扇子扇。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/70297_椅_26885.gif","12","左右","木","椅","Chair","http://cdn.ococci.com/dict_ali/2022-03-30/542367100000006d_1648646728451.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/椅_yǐ.mp3", "椅子 椅披 交椅 电椅 旧椅,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用木、竹、藤等制成的坐具：他把桌子、椅子都擦得干干净净。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/椅_yī.mp3", "椅梧,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落叶乔木，木材可以制器物。亦称“山桐子”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/86534_萤_33828.gif","11","上中下","艹","萤","Hotaru","http://cdnmu.gurobot.cn/saodubi/dict/audio/Hotaru.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yíng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/136/萤_yíng.mp3", "萤火虫,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫，通称\"萤火虫\"，身体黄褐色，尾部有发光器，能发出绿色的光。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/79742_牵_29301.gif","9","上下","牛","牵","Pull","http://cdn.ococci.com/dict_ali/2022-02-24/1645708529908407042_7e783d43-9671-99b7-6a7a-25de7fcda9d7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/牵_qiān.mp3", "挂牵 拘牵 牵动 牵线 牵引 牵强 牵连 牵肠挂肚,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拉，引领向前：牵引。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"关连，带累：牵连。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/71515_织_32455.gif","8","左右","纟","织","Weave","http://cdn.ococci.com/dict_ali/2022-02-24/1645677782175668175_547cb39c-2046-e67c-c95e-7afc21fc6afe.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/织_zhì.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“帜”，旗帜。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/织_zhī.mp3", "织布 织锦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引申为构成：罗织罪名。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用丝、麻、棉纱、毛线等编成布或衣物等：织布。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用染丝织成的锦或彩绸：织锦。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84096_斗_26007.gif","4","独体","斗","斗","Dou","http://cdn.ococci.com/dict_ali/2022-02-24/1645706651787733443_3add438d-f3ed-edbf-bd20-151c463d11ea.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/59/斗_dòu.mp3", "斗争 斗志 斗气 斗法 斗殴 斗嘴 搏斗 打斗,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使动物斗(旧时常用来赌博)：他们俩在村边斗蛐蛐，引来好多人观看。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"争斗：解放前，这两村的村民曾因农田用水发生过械斗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比赛：在这场艰苦的斗智中，他们斗不过敌手，败下阵来。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/59/斗_dǒu.mp3", "斗胆 斗笠 斗篷 烟斗 漏斗 煤斗 泰斗 星斗,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"容量单位。十升为一斗，十斗为一石：今年比去年每亩多收了五斗粮食。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"圆形指纹：斗箕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形如斗状的器物：父亲的烟斗是姐姐十几年前送的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"星宿名，二十八宿之一：北斗七星");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"夸张为像斗那样大小：斗胆、斗门。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量粮食的器具，容量是一斗，呈方形或鼓形，多用木头或竹子制成：地主们用小斗出大斗进的方式，残酷剥削农民。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37702_具_20855.gif","8","上下","八","具","Tool","http://cdn.ococci.com/dict_ali/2022-02-24/1645715046152608698_5cd36618-0d5e-e5b2-fe54-93f3f3d76b0d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/具_jù.mp3", "具备 具有 具体 教具 农具 器具,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"备，具有：这些人也是敌人的第五纵队，不过比前一种稍具形式上的区别。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"供使用的器物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于尸体或某些器物，家中人当时已为我们预备了两具小棺木，搁在廊下。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/23227_次_27425.gif","6","左右","欠","次","Times","http://cdn.ococci.com/dict_ali/2022-02-24/1645703089973084173_1d90601a-21e0-d2e3-4256-457d0fef4a77.mp3");
