INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"质量欠佳：这个杯子是次品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"出外远行时停留的处所：旅次、舟次、途次。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"第二：在地壳里，硅的含量在所有元素中居第二位，仅次于氧。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"顺序：请大家依次排队上车。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示动作的次数：列宁曾经多次批评左派的幼稚病。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/65146_丢_20002.gif","6","上下","丿","丢","Lose","http://cdn.ococci.com/dict_ali/2022-02-25/1645773245655128930_e2e076fa-3a03-5e9b-29ed-3a50b03c834d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/丢_diū.mp3", "丢人 丢面子 丢丑 丢失 丢三落四,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"遗失；失落：妈妈告诉巴特，小羊羔是牧场丢的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"扔；抛弃：请不要随地乱丢果皮。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/62874_哪_21738.gif","9","左右","口","哪","Where","http://cdn.ococci.com/dict_ali/2022-02-25/1645770757302130772_8cd66d97-3438-c2f9-9d1a-421b21201c07.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哪_nǎ.mp3", "哪个 哪儿 哪些 哪里 哪样 哪怕 哪会儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疑问代词。A. 后面跟量词或数量词，要求在同类事物中加以确指。鲁迅的杂文《论雷峰塔的倒掉》在《鲁迅全集》的哪一卷?B. 用于反问，表示否定或肯定：这哪里是什么配载图及注释，简直是一份科学报告。C. 表示不确定的一个：哪天我得抽空去拜访一位老同学。D.用于虚指，表示任何一个：他不能担此重任，从哪方面看也不能。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"né", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哪_né.mp3", "哪吒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哪吒：神话小说《封神榜》里的神名。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"něi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/něi.mp3", "哪个 哪年 哪会儿 哪些,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"“哪”和“一”的合音，但指数量时不限于一：哪个。哪年。哪会儿。哪些。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"na", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/哪_na.mp3", "好哪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，用于句末：加油哪！");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/5827_新_26032.gif","13","左右","斤","新","New","http://cdn.ococci.com/dict_ali/2022-02-25/1645769115129448689_18c67918-8551-10a5-fe3d-ea9ba5a09260.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xīn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/59/新_xīn.mp3", "创新 全新 更新 新书 崭新 新年 翻新,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刚有的，还未用过的：妈妈特地从商店给我买了一个新书包。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不久以前：这是我们新建的房子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示一种有异于旧质的状态和性质：这是一个新时代。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刚出现的或刚经历的：陈然可以从他那里得到更多更新的消息。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/49307_每_27599.gif","7","上下","母","每","Every","http://cdn.ococci.com/dict_ali/2022-02-25/1645765120905465411_b0b2768a-de4f-3536-17e8-1183d7a10b62.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"měi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/74/每_měi.mp3", "每天 每年 每当 每逢,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指全体中的任何一个或一组：周末晚会上每个组都要出一个节目。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38239_平_24179.gif","5","独体","干","平","Ping","http://cdn.ococci.com/dict_ali/2022-02-25/1645767355071871368_f1442c50-a967-1c55-e652-72469be4fdaf.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"píng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/平_píng.mp3", "平常 公平 平时 平坦 平均 平安,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表面没有高低凹凸、不倾斜：找一块平坦的地方，作比赛场地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使平：昨天，三班的同学平了操场。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(与其他的东西)高度相等；不相上下：三班与二班球赛打平了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"公正；均等：在我们国家，不分男女老少，贫富贵贱，大家是平等的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"安定；宁静：老师平心静气地给同学们讲道理。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"普通，经常：雷锋在平凡的工作岗位上，做出了不平凡的贡献。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"平定；用武力征服镇压：解放军终于平息了土匪的叛乱。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48071_她_22905.gif","6","左右","女","她","Her","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/她_tā.mp3", "她们,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"第三人称代词。指自己和对方以外的某个女性：她转过头来瞧了瞧白大嫂子的骡子，摇一摇头。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88036_些_20123.gif","8","上下","二","些","Some","http://cdn.ococci.com/dict_ali/2022-02-25/1645773550467458979_34dac007-4b66-fa0d-3f1d-7eb088555b26.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/些_xiē.mp3", "些许 些微 有些 这些 那些 险些,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在形容词后表示比较的程度：河北的扁柏树比山西的清秀些。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示不定的数量(少许；一点儿)：两税法开始实行的一段时间内，唐政府财政收入增加了些。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言。犹\"们\"：你们这样吵，里头老师些都听见了!");
