INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"构成一个整体的：这一单元的课文都是记叙文。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"原始的；第一：今年元旦我们队要举行联欢会。");
