INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不快；慢：人一旦上了年纪，行动就变得迟缓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比规定的时间晚：他上课经常迟到。");
