INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/78/洗_xǐ.mp3", "洗礼 洗尘 洗涤  洗澡 洗印 冲洗 洗劫,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像用水洗一样地彻底抢光杀尽：1942年2月间，武乡被洗劫一空。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用水或其他溶剂(如汽油、煤油)等除去物体表面上的脏东西：修建的澡塘解决了全机关近二百名职工的洗澡问题。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"切削把物体表面凿去一层使之变小，或把物内侧凿去一层使之增大：场磙原是小场上用的，要转大圈子就得洗一洗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消除或把冤枉的事情弄清楚：直到1979年底，父亲的不白之冤才被洗雪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"照相：照片是我拿去洗的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"玩牌时把牌搅和后再整理齐，以便继续玩：他挺熟练地洗着桌上那副骨牌。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/78/洗_xiǎn.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/16453_背_32972.gif","9","上下","月","背","Back","http://cdn.ococci.com/dict_ali/2022-02-25/1645766375085404065_47c555f5-97fc-b808-ac28-d4fa00b75838.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/127/背_bèi.mp3", "背诵 背后 背面 背离 背叛 背弃 违背,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"违反；违背：他弃信背盟隐匿宝藏。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物体的反面：他的书法力道浑厚，墨透纸背。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脊背。自肩至后腰部分：我很悚然，一见她的眼盯着我，背上也就遭了芒刺一般。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与\"向\"相对：这地方背山面海，风景十分秀丽。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"离开；抛弃：善感的心灵，也曾为背乡离井的行人落下伤感的眼泪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"避开：干事正大光明，没什么好背着人的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"偏僻；冷僻。与\"热闹\"相对：山里的路很背，一个人走得小心点儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"背诵；凭记忆通读：直到现在，我还能背诵她教我们的诗。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bēi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/127/背_bēi.mp3", "背篓 背带 背罪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"担负；承受：背负。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人用脊背驮：背粮食。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/41024_刚_21018.gif","6","左右","刂","刚","Gang","http://cdn.ococci.com/dict_ali/2022-02-22/1645526745423140153_04be0177-7088-a974-6df3-1c940d6e6bc6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10/刚_gāng.mp3", "刚才 刚强 刚直 刚刚 刚劲 刚正 刚巧 金刚,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。才，方才：刚才。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。正好，恰好：刚好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坚硬，坚定，坚强：跟“柔”相对：刚正，刚毅。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73841_共_20849.gif","6","上下","八","共","A total of","http://cdn.ococci.com/saodubi/dict/hanzi_fanyi_audio/A/A total of.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/共_gòng.mp3", "共同 共存 共有 共事 共勉 统共 共鸣 公共,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"共产党的简称：(孙中山)先生确定了联俄、联共、扶助农工的三大政策。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"共同具有和承受：几十年来，他们同甘苦，共患难。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"介词。表示所涉及的对象，相当于“同”、“跟”：我有兄弟姊妹，幼时共我玩耍，我们相处也很好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一同；一起：不是有两颗心跟你的心共鸣吗?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"相同的：人，有共性，也有自己的个性。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"总计；合计：杨志的故事共有三回书，一万五千多字。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǒng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/共_gǒng.mp3", "共手,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拱手，两手在胸前相合，表示恭敬：居其所而众星共之。——《论语·为政》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"环抱：居其所而众星共之。——《论语》。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/共_gōng.mp3", "共承 共勤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"供给；供应；供奉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“恭”，恭敬。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"环供职，奉职。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古国名，在今甘肃省泾川县北。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。春秋时有共华。见《左传．僖公十年》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"谥号。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古国名。在今河南省辉县，西周时为共伯封国，后为卫邑。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59771_汽_27773.gif","7","左右","氵","汽","Steam","http://cdn.ococci.com/dict_ali/2022-02-25/1645771825884262578_35736342-e40e-cda8-b523-ed16876d22b4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/76/汽_qì.mp3", "汽车 汽笛 汽水 汽油,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"固体或液体变成的气体：汽水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指水蒸气：汽船。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59084_决_20915.gif","6","左右","冫","决","Decide","http://cdn.ococci.com/dict_ali/2022-02-25/1645721462092094836_400305fe-6c19-ffaa-eb36-65d7d03316c9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jué", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/决_jué.mp3", "坚决 决定 决心 决计 决裂 决赛 判决,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"定；拿定主意：但我意早决，八月中仍当行，九月已在沪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"堤岸被水冲开口子：1189年，黄河在曹州小堤之北决溢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通过较量：红队誓与蓝队决一雌雄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。必然；一定：少爷和革命者的作品，也决不会一样。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"完毕：悠悠不决之学潮，至兹告一结束。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/1356_定_23450.gif","8","上下","宀","定","Set","http://cdn.ococci.com/dict_ali/2022-02-24/1645710303966260485_b754577f-f212-6884-9cb6-083a788653ba.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/34/定_dìng.mp3", "约定 决定 确定,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)决定，使确定。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)约定。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)已经确定的、不改变的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)必定，一定。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)规定的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"基本义：(形)平静、稳定。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/17313_已_24050.gif","3","独体","己","已","Already","http://cdn.ococci.com/dict_ali/2022-02-24/1645709722064969900_62934932-c095-36cb-9c85-ad6850a43a20.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/已_yǐ.mp3", "已经 已往 久已 而已 已然 早已 业已 已婚,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停止：不战则已，战则必胜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"已经：演出已开始半小时了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停止：在前进中，我不能自己写下上面的话。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93596_经_32463.gif","8","左右","纟","经","Sutra","http://cdn.ococci.com/dict_ali/2022-02-21/1645440821406138275_93a2b370-206d-2b2a-297b-5694db5ebd54.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/经_jìng.mp3", "经纱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"[方]∶织布之前，把纺好的纱或线密密地绷起来，来回梳整，使成为经纱或经线：经纱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"纺织，把纤维拧成纱：吾始经之而不可更也。——《韩非子》。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/经_jīng.mp3", "已经 曾经 经过 经济 经商 经营 经理 经纶 西经,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"正常，常常，常规：正经。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"织布的纵线叫“经”，横线叫“纬”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈表〉过去而且已完成：经历。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"治理，管理，营业：经商。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"禁受，承受，忍受：经受。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"具有典范性的：经典。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地理学上的经度：北京大约位于东经116.5度。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中医把人体气血运行的主干叫“经”：经脉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通过，路过：经手。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宗教中宣讲教义的书：佛经。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/67567_物_29289.gif","8","左右","牜","物","Thing","http://cdn.ococci.com/dict_ali/2022-02-25/1645769733171782658_807c13c2-81f2-35f8-8a52-3fb15e182af6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/物_wù.mp3", "宝物 财物 产物 动物 人物 生物 物质 物产 物价 实物,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"具体的或个别的物品：大概是物以希为贵罢。北京的白菜运往浙江，便用红头绳系住菜根，倒挂在水果店头，尊为\"胶菜\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指自己以外的人或跟自己相对的环境：他从小就会待人接物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"客观存在的一切事物：太阳使我们这里滋生了万物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27847_虎_34382.gif","8","半包围","虍","虎","Tiger","http://cdn.ococci.com/dict_ali/2022-02-25/1645766117620460242_d3682c1d-47e7-1a9b-6b3e-27b3776593ec.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/141/虎_hǔ.mp3", "老虎 壁虎 猛虎 虎口 虎穴 虎符 虎威,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"老虎。猛兽名。猫科，哺乳类，毛黄，有黑色条纹，性凶猛，喜夜间行动，能游泳，捕食大小动物，有时也伤人，皮毛可做褥垫，骨、血、内脏皆可入药：整个伊春地区的林子里只有几只东北虎了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻勇猛威武：小伙子做事干净利落，有一股子虎劲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同\"唬\"。吓唬：我胆小，你可别吓虎我。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"露出严厉或凶恶的表情：他虎起脸把我们骂了一顿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93352_熊_29066.gif","14","上下","灬","熊","Bear","http://cdn.ococci.com/dict_ali/2022-02-25/1645774860150565086_882bc8e5-ad8c-ab18-f5b6-0301b70d9aa5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xióng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/89/熊_xióng.mp3", "熊包 熊猫 熊掌 狗熊 黑熊 熊心豹胆 熊熊烈火 虎背熊腰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物。头大尾短，四肢短而粗，脚掌大，趾端有带钩的爪，能直立行走，也能爬树，以肉为主食。种类很多，有白熊、黑熊和棕熊。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94447_通_36890.gif","10","半包围","辶","通","Pass","http://cdn.ococci.com/dict_ali/2022-02-25/1645761458115704940_09ee7b63-d6a4-2a20-bc64-f3ed02a7bb20.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/通_tòng.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多用于贬义的言语行为。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于演奏某些乐器的动作。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/通_tōng.mp3", "通才 通风 通晓 通敌,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"设有阻碍，可以穿过，能够达到：通风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"男女不正当的性行为：通奸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"懂得，彻底明了：通晓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"传达：通令。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"往来交接：通敌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"普遍、全：通才。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/26482_注_27880.gif","8","左右","氵","注","Note","http://cdn.ococci.com/dict_ali/2022-02-24/1645698265303629460_8648efdd-5065-314c-0d2f-e31ba27eb500.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/77/注_zhù.mp3", "附注 夹注 批注 评注 小注 专注 注视 注册 注目,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"灌进去：注入。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赌博时所下金钱财物：下注。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"记载，登记：注册。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"解释词句所用的文字：注疏（注解和解释注解的文字的合称）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，多用于款项或交易：一注钱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（精神、力量）集中在一点：注视。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用文字来解释词名：注解。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/4343_意_24847.gif","13","上下","心","意","Meaning","http://cdn.ococci.com/dict_ali/2022-02-25/1645754236265557992_fc0a0109-f59c-dc9d-13f9-ced44631b64e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/意_yì.mp3", "注意 本意 意义 故意 大意 特意 同意 曲意逢迎 醉意,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"含义；意思：这篇文章没有什么新意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"料想：但这回却很有几点出于我的意外。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事理；情趣：这个人说话很有诗意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"心愿，愿望：一番好意。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73547_遍_36941.gif","12","半包围","辶","遍","All over","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"biàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/167/遍_biàn.mp3", "遍布 遍及 遍地 普遍,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"广泛；全面：一股慷慨悲歌的火辣辣的情感，涌遍了我的全身。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。同一动作过程做一次，相当于\"次\"、\"回\"：文章写好之后，自己最好多看几遍。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76179_百_30334.gif","6","上下","白","百","Hundred","http://cdn.ococci.com/dict_ali/2022-02-25/1645771608217381857_7f9a9a1d-4941-9974-e9ec-561f4d430363.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/101/百_bǎi.mp3", "百姓 百位 百科 一百 百年 百货 百合 百分 百般,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数目，十个十：二百个学生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示很多：百战百胜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/12150_舌_33292.gif","6","上下","舌","舌","Tongue","http://cdn.ococci.com/dict_ali/2022-02-25/1645745415978950276_e61c0bf8-ad0e-634e-c219-67de1c9aaafa.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shé", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/131/舌_shé.mp3", "舌战 舌锋 舌头 舌叶 舌尖 舌面 口舌,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人类和动物的一种器官，主要作用是辨别滋味、帮助咀嚼和发音：小明这几天舌头发炎，吃什么东西都没味道。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像舌的东西：我的帽舌都折断好几天了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/47471_鬼_39740.gif","9","独体","鬼","鬼","Ghosts","http://cdn.ococci.com/dict_ali/2022-02-24/1645681589491650215_f32c09fc-fa5c-fcba-4240-b742009c6098.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/194/鬼_guǐ.mp3", "搞鬼 见鬼 闹鬼 打鬼 魔鬼 鬼脸 鬼点子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人死后的灵魂：上帝、神、鬼在客观世界中无论过去、现在、将来永远都是不存在的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有某种不良嗜好或行为的人：他简直成了酒鬼。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"机灵，敏慧：你们这些鬼娃娃，昨天偷了我的豆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"见不得人的计谋：不要当面说得好听，背后又在搞鬼。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恶劣，糟糕（限做定语）：这个鬼地方，一下雨就成了烂泥坑。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98440_脸_33080.gif","11","左右","月","脸","Face","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647480757116.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/128/脸_liǎn.mp3", "脸面 脸蛋 脸盆 头脸 嘴脸 脸谱 丢脸 笑脸 门脸,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"头部前面(从额到下巴部分)：她们看到的是王老师一张憔悴的脸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"面子，颜面：也许她实在无脸见人，才走上了绝路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"面部的表情：她经常把脸苦着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"东西房全是敞脸的，是用来停车的地方。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75083_准_20934.gif","10","左右","冫","准","Quasi","http://cdn.ococci.com/dict_ali/2022-02-02/1643809177454021081_4a86e37b-137a-e105-3b84-ef039d417cc6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhǔn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/准_zhǔn.mp3", "准则 准星 准时 准许 准备 准确 准绳 水准 标准 核准 获准 瞄准 照准,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"程度不完全够但可以看作一些的：台儿庄胜利之后，有些人主张徐州战役是\"准决战\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"标准：这个名字集中地反映了当时人们的道德准则。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"准确：他刚装了全口假牙，音也发不准了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一定：蜜蜂准是误以为你要伤害它才蜇你。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/96973_第_31532.gif","11","上下","竹","第","No","http://cdn.ococci.com/dict_ali/2022-03-21/5423671000000088_1647856292675.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/113/第_dì.mp3", "第一 门第 及第 不第 次第 宅第 府第 科第 登第 落第 书香门第,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"封建社会官僚和贵族的大宅子：这是清朝陕甘总督杨遇春的府第，距今已有近200年历史了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"次序：他考了全班第一。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94694_猴_29492.gif","12","左右","犭","猴","Monkey","http://cdn.ococci.com/dict_ali/2022-02-25/1645772597263493700_c24146f5-5621-27f8-8fc4-583e9f8c37a5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hóu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/93/猴_hóu.mp3", "猴子 猕猴  猴戏 耍猴,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言。乖巧；机灵：你看，这孩子多猴!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"猴子；猴儿：山中无老虎，猴子称霸王。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/20666_结_32467.gif","9","左右","纟","结","Knot","http://cdn.ococci.com/dict_ali/2022-02-25/1645745016677652919_fda4ab59-1314-969f-5ff1-1cf72d37bb92.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/结_jié.mp3", "团结 结果 结构 结婚 结论 打结 结束,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"聚，凝聚：结冰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结束；了结：他结了账后离开了宾馆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在绳索、线、带等条状物上打疙瘩：他把两条衣袖在胸前结成一个结子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"系，绾：她头上扎了一个漂亮的蝴蝶结。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"缔结；组合：俄罗斯、乌克兰等十一个国家结为\"独联体\"。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/结_jiē.mp3", "结巴 结果 结实,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物长出果实或种子：玉米地里的玉米结得又大又多。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54087_掰_25520.gif","12","左中右","手","掰","Break","http://cdn.ococci.com/dict_ali/2022-02-25/1645763100077798894_4e182c55-1c4e-4e85-0745-8e20294ef5fd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bāi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/54/掰_bāi.mp3", "掰开 掰断 瞎掰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用手把东西分开或折断：小猴子掰了一个玉米棒子，扛着往前走。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93184_扛_25179.gif","6","左右","扌","扛","Carry","http://cdn.ococci.com/dict_ali/2022-02-25/1645765198976238843_b60309fe-ac33-8ddc-a539-0d9cac916fb2.mp3");
