INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言，抬东西。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用两手举（重物）：力能扛鼎。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"káng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扛_káng.mp3", "扛枪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用肩膀承担。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/19666_满_28385.gif","13","左右","氵","满","Full","http://cdn.ococci.com/dict_ali/2022-02-25/1645774533778685804_8392f9fc-edb1-cd7f-4bfe-4ed6aa4c3f92.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/82/满_mǎn.mp3", "饱满 满足 充满 丰满 圆满 满员 满座,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"到了一定的限度：满员。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"十分，全：满世界。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使满，斟酒：满上一杯酒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"全部充实；容量达到极点：满足。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"骄傲，不虚心：自满。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"少数民族名，满族。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/80429_扔_25172.gif","5","左右","扌","扔","Throw","http://cdn.ococci.com/dict_ali/2022-02-25/1645766722501506586_4379c5e5-9814-eb64-3e08-585d82e68739.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"rēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扔_rēng.mp3", "扔掉 扔球 扔了 扔石块儿 乱扔,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抛，投掷：扔球。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"强牵引：攘臂而扔之。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丢弃，舍弃：扔弃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“仍”，仍然。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摧。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46521_摘_25688.gif","14","左右","扌","摘","Pick","http://cdn.ococci.com/dict_ali/2022-02-25/1645764004479702405_0f8c7d4b-c563-3934-c6a7-2b126eb497b5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhāi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/55/摘_zhāi.mp3", "摘记 摘要 摘录 摘引 摘编 摘登 摘除 摘译 文摘 采摘,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"借：母亲突然生病，我从朋友那里摘了钱才将住院费缴清。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"选取：我还从他那篇文章里摘一些精彩句子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"采取；用手拿下：那时候，我们已到果园里摘梨，摘苹果，又新鲜又便宜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/25447_捧.gif","11","左右","扌","捧","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pěng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/捧_pěng.mp3", "捧场 捧腹 吹捧,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"双手托着：他用双手捧着孩子的脸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29346_瓜_29916.gif","5","独体","瓜","瓜","Melon","http://cdn.ococci.com/dict_ali/2022-02-21/1645412516683097123_f46a3aea-ec96-79bc-0746-e845b13c293f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/97/瓜_guā.mp3", "西瓜 瓜分 瓜葛 瓜蒂 冬瓜  瓜田李下 瓜熟蒂落 顺藤摸瓜,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像切瓜那样的分割：瓜分。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈喻〉亲友关系、社会关系或互相牵连的关系：瓜葛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"葫芦科植物。蔓生，叶掌状。果实可吃或供药用：苦瓜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39204_抱_25265.gif","8","左右","扌","抱","Hug","http://cdn.ococci.com/dict_ali/2022-02-24/1645710630469867272_472fea15-dcd6-5bd4-4eb7-8451fb499503.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/52/抱_bào.mp3", "怀抱 抱养 抱歉 抱怨 抱病 抱恨 合抱 搂抱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用手臂围住：孩子们张开双臂投入宋奶奶的怀抱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(衣)大小合适：她买的这件衣服抱身儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"初次得到：听说老冯最近抱孙子了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结合在一起：只要我们抱成一团，就一定能战胜敌人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(身上)带有：人在自己的活动中又总是抱有某种愿望，追求某种目的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"禽鸟孵卵：我家的母鸡这几天正在抱窝。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39085_蹦_36454.gif","18","左右","足","蹦","Jump","http://cdn.ococci.com/dict_ali/2022-03-09/542367100000007a_1646823539549.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹦_bèng.mp3", "蹦高 蹦跳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跳；跳动。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34271_追_36861.gif","9","半包围","辶","追","Chase","http://cdn.ococci.com/dict_ali/2022-02-24/1645714439914818773_1922a936-64eb-8b8c-1201-ddd4c41e65b5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/166/追_zhuī.mp3", "追逐 追溯 追问,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赶，紧跟着：追逐。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竭力探求，寻求：追问。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"回溯过去，补做过去的事：追溯。");
