INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/43/弓_gōng.mp3", "弹弓 弓箭 弓形 拉弓 弓背 弓弦 弯弓 步弓 硬弓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"射箭或发弹丸的器械。多用坚韧的木条弯成弧形，在弧形的木条两端之间系着坚韧的弦，拉开弦后，猛然放手，借弦和弓背的弹力把箭或弹丸射出：一代天骄，成吉思汗，只识弯弓射大雕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弯曲：他弓着背走路，从来不抬头看人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状像弓一样的器具：这把二胡的弓早就该换了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/92529_甘_29976.gif","5","独体","甘","甘","Gan","http://cdn.ococci.com/dict_ali/2022-02-24/1645712262190214998_ed1d6e51-59a9-e715-1f98-0adff12d602b.mp3");
