INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"甜：苦闷之果是最难尝的；虽然嚼过之后有一点回甘，然而苦的成分太重了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"自愿；乐意：没有放下臭架子甘当小学生的精神，是不能做好的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48839_棉_26825.gif","12","左右","木","棉","Cotton","http://cdn.ococci.com/dict_ali/2022-02-24/1645692870762021312_6a3a0a26-af10-7789-b5d3-f294b1a6285c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mián", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/棉_mián.mp3", "棉袄 棉絮 棉毯 棉布 棉花 棉衣 棉被,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"草棉和木棉的统称，通常指草棉。一年生草生植物，果实如桃，种籽上密生的长纤维就是棉花，种籽可榨油：吐鲁番虽热，仍是个好地方，地宜植棉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指棉桃中的纤维：全棉衣服，穿着就是舒服透气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像棉花的絮状物：这件防寒服，夹层里絮的是人造棉。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36299_娘_23064.gif","10","","女","娘","Mother","http://cdn.ococci.com/dict_ali/2022-02-25/1645770035383727343_60e76e94-3738-dc0b-6a9b-c318f60540d3.mp3");
