INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称母亲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对长一辈或年长已婚妇女的尊称：大娘。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年轻妇女：新娘。");
