INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"统治；管理：孔子主张以德治民，反对苛政和任意刑杀。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"安定；太平：任何优秀的政治家都应以天下大治为己任。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"攻读：大学毕业生应该树立正确的治学态度。");
