INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸟类的一科，翅尖而长，尾巴分开似剪刀。益虫。候鸟，春天飞到北方，秋天飞到南方。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/90/燕_yān.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"河北省境内的山脉：燕山。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"周朝国名，在今河北北部和辽宁南部。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/44453_别_21035.gif","7","左右","刂","别","Don't","http://cdnmu.gurobot.cn/saodubi/dict/audio/Don%27t.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10/别_bié.mp3", "别称 别管 别号 别名 性别 区别 离别 特别,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"分离；离开：可惜我没上完初小，就和蔡老师分别了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"扭动；转变：他把头别转来望着门外。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"区分：我们经过揣摩就能对文章作出鉴别和评价。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"另：敌人又从别处派了一批汉奸来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用针把另一样东西附着或固定在纸、布等物体上：他自豪地把校徽别在胸前。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"类别：在我国，男女同工同酬，没有性别歧视。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用东西卡住：请把门别上，好吗？");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"biè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10/别_biè.mp3", "别扭 别气 别别扭扭,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"执拗；不顺从：你尽跟我闹别扭，你到底想干什么？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抑制；堵住：为参加农业合作社的事，这几天来，他心里别得慌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"藏：别看你一天病病歪歪的，我明白你的小心眼别着什么！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指说话拗口：他别着一口很吃力的北京话。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/77352_干_24178.gif","3","独体","干","干","Dry","http://cdn.ococci.com/dict_ali/2022-02-25/1645743543675708110_86ea53d4-0e43-249a-07b6-640b30554d33.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/干_gàn.mp3", "干部 干活 树干 干劲 才干 实干 躯干 精干 枝干,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从事：那时候都认为干艺术是没有前途的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"做：不仅归有光，连他的老师也都这么干。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有能力；会办事：我想他一定是一个精明干练、久经战斗的人物。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/干_gān.mp3", "干扰 干系 若干 干燥 干脆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"盾牌：执干，干戈（泛指兵器）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清洁，简练，一点不剩：干净卫生，干净利落，消灭干净。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"冒犯，冲犯：干法官。〈引〉冲：哭声直上干云霄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"强行过问，硬管：干涉，干预。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"牵连，涉及：干连，不相干。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"求取，追求：干求。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"岸，水边：湖干，江干。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"妨碍，扰乱：莫干扰她，电视图象受到了干扰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"[天干]“甲乙丙丁戊己庚辛壬癸”等十个字，也作编排次序用。⑾[干支]天干和地支（子丑寅卯辰巳午未申酉戌亥）的合称，历法上把这两组循环相配，可成甲子、乙丑、丙寅......六十组，以表示年、月、日、时，周而复始，循环使用。⑿无水份或少水份的，跟“湿”相对：干燥，干谷子，干麦草秆。⒀水份少的食品：饼干儿，豆腐干。⒁尽净，枯竭，空虚：干杯，干涸，外强中干。⒂徒劳，白白地：干坐，干等这么久，不要干着急。⒃拜认的亲属关系：干爸爸，干女。⒄待慢，不理睬：真没想到，他会干起我们。⒅忿恨话，使对方难堪：他干了我一顿。⒆[干将]〈古〉剑名。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"爽快，直率：她做事干脆得很。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30972_然_28982.gif","12","上下","灬","然","Ran","http://cdn.ococci.com/dict_ali/2022-02-24/1645699159620898562_bdfcbfd0-73a3-eff2-64f8-34172948abed.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"rán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/88/然_rán.mp3", "然而 必然 黯然 盎然 傲然 诚然 枉然 自然 然则,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"是，对：以为然。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（表示转折）但是，不过，可是：然而。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（表示进一层）那么，这样就：然则。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"如此，这样：当然。");
