INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33445_奇_22855.gif","8","上下","大","奇","Qi","http://cdn.ococci.com/dict_ali/2022-02-25/1645768612469224184_df6e08b2-4aa3-e203-351d-0079528d45b7.mp3");
