INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"罕见的；特殊的：这道风景线，堪称天下奇观。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"出人意料；难以预测：他重新设计，以期出奇制胜，有所创造。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"惊异：他惊奇地问：\"真有这样的事吗?\"");
