INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"内脏里的东西从口里涌出：呕吐。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把吞没的东西退出来：吐还不义之财。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吐_tǔ.mp3", "吐翠 吐露 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"说出：吐话。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使东西从口里出来：吐痰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放出，露出：高粱吐穗。吐故纳新。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/45719_啦_21862.gif","11","左中右","口","啦","Come on","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/18/啦_lā.mp3", "哗啦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词。\"了(lｅ)\"和\"啊\"(a)\"的合音，兼有\"了\"、\"啊\"的作用。表示事情已经完成，有惊讶、感叹的语气：这怎么办?饭也吃不成啦!");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lɑ", "https://ota.aidoor.net/scan_pen/content/audio/d4befae0-a926-11ec-bb89-c147036f73d1.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，作用大致和“了”相同：你真的来啦？他早走啦。大楼终于建成啦！");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22651_咕_21653.gif","8","左右","口","咕","Goo","http://cdn.ococci.com/dict_ali/2022-02-25/1645765887929053628_e74af0dd-c710-f738-c302-6d8ea9b7aa73.mp3");
