INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/11796_熟_29087.gif","15","上下","灬","熟","Ripe","http://cdn.ococci.com/dict_ali/2022-02-25/1645767833143331636_995a3ce4-761c-1f69-1799-fe3bdda9e42c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/89/熟_shú.mp3", "熟悉 熟练 熟识 熟手 纯熟 熟睡 熟人,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"周详，程度深：深思熟虑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经反复实践，有经验达到精通：熟练。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"习惯，常见，知道得清楚：熟路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"炼制或加工过的：熟铁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"烹饪食物达到可吃程度：熟食。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物的果实、种子长成：成熟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指庄稼可收割或有收成：一年三熟。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63467_掉_25481.gif","11","左右","扌","掉","Drop","http://cdn.ococci.com/dict_ali/2022-02-24/1645718079665220878_e3020048-8bca-f6f4-4054-44034234b155.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/53/掉_diào.mp3", "掉队 掉色 改掉 掉头 掉换 掉包 掉落 掉转 丢掉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落下：眼镜掉在地上碎了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"回转：她把衣服掉过来看了又看，最后才决定买下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在动词后表示动作的完成：他拔掉针头就往外走。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落在后面：在昨天举行的五公里越野赛中，没有一个战士掉队。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"降低；减损：掉膘。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"更换：上级给我掉换了工作，这样我上下班方便了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摆动：一听这话，他一跺脚，掉头就走。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"遗漏：你把书包丢掉了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/67538_吓_21523.gif","6","左右","口","吓","Scared","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647481126935.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xià", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吓_xià.mp3", "吓人 吓唬 惊吓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"惊吓；使害怕：你别吓着他。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吓_hè.mp3", "恫吓 恐吓 威吓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恐吓；恫吓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叹词。表示不满：吓，怎么能这样呢？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52200_羊_32650.gif","6","独体","羊","羊","Sheep","http://cdn.ococci.com/dict_ali/2022-02-25/1645771465612428314_13810d06-216f-b2ef-9564-be143b3631c5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/124/羊_yáng.mp3", "羊角 羊齿 羊倌 羊羔 羊毫 羊膜 山羊 绵羊 羚羊 羊肠小道 歧路亡羊 顺手牵羊,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物。家畜的一种，头上一般有一对角，种类有山羊、羚羊、绵羊等：老山羊在地里啃白菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/11263_鹿_40575.gif","11","半包围","鹿","鹿","Deer","http://cdn.ococci.com/dict_ali/2022-02-25/1645768973432362552_5916df32-3a21-6dde-c7ad-77f035a40ea8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/202/鹿_lù.mp3", "鹿皮 鹿角 鹿茸 野鹿 梅花鹿 鹿死谁手,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物反刍类的一种。四肢细长，尾短，一般雄性头上有角，个别种类雌性头上也有角。毛多呈褐色，也有的现花斑或条纹。听觉及嗅觉都很灵敏。我国所产种类很多。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"粗，粗劣：鹿床。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
