INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"避开，躲避：逃难。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33968_命_21629.gif","8","上下","口","命","Life","http://cdn.ococci.com/dict_ali/2022-02-25/1645765873306223884_a594213d-ba7d-a258-8577-e60ea158fcf4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/命_mìng.mp3", "生命 性命 命运 革命 命令 命题 奉命 待命,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"取名：取名。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生命，生物的生活能力：救命。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"射中，打中目标：命中。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指派，使用：命他去办。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迷信者所谓\"\"人生来就注定的贫富、贵贱、生死\"\"等：算命骗人钱财。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"上级对下级的指令：命令。");
