INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/157/象_xiàng.mp3", "象牙 象形 象征 象棋 象舞 大象 万象 气象 对象 现象 印象 景象 形象 抽象 迹象 假象 想象 意象,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"仿效；摹拟：象形。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"陆地上现存最大的哺乳动物：大象。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状；样子：万象更新。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24340_野_37326.gif","11","左右","里","野","Wild","http://cdn.ococci.com/dict_ali/2022-02-24/1645704531690942997_a49a1ed4-f03f-be88-9c4d-e45604041399.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yě", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/野_yě.mp3", "野生 野炊 野蛮 野心 野性 野战 山野 原野 田野 视野 旷野 郊野,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不讲理；没礼貌：你太野蛮了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指民间，不当政的：执政党由于经济问题，受到了在野党的抨击。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不受约束：假里，孩子们的心都玩野了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不是由人喂养或栽植的：雪天，野兽在深山里没有食物吃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"郊外：牧羊人经常来往于荒野山间。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"界限；范围：飞机已经消失在我们的视野之外。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/81172_拦_25318.gif","8","左右","扌","拦","Stop","http://cdn.ococci.com/dict_ali/2022-02-25/1645753368506550001_3b6afb95-1b29-a5a4-c921-3684153eb10c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/52/拦_lán.mp3", "拦截 拦路 拦挡 拦路虎 阻拦 遮拦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"阻挡；不让通过：五个彪形大汉拦住了他的去路。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13389_领_39046.gif","11","左右","页","领","Collar","http://cdn.ococci.com/dict_ali/2022-02-22/1645538898258544952_3b2a4dce-7c72-d0f5-b849-802e86eb44e9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lǐng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/187/领_lǐng.mp3", "领导 领唱 带领 领教 领头 领读 领会,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：他骑着一匹火红的烈马，穿一领酱紫色的藏袍。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"纲要；要点：要领。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衣服上围绕脖子的部分：衣领子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"带，引，统率：领队。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接受，取得：领教。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"占有，管辖：占领。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"了解，懂得，欣赏：领会。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"颈项；脖子：他们每当酒酣耳热时，都会禁不住引领而歌。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/81768_壁_22721.gif","16","上下","土","壁","Wall","http://cdn.ococci.com/dict_ali/2022-02-25/1645765437487609587_cda6528d-06bc-8682-2b40-3bc5ee30b1ef.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/27/壁_bì.mp3", "壁柜 碰壁 壁炉 壁画 隔壁 壁虎 戈壁 峭壁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像墙那样直立的山崖：前面又有一段路在峭壁上，马是上不去的了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"墙：看着旧居的断垣残壁，他落泪了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"根毛的细胞壁很薄，细胞质很少，液泡很大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"营垒：早已森严壁垒，更加众志成城。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/82366_墙_22681.gif","14","左右","土","墙","The wall","http://cdnmu.gurobot.cn/saodubi/dict/audio/The_wall.mp3");
