INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用砖、石或土等筑成的屏障或障壁：房屋靠街的墙上有个二尺来宽的小窗户。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13928_蚊_34442.gif","10","左右","虫","蚊","Mosquito","http://cdn.ococci.com/dict_ali/2022-02-23/1645605671145568621_377c5f62-cf86-3c4d-b931-ab2300e402d8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wén", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚊_wén.mp3", "蚊虫 蚊香 蚊蝇 蚊帐 蚊子 灭蚊 驱蚊,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚊子。蚊科，种类很多，雌虫吸血，能传播疾病，雄蚊吸食花果液汁。幼虫(孑孓)和蛹都生活在水中：上海天热，夜又多蚊，不能做事。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27403_咬_21676.gif","9","左右","口","咬","Bite","http://cdn.ococci.com/dict_ali/2022-02-23/1645619976979930626_f633a777-f882-f471-e7ff-5e00e1e8db24.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/咬_yǎo.mp3", "咬牙 咬字 咬和 反咬 咬紧牙关 咬文嚼字 咬牙切齿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"狗叫：刚一进村，就听见一阵鸡叫狗咬声。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用上下牙齿夹住。一条蛇咬住了小壁虎的尾巴。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"追赶进逼：双方的比分一直咬得很紧。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"受审问时牵扯无关的人：他在受审时，为减轻自己的罪行，反咬别人一口。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"读字音：他在说话时，喜欢咬文嚼字。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99932_断_26029.gif","11","左右","斤","断","Break","http://cdn.ococci.com/dict_ali/2022-02-25/1645763100077798894_4e182c55-1c4e-4e85-0745-8e20294ef5fd.mp3");
