INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"㈠(动)");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"截断。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"断绝，隔绝。㈡");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"判断。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"戒除(烟酒)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"绝对、一定(多用于否定式)，表示坚决排除。");
