INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)掉转。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(～子、～儿)(量)用于人的分组；伙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)分出一部分发给；调配。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)手脚或棍棒等横着用力，使东西移动。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24882_甩_29993.gif","5","独体","用","甩","Dump","http://cdn.ococci.com/dict_ali/2022-02-24/1645706979654086861_3e7e2dde-4428-e33e-8e6a-96cf8b01de32.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shuǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/98/甩_shuǎi.mp3", "甩手 甩开 甩卖,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抡，扔。抛开，抛去。虫类下卵。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/74663_赶_36214.gif","10","半包围","走","赶","In a hurry","http://cdn.ococci.com/saodubi/dict/hanzi_fanyi_audio/I/In a hurry.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/159/赶_gǎn.mp3", "赶上 赶巧 赶忙 赶走 赶快 赶路 赶集 追赶 驱赶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"加快行动，不误时间：我必须这样做，以便母亲和姐姐多赶出点活计来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"去：赶集去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"追：经过半年多的努力，他终于赶上了全班的进度。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"遇到（某种情况）：我到他家里时，正赶上是他的生日。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"介词。等到（某个时候）：赶明天再来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"驱使，驾驭，驱逐：到敌人后方去，把强盗赶出去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赶快行动：你赶紧的，都要迟到了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52335_房_25151.gif","8","半包围","户","房","Room","http://cdn.ococci.com/dict_ali/2022-02-25/1645772718291407574_101c328a-e5a8-c4b0-cef4-987ff43d933d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/房_fáng.mp3", "房子 房屋  房檐 房产 房东 房间 草房 房契 房租,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"星名。二十八宿之一。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"房子：楼房。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"作用、结构像房子的：树上有一个巨大的蜂房。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从事某种职业的人：我立起身来问茶房什么事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧指家族的一支：觉新在这一房里是长子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"房间：这是间十分考究的书房。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于配偶：你早给他说一房亲事嘛！");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/15322_傻_20667.gif","13","左右","亻","傻","Silly","http://cdn.ococci.com/dict_ali/2022-02-24/1645717514928706097_0b7030fc-df08-f4c9-a09f-d0bb1e002040.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/6/傻_shǎ.mp3", "傻瓜 傻气 傻笑 傻劲儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"老实，死心眼而不知变通。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"愚蠢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"呆，愣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/12005_转_36716.gif","8","左右","车","转","Turn","http://cdn.ococci.com/dict_ali/2022-02-25/1645771595034468447_60a7a479-69df-89b8-5083-b22a4a0777f7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/转_zhuàn.mp3", "转向 转头 转速 转圈,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"围绕着一个中心运动：越陷越深绕着太阳转。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旋转：车轮飞转。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，旋转一圈为一转：绕了几十转。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，古代勋位每升一级称“一转”：“策勋十二转，赏赐百千强。”");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使旋转：转动地球仪。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/转_zhuǎn.mp3", "转动 转头 转生 转让,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"改变形势、情况：转败为胜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迁徙；流亡：老弱转乎沟壑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不直接的，中间再经过别人或别的地方：转送。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"改换方向：转弯。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"改变位置：转移。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/转_zhuǎi.mp3", "转文,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"[转文]指说话或写文章时有意不用通俗易懂的词句，而使用文言文词语以显高雅。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10894_卫_21355.gif","3","独体","卩","卫","Wei","http://cdn.ococci.com/dict_ali/2022-02-24/1645705321666630871_b2980b43-dcaa-80c5-6e33-81db7802e53e.mp3");
