INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国明代驻兵的地点（后只用于地名）：威海卫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代称驴：“策双卫来迎”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"防护人员：警卫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国周代诸侯国名。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"保护，防护：保卫。");
