INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（刷俐）形容动作很敏捷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（刷白）色白而略微发青。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shuā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10/刷_shuā.mp3", "刷子 刷洗 刷新 冲刷 粉刷 洗刷 印刷,");
