INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象声词。风刮得树叶儿刷刷地响。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刷子(用毛、棕等制成的清洁用具)。最近生产了一种比较科学而适用的牙刷。");
