INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"涂：冬天，手上擦一些甘油，就不会裂口子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用布、手巾等揩拭，使物干净：他把桌子擦得干干净净。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两物相摩：战士们个个摩拳擦掌，士气很高。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"贴近；挨着：他们与我擦肩而过。");
