INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/53429_塘_22616.gif","13","左右","土","塘","Pond","http://cdn.ococci.com/dict_ali/2022-02-25/1645743517519446866_83c9bf07-96e0-47f0-51c0-c87aeb3bc76b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"táng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/26/塘_táng.mp3", "池塘 塘坝 塘堰 泥塘 苇塘 澡塘,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水池：几只鸭子正在塘里戏水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"堤岸；堤防：吴越在钱塘江边修筑了海塘，使成千上万的农田免于水患。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浴池：学校又修建了一所大澡塘。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87242_脑_33041.gif","10","左右","月","脑","Brain","http://cdn.ococci.com/dict_ali/2022-02-24/1645693029778256931_2aee9924-3143-872f-9b13-d521e9e36698.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/128/脑_nǎo.mp3", "脑力 脑髓 脑海 脑袋 大脑 首脑 头脑 电脑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状或颜色像脑的：豆腐脑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通称“脑髓”。人和高等动物神经系统的主要部分，在颅腔内，又分为脑干（延脑、脑桥和中脑）、小脑、间脑和大脑。主管全身感觉和运动。人脑又是思想、记忆等活动的器官：脑筋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从物体中提炼出的精华：樟脑具有杀虫防潮的功效。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"头部：每当说到高兴处，他总是摇头晃脑，得意忘形。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/19326_袋_34955.gif","11","上下","衣","袋","Bag","http://cdn.ococci.com/dict_ali/2022-02-25/1645772179340733496_a6a41cb3-8494-fe01-83cb-f062976ceee0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/147/袋_dài.mp3", "麻袋 袋子 皮袋 脑袋 口袋 衣袋 烟袋 邮袋 冰袋 被袋 袋装,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用布、皮等做成的能装东西的器具：这个本子平时装在衣袋里，有空便掏出来看看。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于盛物的口袋之类：他一口气把两袋大米扛上了五楼。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63495_灰_28784.gif","6","半包围","火","灰","Ash","http://cdn.ococci.com/dict_ali/2022-02-24/1645715353959571562_7db4c183-91d2-48b5-92f1-e2e93c6be24a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/86/灰_huī.mp3", "灰色 灰暗 灰尘 灰白 石灰 烟灰 灰烬 炉灰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物质燃烧后剩下的粉末：草灰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指石灰：刷灰浆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"尘土：灰尘。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消沉，失望：心灰意懒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"黑白之间的颜色：灰色。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63030_哇_21703.gif","9","左右","口","哇","Whoa","http://cdn.ococci.com/dict_ali/2022-02-22/1645539359839607142_7dd94047-8433-ee43-b7b7-efaa8b10f51d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哇_wā.mp3", "哇塞 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指靡靡之音。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象声词，形容哭声、呕吐声。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wɑ", "https://ota.aidoor.net/scan_pen/content/audio/d4281210-a926-11ec-bb89-c147036f73d1.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，大致相当于“啊”（前面紧挨着的音一定是ｕ、ａｏ、ｏｕ等结尾的）多好哇！快走哇！");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/49003_捕_25429.gif","10","左右","扌","捕","Catch","http://cdn.ococci.com/dict_ali/2022-02-25/1645774180297047975_05da7518-eef6-f702-01d4-70c446ee8128.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/53/捕_bǔ.mp3", "捕获 拘捕 拒捕 搜捕 巡捕 追捕 捕捉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"捉；逮：小时候，我们常到河里捕鱼捉虾。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/68174_迎_36814.gif","7","半包围","辶","迎","Ying","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yíng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/165/迎_yíng.mp3", "迎春 迎击 迎接 迎面 欢迎 迎风 迎头 迎合,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接：迎接。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"面对着，冲着：迎面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"揣度别人心意而投其所好：逢迎。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94329_阿_38463.gif","7","左右","阝","阿","Ah","http://cdn.ococci.com/dict_ali/2022-02-25/1645763241220300719_874643fe-dbc4-74d1-7c78-a3ffdc8f0709.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"à", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/阿_à.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"可，是否。用在问句中，加强语气。如：阿晓得(可晓得)？阿去(可去)？");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/阿_ǎ.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于表示各种感情(如惊讶)。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/阿_ā.mp3", "阿姐 阿妹 阿爸 阿妈 阿拉伯 阿飞 阿公,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在排行、小名或姓的前面，有亲昵的意味：阿宝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在某些亲属名称的前面：阿婆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"<方>前缀。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/阿_ē.mp3", "阿谀 阿附 阿胶 阿其所好,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"偏袒：阿好，阿私。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大的山陵，大的土山：阿丘，阿阜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"曲隅，角落：若有人兮山之阿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地名：即今山东省东阿县");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"曲从；迎合：阿谀奉承。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57208_姨_23016.gif","9","左右","女","姨","Aunt","http://cdn.ococci.com/dict_ali/2022-02-25/1645761278217546635_bb460cfa-3bdc-c7a8-4ffc-9926d330d3d0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/30/姨_yí.mp3", "姨母 姨妈 姨丈 姨表 姨娘 二姨 大姨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称母亲的姊妹：姨母。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"妻的姊妹：大姨子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"妾：姨太太。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27391_宽_23485.gif","10","上下","宀","宽","Wide","http://cdn.ococci.com/dict_ali/2022-02-24/1645712980637422708_d83cd1e6-3e36-5e22-44f9-c0572b332e6b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/34/宽_kuān.mp3", "宽敞 宽慰 宽大 宽广 宽阔 宽厚 宽容,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"广阔；面积大：这绿色宽广的田野也显得狭隘了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放宽；放松：目前资本主义国家大多已放宽对选民选举资格的限制。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宽度：墙外是五十多米宽的护城河。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宽绰；富裕：他虽然这几年手头比过去宽多了，但仍然很节约。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不严厉；不苛求：对自己要求要严，但对别人应宽一些。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90876_龟_40863.gif","7","上下","刀","龟","Turtle","http://cdn.ococci.com/dict_ali/2022-02-25/1645758022407876415_4a7e7281-10c7-ae53-36ee-716ffafa33ed.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/205/龟_guī.mp3", "龟甲 龟缩 乌龟 龟年鹤寿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"爬行动物。身体长圆而扁形，背、腹坚硬，背部隆起，四肢短，趾上有蹼，头、尾、四肢均可收缩，大多数生活在水边，吃小动物或植物，生命力强。肉可食，壳可入药：这些文字是刻在龟壳和扁平的兽骨上的。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jūn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/205/龟_jūn.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“皲”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/205/龟_qiū.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"龟兹〕中国汉代西域国名，在今新疆维吾尔自治区库车县一带。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38944_顶_39030.gif","8","左右","页","顶","Top","http://cdn.ococci.com/dict_ali/2022-02-24/1645709236753591519_e80d18ed-2376-491f-8c54-32c39433e103.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dǐng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/187/顶_dǐng.mp3", "到顶 房顶 绝顶 顶点 顶撞 顶灯 顶替 头顶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"担当；支持；相当：你这点钱不顶事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数量单位：我送给他三顶帽子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用头和角撞击：他的父亲前几天被牛顶伤了，现在还住在医院里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代替：他今天代替小明打扫卫生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用东西支撑：风实在太大了，你要把门顶好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用头支承：他本身就是一个热血沸腾顶天立地的英雄好汉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"顶让或取得经营权等：他把店面顶出去了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(人体或物体上)最高或最上面的部分：几天之后，将辫子盘在顶上的人逐渐增加起来了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迎；冒：着领导们顶风冒雨地赶到医院，探望因工受伤的工人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用语言冲撞：他今天顶撞了他妈妈。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/53605_披_25259.gif","8","左右","扌","披","Pii","http://cdnmu.gurobot.cn/saodubi/dict/audio/Pii.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/52/披_pī.mp3", "披风 披挂 披甲 披露 披散 所向披靡 披星戴月,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"她披头散发地冲了进来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"裂开：我根竹竿披了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"覆盖或搭在肩背上：她乌黑色的浓密卷发从头上一直披到肩上。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/8883_鼓_40723.gif","13","左右","鼓","鼓","Drum","http://cdn.ococci.com/dict_ali/2022-02-24/1645714348859263848_73d981ba-9a59-4edf-275b-3cf68fa64afe.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/204/鼓_gǔ.mp3", "板鼓 打鼓 石鼓 花鼓 战鼓 鼓励 鼓动,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用风箱、扇：她正在用电风扇向蜂窝煤灶鼓风。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"发出声音：他们从我们楼前走过的时候，我们鼓掌欢迎他们。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种打击乐器。中空，多为圆筒形或扁形：人们站成两行，敲锣打鼓地迎接他的到来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状、声音、作用像鼓的东西：在这个会上，各种各样的意见撞击着他的耳鼓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/68842_晒_26194.gif","10","左右","日","晒","Sun","http://cdn.ococci.com/dict_ali/2022-02-25/1645773198663310445_7a706e60-dbc1-cc7a-62ab-9fc4b04cdf93.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/60/晒_shài.mp3", "晾晒 晒台 晒图 晒场 翻晒 晒太阳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把东西放在太阳光下照射，使之干燥：把谷子拿出去晒一晒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使人或物在阳光下吸取光和热：父亲在院子里晒太阳。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76162_极_26497.gif","7","左右","木","极","Pole","http://cdn.ococci.com/dict_ali/2022-02-25/1645753280884282147_21652388-13d4-f84a-ecb8-9d00cd0f77b6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/极_jí.mp3", "积极 极度 极端 北极 极限 磁极 两极 正极,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竭尽：听说他还对母亲极口夸奖我。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词，最：\"五卅惨案\"引起了全上海以至全国人民的极大愤慨。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地球的南北两端；磁体的两端等：地球绕着地轴自转，地轴的两端叫两极。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"达到顶点：希特勒攫取权力的手段真可谓登峰造极。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/40634_傍_20621.gif","12","左右","亻","傍","By","http://cdn.ococci.com/dict_ali/2022-02-25/1645767948344701630_538d1286-cc67-792f-858e-febedf0c5aa0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/6/傍_bàng.mp3", "傍依 傍晚 依傍 偎傍 傍花随柳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"临近(指时间)。");
