INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一点一点地下落的液体：天空中由密集的水滴形成的云层也会反射声波。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：当她的丈夫被敌人杀害的时候，她强忍着悲痛不掉一滴眼泪。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/66341_溪_28330.gif","13","左右","氵","溪","Creek","http://cdn.ococci.com/dict_ali/2022-02-04/1643967554882850387_e06d29f8-d78e-471d-ca93-e6ce73164f83.mp3");
