INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bèn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/奔_bèn.mp3", "投奔 奔命 逃奔 奔头儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"走向：他顺着山路直奔海边。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。接近；将近：一点都看不出，他是奔70的人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竭尽全力(从事某项活动)：你们所缺的原料，由我去奔。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/奔_bēn.mp3", "飞奔 奔腾 奔波 奔跑 奔驰 奔窜 奔泻,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"急驰；快跑：在非洲热带草原，常常可以看到羚羊在狂奔。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赶忙或赶急事：\"好好先生\"一遇到对己不利的事，便四处奔走，多方游说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"逃跑：在猎犬的追赶下，狐狸在树林中四处奔逃。");
