INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/77/洋_yáng.mp3", "洋气 海洋 留洋 洋溢 大洋 洋相 洋芋,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丰富；盛大：走进博物馆，展品琳琅满目，真可谓洋洋大观。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"最大的水域：广大的海洋被大陆分割成彼此相通的四个大洋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"现代化的：土洋结合。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"盛大；丰富：热情洋溢。");
