INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/冲_chòng.mp3", "冲着 冲床 冲劲儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凭，根据：冲你这么好学，一定能有成就。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对着，向着：冲着太阳。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种使金属板成形或在金属板上打孔的专用设备称“冲床”。");
