INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"向上钻：火焰冲出了房顶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"交通要道：冲要的马路和街道，忽然布满了荷枪实弹的武装岗哨。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"快速向前直闯：这次跑八百米时，他一直冲在最前面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用开水等浇：水开了，给客人冲杯茶。");
