INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟“细”相反。A.长条东西直径大的：这棵银杏树又粗又高。B.颗粒大的：学校的足球场是用粗沙铺的。C.声音低而大：他在窗外粗声粗气地叫我。D.疏忽不周密：领导说我不是技术不好，而是粗心大意没开好车。E.毛糙，不精致：方案粗定，实施过程中进一步完善。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鲁莽：他是个粗人，别跟他计较。");
