INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/帆_fān.mp3", "帆船 帆布 扬帆 风帆 扯帆 一帆风顺,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挂在船桅上接受风力推动船前进的布篷：桥洞高大，木船竟能扬帆通过。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"船只：水既可载着千帆航行，也可将它们葬于腹底。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64576_艘_33368.gif","15","左右","舟","艘","Ship","http://cdn.ococci.com/dict_ali/2022-02-25/1645765813201557384_ba0380a3-fcaa-2985-b919-bd8451229db9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sōu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/131/艘_sōu.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于船只：两艘航空母舰驶向太平洋。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90634_军_20891.gif","6","上下","冖","军","Jun","http://cdn.ococci.com/dict_ali/2022-02-24/1645714578269876335_6f2692a4-370c-9694-8b49-c270321f633a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jūn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/军_jūn.mp3", "军人 军队 红军 军旅 解放军 海军 空军,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军队的编制单位，是\"师\"的上一级：千村沦落悲三楚，四位\"英雄\"丧甘军。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"武装部队：我们有一个强大的空军和一个强大的海军。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48482_舰_33328.gif","10","左右","舟","舰","Ship","http://cdn.ococci.com/dict_ali/2022-02-25/1645765813201557384_ba0380a3-fcaa-2985-b919-bd8451229db9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/131/舰_jiàn.mp3", "舰队 舰艇 战舰 军舰 兵舰 炮舰 旗舰 海舰 列舰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大型军用船只：军校毕业后，他被分配到了一驱逐舰上服役。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/74537_稻_31291.gif","15","左右","禾","稻","Rice","http://cdn.ococci.com/dict_ali/2022-02-25/1645767008719640218_89c32f4c-8132-52e9-a08f-0d9fa5ddf8b7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/111/稻_dào.mp3", "水稻 稻田 稻子 稻谷 稻草 稻身 稻秧,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"禾的总称。一年生草本植物，叶子狭长，花白色或绿色。子实叫稻谷，碾制去壳后叫大米，为我国重要粮食作物之一。主要分水稻和陆稻两大类。通常指水稻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"这种植物的子实：南宋时，太湖流域的稻米、福建等地的水果都供应到临安。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/53539_园_22253.gif","7","全包围","囗","园","Garden","http://cdn.ococci.com/dict_ali/2022-02-25/1645767161134337582_e4351975-efa2-5fed-3075-74a812dbedb6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yuán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/园_yuán.mp3", "园林 园丁 园地 园艺 园圃 田园 花园 公园 动物园 家园 乐园 春色满园,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在一定范围内种植果木、花草、蔬菜的地方：我家的后面有一个很大的园子，相传叫作百草园。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"供人游览、娱乐的地方：公园。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52681_翠_32736.gif","14","上下","羽","翠","Cui","http://cdn.ococci.com/dict_ali/2022-02-23/1645608261529946609_660039e0-0c7b-8f30-60a0-3ab3c0c040b3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cuì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/125/翠_cuì.mp3", "翠竹 翠鸟 翠绿 翠菊 翠微 翠玉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"翡翠。一种宝石：缅甸的翡翠非常有名。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(较鲜的)绿色：这里的翠竹青山，让人留连忘返。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22486_队_38431.gif","4","左右","阝","队","Team","http://cdn.ococci.com/dict_ali/2022-02-24/1645709988578227102_7faa60f2-3319-d0b9-a91d-4bd70f63041a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"duì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/181/队_duì.mp3", "队伍 队长 队列 队员 队形 乐队 部队 掉队 归队,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指中国少年先锋队：队员们打着队旗行进在山路上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"具有某种性质的集体：方志敏是中国工农红军北上抗日先遣队总司令。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"行列：讲究社会公德，排队上车，不要拥挤。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。一队人敲锣打鼓地迎接县上来的科技扶贫组。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34746_铜_38108.gif","11","左右","钅","铜","Copper","http://cdn.ococci.com/dict_ali/2022-02-25/1645746667795834497_6a867130-3ee4-34fc-a081-8615baf36b44.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/铜_tóng.mp3", "铜匠 铜板 铜钱 铜锈 铜牌 铜筋铁骨 铜墙铁壁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"化学元素。符号Cu，原子序29。淡紫红，延展性、导电性、导热性都很强，是工业的重要的原料，用途极为广泛：古时铜很珍贵，没有用于农业生产。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/2792_号_21495.gif","5","上下","口","号","Number","http://cdn.ococci.com/dict_ali/2022-02-25/1645766672421458440_73d5e3b0-45c1-39f0-78e8-adaa18f7256f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/号_hào.mp3", "号令 人号 军号 号称 号兵 号召 号手 逗号 号脉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"名称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"扬言，宣称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排定的次序或等级。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"记上标志。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，用于人数。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"命令。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"标志。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指人除有名、字之外，另起的别称。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/28422_梧_26791.gif","11","左右","木","梧","Wu","http://cdn.ococci.com/dict_ali/2022-02-25/1645767540997153954_f024770d-8311-5cc3-23d9-3cfb5d49eb76.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/梧_wú.mp3", "梧桐,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～桐〕落叶乔木。木质轻而坚韧，可制乐器和各种器具，种子可食，亦可榨油。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52974_桐_26704.gif","10","左右","木","桐","Tong","http://cdn.ococci.com/dict_ali/2022-02-25/1645756009097871158_0a4512fc-6893-94cf-7ce2-7908f869d460.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/桐_tóng.mp3", "梧桐 桐城 桐油,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔泡（pāo）～〕落叶乔木，叶大，开白色或紫色花，木材可做琴、船、箱等物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～桐〕落叶乔木。木质轻而坚韧，可制乐器和各种器具，种子可食，亦可榨油。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/97970_掌_25484.gif","12","上下","手","掌","Palm","http://cdn.ococci.com/dict_ali/2022-02-24/1645715880796423085_ddb34c05-87b1-d5d2-5ddd-5021170f17fa.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/53/掌_zhǎng.mp3", "掌声 巴掌 手掌 鼓掌 掌握 掌管,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鞋底或牲口蹄子底下的东西：鞋掌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用巴掌打：掌嘴。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔掌故〕关于历史人物、典章制度等的故事或传说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把握，主持，主管：掌管。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"手心，脚心：掌心。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/12967_枫_26539.gif","8","左右","木","枫","Maple","http://cdn.ococci.com/dict_ali/2022-02-21/1645449345614803090_2be00fd8-61dc-e667-6dac-cd177e61000e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/枫_fēng.mp3", "枫树 枫叶 枫林 丹枫 霜枫 秋枫 江枫,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落叶乔木，春季开花，叶互生，通常三裂，边缘有锯齿，秋季变成红色，树脂可入药，亦称“枫香树”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/51350_松_26494.gif","8","左右","木","松","Loose","http://cdn.ococci.com/dict_ali/2022-02-25/1645744631392062773_b42ad359-950b-abcf-eb3e-281d932748b6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/松_sōng.mp3", "放松 宽松 轻松 疏松 松口 松动 松弛 松懈,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稀散，跟“紧”相对：松脆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宽，不紧张：松弛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放开，弄散：松手。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用鱼、虾、瘦肉等做成的绒状或碎末状的食品：这肉松吃起来很可口。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"常绿乔木，种类很多，树皮多为鳞片状，叶针形，结球果，木材和树枝都可利用：大雪压青松，青松挺且直。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/67056_柏_26575.gif","9","左右","木","柏","Bo","http://cdn.ococci.com/dict_ali/2022-02-25/1645771994850041883_c6583d8b-bdc0-dea9-8718-12e5fa2c1b36.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/柏_bǎi.mp3", "柏油 翠柏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"常绿乔木，叶鳞片状，结球果，有“扁柏”、“侧柏”、“圆柏”、“罗汉柏”等多种。木质坚硬，纹理致密。可供建筑及制造器物之用。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/柏_bó.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"柏林〕德国的首都。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bò", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/柏_bò.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“檗”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/58978_装_35013.gif","12","上下","衣","装","Install","http://cdn.ococci.com/dict_ali/2022-02-22/1645541553159618311_a7f5c082-0b32-5665-717f-4d530965c4e3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/148/装_zhuāng.mp3", "安装 包装 便装 假装 化装 军装 装备 装订,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"安放：南宋所造的船，上面已装有指南针。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"将东西放进器物里：她顺手将衣服装进旅行袋里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"打扮；修饰：凡尔赛宫的内部装饰，以雕刻、巨幅油画及挂毯为主。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衣服(泛指物品)：军训时，学校还给每个同学发了一套新军装。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/47312_桦_26726.gif","10","左右","木","桦","Birch","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/桦_huà.mp3", "白桦 桦树,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"“白桦”、“黑桦”均是这一属。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"双子叶植物的一属，落叶乔木或灌木。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"树皮容易剥离，木材致密，可制器具。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73480_耐_32784.gif","9","左右","而","耐","Nai","http://cdn.ococci.com/dict_ali/2022-02-23/1645621445419557636_819d3db9-1a16-73f5-9d16-820fb3dc7a6e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/126/耐_nài.mp3", "耐烦 耐用 耐火材料 耐砖 耐心 耐劳 耐穿 忍耐 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“奈”，奈何。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"忍，受得住。");
