INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/杉_shān.mp3", "杉树 杉木,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"常绿乔木，树干很高很直。木材白色，质轻，有香味，可供建筑和制器具用。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36536_化_21270.gif","4","左右","亻","化","Melt","http://cdn.ococci.com/dict_ali/2022-02-25/1645763796341665061_1ecf836c-2daf-5d27-12f2-140982dc93d4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/12/化_huà.mp3", "化学 融化 化身 化石 化验 化纤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消化；消除：化痰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"放在名词或形容词后，表示转变成某种性质或状态：现在许多人在提倡民族化、科学化、大众化，这很好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指化学：他的数、理、化成绩比较好，适合学理工科。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"变化；使变化：化装。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"烧化：火化。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"感化；转变人心、风俗：教化。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（僧道）向人求布施：化斋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"熔化；融化：雪化了，春天就要来临。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/12/化_huā.mp3", "化子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"乞丐：化子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用掉、耗费，同“花”：化钱，化工夫。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87033_桂_26690.gif","10","左右","木","桂","Gui","http://cdn.ococci.com/dict_ali/2022-02-24/1645713226274499753_0db822aa-408f-3dec-a830-b74821cd5a98.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/桂_guì.mp3", "桂皮 金桂 桂花 桂冠 桂剧 桂圆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"木名。A. 常绿灌木或小乔木。秋天开花，香气极浓，其花可提取芳香油或作食品、糖果的香料：学校的东南角是一片桂树林。B. 肉桂树。常绿乔木。果实椭圆形，紫红色，树皮极香，并含有挥发油，发作香料，也可入药：在熬卤水的时候，可以加一些桂皮，使之香。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"广西壮族自治区的简称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
