INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gě", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/合_gě.mp3", "十合为升,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"容量单位，市制十合为一升。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hé", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/合_hé.mp3", "会合 凑合 场合 参合 集合 配合 合格 合同 合作,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闭；合拢。与\"开\"相对：今天是双喜临门，她老人家笑得合不拢嘴。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"全：除夕之夜，我们合家欢聚，共享天伦之乐。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"共同聚集到一起。跟\"分\"相对：后梁、后唐、后晋、后汉、后周五个朝代，合称五代。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计：今年我家养了五头肥猪，十只羊，你给我算算，合多少钱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"适合；合适：这套衣服还比较合身。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/61977_雁_38593.gif","12","半包围","隹","雁","Wild Goose","http://cdnmu.gurobot.cn/saodubi/dict/audio/Wild_Goose.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/183/雁_yàn.mp3", "雁行 大雁 鸿雁 雁过拔毛 离群之雁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"属鸟类，颈、翼较长，足、尾较短，羽毛呈紫褐色，善飞行和游泳：西风烈，长空雁叫霜晨月。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64191_丛_19995.gif","5","上下","一","丛","Cong","http://cdn.ococci.com/dict_ali/2022-02-23/1645621813522071126_b15453c7-3932-aee6-ea7c-9e47f4d8e97e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/丛_cóng.mp3", "花丛 草丛 树丛 丛生 丛林,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"聚集：废墟上已经杂草丛生了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"汇集在一起的人：他匆匆地走了，很快便消失在人丛中。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/9902_深_28145.gif","11","左右","氵","深","Deep","http://cdn.ococci.com/dict_ali/2022-02-25/1645718894323651235_0e5baf88-2683-0e2d-3d42-a681d34aee56.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/80/深_shēn.mp3", "深沉 深厚 深浅 深夜 深刻 加深 深信,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从水面到水底的距离或距离大，跟\"\"浅\"\"相对：水深千尺。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间久：夜深人静。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从面到底、从外到里、从上到下的距离或距离大：深度。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"颜色浓：深蓝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"很，极，厚，长远，程度高的：深信。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87181_猛_29467.gif","11","左右","犭","猛","Fierce","http://cdn.ococci.com/dict_ali/2022-02-25/1645771027410349337_33a893c4-749c-7fd6-67b2-7b67e23cd147.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"měng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/93/猛_měng.mp3", "凶猛 猛烈,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"猛烈；剧烈(形容在声势、力量、强度等方面大而急速)：它咆哮着，猛地向岸边袭击过来，冲进了岩石的罅隙里，又拨刺着岩石的壁垒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凶恶；凶暴：猛兽一般是单独的，而牛羊则喜结队而行。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"勇猛；威猛：真的猛士，敢于直面惨淡的人生，敢于正视淋漓的鲜血。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35027_灵_28789.gif","7","上下","火","灵","Ling","http://cdn.ococci.com/dict_ali/2022-02-25/1645771981864015211_8b8b7f8b-fbc8-ab5c-cc5a-4c584b9c0323.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"líng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/86/灵_líng.mp3", "机灵 灵敏 心灵 灵活 灵魂 灵巧 亡灵 失灵 飞灵 神灵 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有效的：这种办法对他是不灵的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"聪明；机敏：一双灵敏的眼睛不断地东瞧西望。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敏捷的：老奶奶毕竟上了年纪，手脚也不灵了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"神仙或关于神仙的：命运并没有什么神灵在主宰。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/86183_休_20241.gif","6","左右","亻","休","Hugh","http://cdn.ococci.com/dict_ali/2022-01-10/1641812195922874931_7acddcec-fda7-2053-1822-93f2dd42c445.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/2/休_xiū.mp3", "休息 休学 休假 休养 休克 退休,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停止：那时候，各割据政权之间混战不休。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"休养；歇息：部队训练结束后，又在这里整休了20天。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丈夫与妻子断绝夫妻关系：不是她要离婚，是咱们休她。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91319_季_23395.gif","8","上下","子","季","Season","http://cdn.ococci.com/dict_ali/2022-02-25/1645758519703081869_c2624764-1685-85c7-fb3f-36ef15e3c521.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/33/季_jì.mp3", "季节 季度 季风 四季 旺季 夏季,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"末：他对于明季的遗老很有同情，对于清初的文祸也颇不满。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一个时期：人们的求知欲被激发起来了，书市一开张便进入旺季。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"三个月为一季，一年分为春、夏、秋、冬四季：广东天气好，花又多，蜜蜂一年四季都不闲着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指一年四季中，每季的最后一月：时节是季秋，正是天高气爽的时候。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57444_蝴_34676.gif","15","左中右","虫","蝴","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/144/蝴_hú.mp3", "蝴蝶 蝴蝶花 蝴蝶结 蝴蝶装,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蝴蝶。昆虫名。翅膀阔大，颜色美丽，静止时四翅竖立在背部，腹部瘦长。喜在花草丛中飞行，吸食花蜜：蝴蝶在花丛中翩翩飞舞，活像一朵\"能飞的花\"。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/56672_蝶_34678.gif","15","左右","虫","蝶","Butterfly","http://cdn.ococci.com/dict_ali/2022-02-24/1645707649791545390_43d8978a-7e3a-997f-fb62-4bd0de030b8f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/144/蝶_dié.mp3", "蝶形 蝴蝶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蝴蝶。一种昆虫。会飞，背上有两对翅且阔大，不飞时四翅竖立在背部，腹部瘦长，喜欢飞行于草间、花丛中，吸花蜜。幼虫多对农作物有害，但有的幼虫吃蚜虫，是益虫：他又用颜料在雄蝶身上做了记号。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/92184_麦_40614.gif","7","独体","麦","麦","Mai","http://cdn.ococci.com/dict_ali/2022-02-25/1645756817894596236_10221e8b-2dd3-0fb3-edcc-59b9b9c51f67.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/202/麦_mài.mp3", "麦苗 麦秸 麦秆 麦禾 大麦 小麦 燕麦 荞麦 野麦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物名。乔本科，一年生或越年生草本，子实磨成面粉可供食用，也可用来制糖或酿酒，是我国重要的粮食作物，其种类甚多。我国广为种植的为小麦和大麦通称：原野上，绿的呢，是麦田，黄的呢，是油菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"电磁系单位制中磁能量的单位，即麦克斯韦的简称。如果磁场的磁感应强度为1高斯，那么垂直于磁力线方向的平面上每平方厘米中所通过的磁通量就等于1麦克斯韦。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75423_苗_33495.gif","8","上下","艹","苗","Miao","http://cdn.ococci.com/dict_ali/2022-02-24/1645704942303273184_3d6b3105-217d-b770-384a-92db0e976b3d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"miáo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/133/苗_miáo.mp3", "苗条 苗头 苗子 禾苗 幼苗 火苗 苗圃,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"没有吐穗的庄稼。泛指初生的植物：禾苗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人的身体细长柔美：苗条。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疫苗，能使机体产生免疫力的生物制剂：卡介苗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状像苗的：火苗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"少数民族名：苗族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"某些初生的饲养动物：鱼苗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物的原由、开端或早期显露的迹象：苗头。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/82348_桑_26705.gif","10","上下","木","桑","Sang","http://cdn.ococci.com/dict_ali/2022-02-24/1645698754999448273_5252eb66-6a91-6ae8-0475-d081879a226b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/桑_sāng.mp3", "桑梓 桑甚 桑蚕 沧桑 扶桑 饱经沧桑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落叶乔木。品种多，常培养为灌木状。树皮有浅裂，叶卵形，花单性，花呈黄绿色。叶可喂蚕，皮可造纸，叶、枝、果、皮、根均可入药：商朝种植的作物有黍、稷、麦、稻、桑、麻等。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/60325_肥_32933.gif","8","左右","月","肥","Fat","http://cdn.ococci.com/dict_ali/2022-02-25/1645770114579978475_9a513f37-379a-26c0-e24d-e80d7ba11f75.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"féi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/127/肥_féi.mp3", "肥沃 肥大 肥胖 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使肥沃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(名)肥料。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)肥沃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)含脂肪多(但通常不用来形容人)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由不正当的收入而富裕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)肥大(跟“瘦”相对)：棉袄的袖子太肥了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)胖；肥沃。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93116_农_20892.gif","6","独体","冖","农","Nong","http://cdn.ococci.com/dict_ali/2022-02-24/1645711340239829796_421fe78d-d54e-aca8-aa48-7cbdd3abfe3d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nóng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/农_nóng.mp3", "贫农 富农 农忙 务农 农民 农历 农活,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"种庄稼；跟种庄稼有关的：他立志回乡务农。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从事农业生产的人：棉农喜摘新棉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/70398_归_24402.gif","5","左右","彐","归","Return","http://cdn.ococci.com/dict_ali/2022-02-25/1645759603373202062_cdc18665-8cc2-d809-c6e2-b765435c005c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/43/归_guī.mp3", "荣归 当归 回归 终归 划归 归案 归队 归纳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"还(物)：物不是给他没收了吗，怎么又物归原主了？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"返；回：敌人可能从旧关和娘子关两地出发，截断我们的归路和去路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由（谁负责）：一切杂事都归这一组管。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在相同的动词之间，表示动作未引起相应的结果：说归说，但真正做起来他还是十分卖力的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"属于（谁所有）：这些东西归你。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/43/归_kuì.mp3", "归赈 归色,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"惭愧：归色(愧色)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“馈”，赠送：归示。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73838_戴_25140.gif","17","半包围","戈","戴","Dai","http://cdn.ococci.com/dict_ali/2022-02-24/1645703257530363441_3d47a387-bfef-0c93-a296-51062d0cc512.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/戴_dài.mp3", "拥戴 戴帽子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拥护；尊敬。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把东西放在头、面、胸、臂等处。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46393_谷_35895.gif","7","上下","谷","谷","Valley","http://cdn.ococci.com/dict_ali/2022-02-21/1645443307146360993_7c82569a-ef3a-5d65-2b23-1811216a388c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/谷_gǔ.mp3", "布谷 山谷 河谷 峡谷 稻谷 谷坊 悬谷 溪谷 落谷,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两山之间流水的通道或夹道：地球表面有陆地，有海洋，有高山，有深谷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"各类作物：农村呈现出五谷丰登的新气象。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/谷_yù.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于民族名，古代北方有“吐谷浑”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/80323_粒_31890.gif","11","左右","米","粒","Grain","http://cdn.ococci.com/dict_ali/2022-02-24/1645669454396035883_edf78c4b-09c3-1096-5b69-b314b826bd41.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/117/粒_lì.mp3", "米粒 谷粒 粒米狼戾,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小圆形或小碎块形的物体：满桌都是饭粒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：这里的每一粒黄土，浸透着祖辈们辛勤的汗水。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13443_虽_34429.gif","9","上下","虫","虽","Although","http://cdn.ococci.com/dict_ali/2022-02-25/1645773134207239585_35a201f4-4669-a1fb-7ee2-b601dc0f6ddd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"suī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/虽_suī.mp3", "虽然 虽说 虽则 虽死犹生 虽死犹荣,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。A.虽然：事情虽小，意义却很大。B.即使；纵然：为人民而死，虽死犹荣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/79024_辛_36763.gif","7","独体","辛","辛","Sin","http://cdn.ococci.com/dict_ali/2022-02-25/1645757431295465506_9606a0da-9624-6662-ec9e-fec5b9d0b0db.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xīn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/165/辛_xīn.mp3", "辛苦 辛劳 辛勤 辛酸 辛辣 艰辛 酸辛 含辛茹苦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"气味，带辣味：他走到坑道口，迎面扑来一股强烈的辛辣硝烟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"劳苦，艰难：每天他都非常辛苦。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"天干的第八位，用于作顺序第八的代称：辛亥革命。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悲伤：文章读起来使人真像看见了妈的泪眼和笑颜，听见了她那酸辛而热情的语言。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/60377_苦_33510.gif","8","上下","艹","苦","Bitter","http://cdn.ococci.com/dict_ali/2022-02-24/1645695834731039736_439c30b8-0e39-a3cc-2cab-62480e500817.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/133/苦_kǔ.mp3", "苦海 辛苦 苦瓜 苦胆 苦处 苦难,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像黄连或胆汁的味道：这菜太苦了，叫人怎么吃得下?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"痛苦；困苦：生活再苦，她也不愿让孩子辍学。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悲伤凄凉：张长海心中悲苦之极，但却说不出一句话来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有耐心地，尽力地：要掌握语文知识就得苦学。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/41797_葡_33889.gif","12","上下","艹","葡","Portugal","http://cdn.ococci.com/dict_ali/2022-02-25/1645768372284960829_54eea950-2c3a-e660-d805-ea79afa5af1e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/137/葡_pú.mp3", "葡萄 葡萄糖,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"葡萄。多年生落叶藤本植物，叶子掌状分裂，开小花。这种植物的果实也叫葡萄，多汁，可生食、制干、酿酒。也写作\"蒲桃\"、\"蒲陶\"或\"蒲萄\"：她精心照管园里的葡萄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"葡萄牙的简称。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/95344_萄_33796.gif","11","上下","艹","萄","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"táo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/136/萄_táo.mp3", "葡萄,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"葡萄〕ａ．落叶藤本植物，果实圆形或椭圆形，味甜可食，亦可酿酒；ｂ．这种植物的果实或像其形者，如“葡萄干”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87786_紫_32043.gif","12","上下","糸","紫","Purple","http://cdn.ococci.com/dict_ali/2022-02-25/1645774769364593023_7b1bdbf9-eae6-072d-ee9b-726322d5eb83.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/118/紫_zǐ.mp3", "紫色 紫红 紫竹 紫菜 紫丁香 紫罗兰 紫外线,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种颜色(即红与蓝相混合而成的颜色)：到花落之时，它又变成紫色了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/41782_狐_29392.gif","8","左右","犭","狐","Fox","http://cdn.ococci.com/dict_ali/2022-02-25/1645775006044888017_fdc70ec9-4b2c-f3f8-135f-e57dfda85079.mp3");
