INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"狐狸。哺乳动物，犬科，肉食类，形状似狼，生性狡猾，毛皮珍贵：狐狸再狡猾，也逃不过猎人的眼睛。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24711_招_25307.gif","8","左右","扌","招","Recruit","http://cdn.ococci.com/dict_ali/2022-02-23/1645615857106979720_47ab84e5-19a7-bff8-6561-9f826e000007.mp3");
