INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"应接。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"打手势叫人来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用公开的方式使人来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摇动：招摇（故意张大声势，引人注意）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"承认自己的罪行。");
