INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"狐狸：冬天，狐狸常常到农院把鸡咬死。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/81557_募_21215.gif","12","上下","力","募","Recruit","http://cdn.ococci.com/dict_ali/2022-02-23/1645615857106979720_47ab84e5-19a7-bff8-6561-9f826e000007.mp3");
