INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"suān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/酸_suān.mp3", "酸楚 酸梅 酸软 酸痛 寒酸 酸甜苦辣,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像醋的气味或味道：酸菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"讥讽人的迂腐：穷酸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因疲劳或疾病引起的微痛而无力的感觉：酸痛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悲痛，伤心：酸楚。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"化学上称能在水溶液中产生氢离子的化合物，分“无机酸”、“有机酸”两大类：盐酸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/66869_曹_26361.gif","11","上下","曰","曹","Cao","http://cdn.ococci.com/dict_ali/2022-02-24/1645703858517436543_1a89c3bc-182e-dfcd-b735-682d2aac684f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cáo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/62/曹_cáo.mp3", "曹氏 曹家 曹冲 曹操,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代官署中分科办事的部门：东汉成帝初，置尚书四人，分为四曹。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/1220_称_31216.gif","10","左右","禾","称","Say","http://cdn.ococci.com/dict_ali/2022-02-25/1645751687981445863_85bd9d9a-44bf-e1fa-fc04-3a68e7c7047d.mp3");
