INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"适合；配得上：她穿这件衣服与她的气质太不相称了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/110/称_chèng.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“秤”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/110/称_chēng.mp3", "称呼 称号 爱称 简称 称赞 称颂 称谢,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称呼：我们都习惯称她\"老大姐\"。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"声称：石守信等领会皇帝的意图，称病辞职。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"举事：称兵");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"测定重量：称一下这袋面粉的重量。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表扬：他的行动受到了同学们的一致称赞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叫，叫做：称孤道寡。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76198_员_21592.gif","7","上下","口","员","Clerk","http://cdn.ococci.com/dict_ali/2022-02-23/1645608380813199881_873520eb-6677-04ec-a500-6595fb2b01fb.mp3");
