INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"周围：我国幅员辽阔，物产丰富。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"工作、学习或某种团体、组织中的成员。我的父亲是中学教员。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：张飞是刘备手下的一员猛将。");
