INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gēn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/根_gēn.mp3", "根本 根源 树根 菜根 根据 根底 根基 胚根 除根,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物的本源；根由：发生这种事情的根源在于粗心大意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物生长在水或土壤中的部分，能吸收养分以供植物上部，有的还能贮藏养料：萝卜吃根不吃叶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻子孙后代：程家只有这么一条根。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于条形或细长的东西：一根根原木随着流水往前漂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：这有两根草。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"彻底：你这病得根治。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凭证；依据：你那收据存根了没？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/70758_柱_26609.gif","9","左右","木","柱","Column","http://cdn.ococci.com/dict_ali/2022-02-21/1645458200922335948_688ce041-b3b2-87be-bed6-622aa8e7c2e0.mp3");
