INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像柱的东西：冬天，山崖上的冰柱挂成一排，甚是好看。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用木、石等制成的，在建筑物中直立而起支撑作用的构件：厅前两边的木柱上，贴着刚写好的春联。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/80622_议_35758.gif","5","左右","讠","议","Discuss","http://cdn.ococci.com/dict_ali/2022-02-24/1645713643768486795_80204a61-cc89-1eb3-8388-b091efbe2c31.mp3");
