INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"达到：在阿尔卑斯山北面的那些城市，罗马教皇是鞭长莫及了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"趁着；乘：要及早排除隐患，以免酿成大祸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。相当于\"和\"、\"跟\"、\"与\"：人们关于未来的正确思考与认识，都是根据客观事物及其规律而作出的一种超前反映。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"追上；赶上：你这招，简直搞得我措手不及。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/28686_懒_25042.gif","16","左中右","忄","懒","Lazy","http://cdn.ococci.com/dict_ali/2022-03-23/5423671000000080_1648025263876.mp3");
