INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不勤快；不喜欢劳动和工作：其实他平时是不懒的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疲倦；疲惫：他伸起酸懒的腰杆，对着柜台出神。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不情愿：对于已过去的那些日子，他实在懒得再谈。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22774_并_24182.gif","6","上下","干","并","And","http://cdn.ococci.com/dict_ali/2022-03-03/1646274508705335751_c4fd0cf4-4b3b-9ab6-3019-2af0f8e84297.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/并_bìng.mp3", "合并 归并 并举 并肩 并列 并排 并行 兼并 并吞,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"合在一起：小液泡逐渐胀大，最终合并成一个大液泡。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"平排着：四辆摩托车并驾齐驱在前面开路，贵宾轿车紧随其后。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。A. 同时；一起：元朝统治者对各种宗教，采取兼容并包的政策。B. 用在否定词前加强否定的语气：我并非不想上大学，而是没有那个经济条件。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/并_bīng.mp3", "并州,");
