INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"长，高:小娟身材修长，出落得亭亭玉立。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"兴建，建造：回鹘人在修住宅，开店铺，与汉人通婚。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"整治(使完美或恢复完美)：他是个修皮鞋的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"编纂，撰写：《春秋》传说是孔子编修的一部历史书。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"装饰，使完美：他又把住房装修了一下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"学习，专研：他大学课程修满毕业时名列全年级第二名。");
