INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"担负：足下能肩此重任，真是社稷之福!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：卫老婆子仿佛卸了一肩重担似的嘘一口气。");
