INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"少：鲜有。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/197/鲜_xiān.mp3", "鲜明 新鲜 鲜艳 鲜红 鲜美 海鲜,");
