INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"新宰杀的(畜禽肉)；刚成熟的：他平常饮食也十分讲究，只吃鲜肉，不吃冻肉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"滋味美好：这道菜，味道鲜极了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24043_哄_21700.gif","9","左右","口","哄","Coax","http://cdn.ococci.com/dict_ali/2022-02-18/1645166333080903685_d5370c44-c98c-1f2c-b4a8-d6f4ace3cd1c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哄_hòng.mp3", "起哄 哄抢 哄抬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"吵闹，搅扰：起哄（故意吵闹扰乱，亦指开玩笑）。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hǒng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哄_hǒng.mp3", "哄人 哄弄 哄骗 哄逗 哄劝,");
