INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用语言或行动逗人喜欢：哄小孩儿。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哄_hōng.mp3", "哄传 哄动 哄然 哄抬 哄堂 闹哄 乱哄哄,");
