INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/先_xiān.mp3", "先后 优先 领先 首先 先锋 先进 先烈 先行 先驱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"祖先；上代：许多世家子弟藏有祖先家信，可以作为证据。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"尊称死去的人：人们从这里可以了解到中国革命所经过的艰苦道路，先烈们的光辉业绩。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间或次序在前：你先行一步，我待会儿再来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90489_梦_26790.gif","11","上下","木","梦","Dreams","http://cdn.ococci.com/dict_ali/2022-02-25/1645768410389889353_c49a8b41-6f5c-1b21-eb76-33c93cbc61a4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/梦_mèng.mp3", "梦乡 梦幻 梦话 梦游 梦想 梦境,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"做梦；梦见：刚入伍时，他常梦到家乡的亲人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"想像；幻想：他的发财梦破灭了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"睡眠时局部大脑皮层没有完全停止活动而引起的表象活动。宗教观念、神话故事、梦境奇遇等，也是客观事物在人脑中形成的某种反映。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24826_闭_38381.gif","6","半包围","门","闭","Close","http://cdn.ococci.com/dict_ali/2022-03-30/542367100000006d_1648615990976.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/181/闭_bì.mp3", "封闭 倒闭 关闭 停闭 闭幕 闭塞 闭月羞花,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闭塞；不开通；阻塞；堵住：清政府实行闭关政策，多次下令禁止海外贸易。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"关上；合上：他坚决反对在讨论问题的时候，开口闭口拿笔记本来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10842_紧_32039.gif","10","上下","糸","紧","Tight","http://cdn.ococci.com/dict_ali/2022-02-24/1645688524993137517_a8a0fba1-424d-1bf4-5942-4bebe51ad2b9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jǐn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/118/紧_jǐn.mp3", "赶紧 抓紧 紧急 松紧 紧张 紧凑 紧迫 紧缩,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物体受到拉力或压力后呈现的状态。跟“松”相对：绳子捆得太紧，一时无法解开。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迫切：时间紧，大家还要加把劲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"情绪紧张：袁隆平每听到敲门声，心里就发紧。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"剧烈；猛烈：在海风吹得紧的时候，白色的帆张得满满的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使紧：张师傅，请把螺丝再紧一下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"间隙小：快把门窗关紧。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经济不宽裕：低收入的人家确乎是紧起来了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/82983_润_28070.gif","10","左右","氵","润","Run","http://cdn.ococci.com/dict_ali/2022-02-25/1645773353116848984_4ba8ead3-c28e-e01e-9c47-c2c66d1e831f.mp3");
