INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"加油或水使不干枯。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不干枯，湿燥适中。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细腻光滑。");
