INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔累累〕a.连续成串，如“果实累累”；b.颓丧的样子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔累赘〕a.多余，不简洁；b.使人感到多余或麻烦的事物。");
