INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因体力、脑力消耗多而觉得疲劳：尽管这样，他也不觉累。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"操劳：你已累了一天，应该好好休息一下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使之疲劳；疲惫：母亲被累倒了。");
