INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连及，连带。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连续，重叠，堆积。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"照原数目多少而递增。");
