INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/85/瀑_bào.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（瀑河）水名，在中国河北省。亦作“鲍河”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/85/瀑_pù.mp3", "瀑布,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～布〕水从高山陡直地流下来，远看好像挂着的白布。简称“瀑”，如“飞～流泉”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55163_布_24067.gif","5","半包围","巾","布","Cloth","http://cdn.ococci.com/dict_ali/2022-02-24/1645709171586123384_7b15764a-a3c3-da93-7c7f-23fdaf855602.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/布_bù.mp3", "公布 棉布 麻布 布鞋 发布 布告 散布 布丁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用棉、麻、化学纤维等织成的，可以做衣服或其他物件的材料：演出时，场上用黑色布幔把台遮住。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宣告：1987年4月，《联合声明》宣布中华人民共和国政府将于1999年12月20日对澳门恢复行使主权。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"布置；设置：东京的城市布局，打破了\"坊\"、\"市\"界限。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/14425_炉_28809.gif","8","左右","火","炉","Furnace","http://cdn.ococci.com/dict_ali/2022-01-27/1643294046635967686_a4bdc3ae-c2a9-7130-e710-11af76691cd7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/86/炉_lú.mp3", "炉子 炉火 炉渣 火炉 电炉 香炉 锅炉 壁炉 炉火纯青,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于取暖、烧水、做饭、冶炼等用的盛火器具或装置：一到冬天，她总是离不开那个手炉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：店铺旁边有一炉火，燃得正旺。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/28038_烟_28895.gif","10","左右","火","烟","Smoke","http://cdn.ococci.com/dict_ali/2022-02-25/1645757323740585605_9beb602a-e024-fb43-4409-3296f5c9409c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/87/烟_yān.mp3", "烟火 烟花 烟波 烟雨 烟尘 烟雾 人烟 炊烟 香烟 硝烟 烟波浩渺 烟消云散,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"专指鸦片：林则徐虎门禁烟，英国鸦片商人恼羞成怒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像烟一样的东西：烟雾。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物质燃烧时产生的混合气状物：南面的天空被浓烟盖满了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用烟草制作的香烟：他口里叼着一支烟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由于烟的刺激使眼睛睁不开或流泪：她烤炭火时，烟了眼睛。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/18228_遥_36965.gif","13","半包围","辶","遥","Yao","");
