INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"远：遥远。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87296_川_24029.gif","3","独体","川","川","Chuan","http://cdn.ococci.com/dict_ali/2022-02-23/1645614286895720791_2575b67d-78e6-7e7e-42e0-f9e3bc6c2cdd.mp3");
