INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"听见：流言，尤使我耳不忍闻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"听见的事情：只要你上街，新闻多得很。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"名声：丑闻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用鼻子嗅：那个胖胖的鼓着两只金鱼眼的女孩子摘下一枝路旁的野花，闻了闻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"出名，有名望：涉及名流闻人的事情要使不少小报记者忙得汗流浃背。");
