INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"míng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/名_míng.mp3", "名人 名著 名字 名言 名称 名词 名贵,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"说出，叫出：莫名其妙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人或事物的称谓：名字。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"声誉，有声誉的：出名。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"名义。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计人数的量词：五名教师。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"说：这件事真叫人感到莫名其妙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"名词：人或事物名称的词。");
