INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"日光：耀景。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"舞台上或摄影棚等，根据需要，人工布置景物：布景。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬慕，佩服：景仰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"风光，风景：美景");
