INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地方行政区域：省份。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代称王宫禁地：省中。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国古官署名：中书省。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"节约，不费：省钱。");
