INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"部队：我父亲那时候率部突围才得以幸免于难。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"部位；部分：《牡丹亭》里，主人公杜丽娘把她内心的激动和外部景物巧妙地糅合在一起。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军队中连以上的领导机构或其所在地：所有排以上军官到团部参加军事会议。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。A. 用于影片、书籍等：这部书，对于研究社会科学的人很有用。B. 用于机器或车辆：这几部汽车是工厂前几年买的。");
