INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"美；美丽：当时她才十九岁，秀外慧中，人见人爱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"优异出众的人：他是我校的后起之秀。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"茂盛：佳木秀而繁荫。");
