INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“諅”。周年。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/其_qí.mp3", "其中 其他 其次 其间 其实 尤其 不厌其烦 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在副词后作陪衬：我拿到入学通知书后，母亲极其高兴。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代词。他(她、它)；他们(她们、它们)：著称世界的\"五岳\"名山，以其独特风格而闻名海外。");
