INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/3/位_wèi.mp3", "位子 部位 地位 座位 位置 位于 位移 各位,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"所在或所占的地方。主持人让大家各就各位，大会马上开始。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"祭祀时设的灵位、神位：他又到屋里，从躺箱上头的墙壁上，把\"白氏门中三代宗亲之位\"也撕下来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"职位；地位：以革新或留学获得名位，生计已渐充裕者，很容易流入这一路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于人：请两位稍等一下。");
