INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"整体里的一部分：小二黑这个孩子，在三仙姑看来好像鲜果，可惜多一个小芹，就没了自己的份儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：他叫侍从将那一份知启先送回去，然后出门上轿去了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在“年”“月”后面，表示划分的单位：三月份春暖花开，是郊游的好时节。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50283_枝_26525.gif","8","左右","木","枝","Branch","http://cdn.ococci.com/dict_ali/2022-02-24/1645712462200675089_12396536-6764-329c-48b7-09d33550af1e.mp3");
