INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。A．斑竹一枝千滴泪，红霞万朵百重衣。B．架上放着几枝枪。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/15141_搭_25645.gif","12","左右","扌","搭","Take it","http://cdnmu.gurobot.cn/saodubi/dict/audio/Take_it.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/55/搭_dā.mp3", "搭车 搭伙  白搭 扭搭 搭配 搭桥 勾肩搭背,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"支起：他帮人家搭柴灶，用旧煤油桶做煤球炉子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"共同抬：他们把加剧搭进屋去。");
