INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挂：他把衣服搭在杆上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连结一起：他冲进门来，前言不搭后语地说了好一阵。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"披：他把衣服搭在肩上，气冲冲地跑了出去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凑在一起：他很喜欢搭讪。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/68643_淡_28129.gif","11","左右","氵","淡","Light","http://cdn.ococci.com/dict_ali/2022-02-25/1645761692249409851_e218c235-1401-a711-48fa-019581a84b94.mp3");
