INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(颜色)变浅：天空的霞光渐渐地淡下去了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稀薄。气体或液体中所含的某种成分少。与\"浓\"相对：天高云淡，望断南飞雁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言。无关紧要的；没有意味的：站不站岗是淡事，反正敌人出来就打。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(味道)不浓：这道菜应再加点盐，实在太淡了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不热情：我因打电子游戏旷了课，同学们对我显得有些冷淡。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生意不兴旺：是这几个月服装销售的淡季。");
