INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/够_gòu.mp3", "够格 够呛 不够 足够 能够 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"达到某种标准或某一点：他报名参军，身体肯定是够格的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"达到，及：她想去摘左边的一枝梅花，但由于身材矮小了一点，怎么也够不着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"超过一定限度：这种生活我早已过够了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数量上满足需要：那时候，工资很低，每月都觉得钱不够花。");
