INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"职务和级别的名号。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"马嚼子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"含在心里。");
