INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"无趣味：有的同学嫌哲学枯燥无味，选修了其他课程。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(植物)失去水分。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"干涸(井、水流等没有水)：他再也不相信海枯石烂之类的谎话了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/97413_劝_21149.gif","4","左右","力","劝","Persuade","http://cdn.ococci.com/dict_ali/2022-02-24/1645661344200212429_1b013ee4-a2b4-7ab8-0245-21fb4b4b484e.mp3");
