INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"讲明事理，使人听从。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"勉励。");
