INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"充分利用机会、时间等：王师傅趁空修理自行车。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/72206_将_23558.gif","9","左右","寸","将","Will","http://cdn.ococci.com/dict_ali/2022-02-25/1645772780684885385_5dbf5cec-0507-4b40-7bef-f3423a15174a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/将_jiàng.mp3", "大将 将领 干将 虎将 健将 上将,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军衔名，在校级之上：名将以身殉国家，原拼热血卫吾华。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能手；能人：赛场上体坛老将大显身手，后起新秀崭露头角。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/将_jiāng.mp3", "将来 将信将疑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"保养；他伤得不轻，得着实将养几月。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"下象棋时攻击对方的\"将\"或\"帅\"：当头炮一将，红方便赢了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用言语刺激：他不愿去，你将他也没用。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"将要：我们将建设一个新世界。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/将_qiāng.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"愿;请求。用来表示礼貌上的尊敬。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88583_难_38590.gif","10","左右","隹","难","Difficult","http://cdn.ococci.com/dict_ali/2022-02-25/1645750523732953534_f4716613-abb9-e925-39a9-02683e5b872b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/183/难_nán.mp3", "难怪 难免 难得 难听 难过 难点 难受 难关,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"做起来费力：红军不怕远征难，万水千山只等闲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使感到困难：我一定要出个谜语难住你。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言。如今；现在：王老爷难也有点勿老实哦!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不容易；不可能：他的观点很难改变。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不好：有些商业化的影视片实在难看。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/183/难_nàn.mp3", "难民 遭难 非难 责难 逃难 死难 难友,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不幸的遭遇；祸患：祖国如有难，汝应作前锋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"质问；诘问：她这样做是对的，是无可责难的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36872_且_19988.gif","5","独体","一","且","And","http://cdn.ococci.com/dict_ali/2022-03-03/1646274508705335751_c4fd0cf4-4b3b-9ab6-3019-2af0f8e84297.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/且_jū.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文言助词，用在句末，与“啊”相似。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多的样子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“趄”，趑趄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"农历六月的别称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬慎的样子：“有萋有～”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiě", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/且_qiě.mp3", "且慢 并且 而且 姑且 况且 苟且 尚且 暂且,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。A. 表示暂时；姑且：让我且看一看再决定。B. 快要；将要；将近：他已是年且50的人了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。A. 表示进一层，并且；而且：河水既深且凉。B. 表示两个动作同时进行：他俩且行且议。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35680_狂_29378.gif","7","左右","犭","狂","Crazy","http://cdn.ococci.com/dict_ali/2022-02-25/1645755381775549986_0a7fdd58-ffcd-df5a-0dd2-da27af222a09.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/92/狂_kuáng.mp3", "狂暴 狂风 狂热 狂言 发狂 狂欢,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"任情地做，不用理智约束感情：四年大学生活就要结束了，大家不由聚在一起狂欢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疯癫；精神失常：收到录取通知书后，他欣喜若狂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"猛烈的，声势大的：我终于冒着狂风暴雨乘黄包车赴会。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"傲慢；狂妄：瞧他那狂劲儿，总有一天要跌得头破血流。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63660_吼_21564.gif","7","左中右","口","吼","Roar","http://cdn.ococci.com/dict_ali/2022-02-25/1645752100235448512_9b5cd548-49e5-a953-565c-e0404c90ca3e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/吼_hǒu.mp3", "吼叫 大吼 猛吼 怒吼 狮吼 牛吼 狂吼,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(风、汽笛、大炮等)发出很大的响声。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(猛兽)大声叫。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"发怒或情绪激动时大声叫喊。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3852_复_22797.gif","9","上中下","夂","复","Fu","http://cdn.ococci.com/dict_ali/2022-02-25/1645771463686882207_d1e0e7d1-80c3-d7bc-b67b-3d8c83087fe2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/复_fù.mp3", "复仇 复合 复活 答复 复述 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"转过去或转回来：近来天气反复无常。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"重复。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"还原；使如旧：你很快就会康复。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"回答；告诉：对来信中的问题，她总是及时处理或答复。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"报复：满怀失去田地的痛苦、饥饿的煎熬和复仇的怒火，他们揭竿而起。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99892_哀_21696.gif","9","上下","口","哀","I'm sorry","http://cdnmu.gurobot.cn/saodubi/dict/audio/I%27m_sorry.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"āi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哀_āi.mp3", "悲哀 哀怨 哀悼,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悲痛；悼念。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76278_葫_33899.gif","12","上下","艹","葫","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/137/葫_hú.mp3", "葫芦 葫蔓藤 葫芦藓 葫芦科,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"葫芦。草本植物，茎蔓生，叶子互生，夏天开白花，果实中间细，两端像球形，可做器皿，也可供玩赏：他到船上取了一个盛酒的葫芦上岸来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/67399_芦_33446.gif","7","上下","艹","芦","Lu","http://cdn.ococci.com/dict_ali/2022-02-25/1645764500197907775_da97d72f-5823-0762-3fb8-3ff23666baaf.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/芦_lú.mp3", "芦苇 芦花 芦衣 芦根 芦席 芦笛 芦笙 芦荡 葫芦 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"芦苇。多年生禾本科植物，多生长在水边，叶披针形，茎中空并光滑，花紫色，其下面有很多丝状的毛。芦苇秆可编席及造纸，根和地下茎还可入药：翠鸟喜欢停在水边的芦苇秆上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/79264_藤_34276.gif","18","上下","艹","藤","Rattan","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"téng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/140/藤_téng.mp3", "藤蔓 藤编,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔藤黄〕a.常绿乔木，茎高达二十米，树脂黄色，有毒；b.这种植物的树脂，可作国画颜料。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指“白藤”、“紫藤”：藤条。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指匍匐茎或攀援茎：藤本植物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63191_谢_35874.gif","12","左中右","讠","谢","Thank you","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/谢_xiè.mp3", "感谢 谢谢 谢客 致谢 答谢 谢幕,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"感激：那青年说：“大恩不言谢，我总要粉身碎骨报答你老人家的!”");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"认错：我要深深地向你们谢罪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"推辞：他对自己要求很严，每当有人送礼上门，都婉言谢绝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/25717_啊_21834.gif","10","左中右","口","啊","Ah","http://cdn.ococci.com/dict_ali/2022-02-25/1645763241220300719_874643fe-dbc4-74d1-7c78-a3ffdc8f0709.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"á", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/18/啊_á.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叹词，表示疑问或反问：啊，你说什么？");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"à", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/18/啊_à.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用来表示悲痛、遗憾或忧伤。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叹词，表示应诺（音较短）：啊，好吧！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叹词，表示醒悟（音较长）：啊，我这才明白过来！");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示赞叹（音较长）：啊，亲爱的祖国！");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/18/啊_ǎ.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叹词，表示疑惑。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/18/啊_ā.mp3", "啊呀 啊哇 啊哪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叹词。多用于句首，表示赞叹或惊异：啊!我仿佛听见大海正在唱着一曲新歌。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13161_蚜_34460.gif","10","左右","虫","蚜","Aphids","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yá", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚜_yá.mp3", "蚜虫 棉蚜 烟蚜,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚜虫。昆虫，又叫\"甜虫\"，俗称\"腻虫\"。身体卵圆形，绿色、棕色或紫红色，腹部大，吸食植物的植液，是农作物的害虫：棉花地里开始长棉蚜了，应赶快喷洒农药。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13709_盯_30447.gif","7","左右","目","盯","Stare","http://cdn.ococci.com/dict_ali/2022-02-24/1645681618729074462_344624e8-722b-f433-0df2-46def24591b2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/102/盯_dīng.mp3", "盯人 盯梢 直盯盯,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把视线集中在一点上：这小女孩忽灵灵地闪着一双大眼睛盯住我。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3232_赛_36187.gif","14","上下","贝","赛","Sy","http://cdn.ococci.com/dict_ali/2022-02-25/1645767111888081117_6d145f3b-19d1-6033-87e2-31b765236506.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/159/赛_sài.mp3", "赛车 赛马 比赛 决赛 初赛 竞赛 预赛,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧时行祭礼以酬报神恩：这里的村民过去常举行赛神会。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竞争；较量；比高低：那些日子里，全船像要参加国际棋赛一样。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"胜过；比得上：这些中年人干起活来赛过小伙子。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85493_感_24863.gif","13","上下","心","感","Sense","http://cdn.ococci.com/dict_ali/2022-02-24/1645714897224478646_984afee6-76eb-6bd5-75ed-58c6de95fb6e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/感_gǎn.mp3", "感动 感激 感恩 反感 灵感 敏感 感想 感叹号 好感,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"受外界影响而引起的反应：受了你的感化后，知道了做人的责任。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"觉得：这段时间，我总感觉身体不舒服。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对别人的好心表示谢意：你这样做，他们太感激你了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"感染（疾病）：他得了流感。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（胶片等）接触到光线而发生变化。感光。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/感_hàn.mp3", "感突 感移 释感 怀感 感恨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“憾”，怨恨；遗憾。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"通“撼”，摇动。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36674_怪_24618.gif","8","左右","忄","怪","Weird","http://cdn.ococci.com/dict_ali/2022-02-18/1645193088275030486_4aaa485b-8bed-a870-b62f-a8c46fe64b89.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"guài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/45/怪_guài.mp3", "古怪 错怪 奇怪 责怪 怪罪 怪诞 怪癖 怪物 怪异,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(觉得)惊奇；惊异：你这样大惊小怪地做什么？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"怨；责备：这只怪他们以一种错误的认识去归纳客观事实。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不常见的；奇特的：贝壳的颜色不一，形状也千奇百怪。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/45113_慢_24930.gif","14","左右","忄","慢","Slow","http://cdn.ococci.com/dict_ali/2022-02-25/1645764629621696166_89176e03-235e-7439-bc16-afb9fd98ef8a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"màn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/慢_màn.mp3", "缓慢 快慢 傲慢 怠慢 慢性子 慢悠悠,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对人态度冷漠：我也没有这么傲慢，对于一位素不相识的投稿者，会轻率的写信去叫他。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从缓：这件事不能急，慢一点看着再说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"行走；速度低；做事费时：学文化应该一点一滴地慢慢积累，特别是初学的人不宜求之过急。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/26106_锋_38155.gif","12","左右","钅","锋","Feng","http://cdn.ococci.com/dict_ali/2022-02-22/1645527728042129130_c718a70e-39f7-da03-db8e-dd00bdd245e1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/179/锋_fēng.mp3", "笔锋 冲锋 刀锋 前锋 话锋 先锋 锋利 交锋 锋芒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刀剑等器械锐利或尖端部分：月的光亮里，刀光一闪，刀锋剁在坑砖上，冒出了火花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指器物像刀锋的尖端：毛笔的笔锋触到信笺，他很快书写起来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48823_蜜_34588.gif","14","上下","虫","蜜","Honey","http://cdn.ococci.com/dict_ali/2022-02-24/1645704462823567275_8a2bc694-e301-cc87-f355-51a0239777ef.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/143/蜜_mì.mp3", "蜜源 蜜语 蜜甜 蜜露 蜜饯 蜜蜂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"甜美。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蜜蜂采取花的甜汁酿成的东西。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50271_蜂_34562.gif","13","左右","虫","蜂","Bee","http://cdn.ococci.com/dict_ali/2022-02-25/1645765684602492504_86c75422-7a61-4c39-3bdc-5d3cbd7c186f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/143/蜂_fēng.mp3", "蜂拥 蜂聚 黄蜂 蜜蜂 蜂群 蜂乳 蜂王 蜂窝,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"膜翅类昆虫名。会飞，多有毒刺，喜群居，种类甚多：好像守门的蜂，尾上藏是蜂虿，知道它的职务，是保护全群安全的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指蜜蜂：因这缘故，使养蜂者的目的，不在于使酿蜜而在于使繁殖了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻众多而杂乱：街上的人群蜂拥着，跑的跑，叫的叫，冲了过去。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/56293_幕_24149.gif","13","上下","巾","幕","Curtain","http://cdn.ococci.com/dict_ali/2022-02-25/1645772745588726732_8cd33e4a-7868-c039-920e-daa53f5ffe9a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/幕_mù.mp3", "幕布 开幕 闭幕 夜幕 银幕 谢幕 幕府 幕僚 幕后,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"话剧或歌剧的较完整的段落：我曾为着演出\"序幕\"而苦练劈叉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"影剧院里垂挂在舞台前的大幅布、绸、丝绒等：望着即将拉开的幕，她心里紧张极了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"覆盖在上面的帷幔；也特指帐篷：在大草原上，牧民的帐幕星罗棋布。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13881_扫_25195.gif","6","左右","扌","扫","Sweep","http://cdn.ococci.com/dict_ali/2022-02-25/1645771653588300177_cf5f8cfa-37f0-2998-8c8b-74ecec1a1234.mp3");
