INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"描画。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清除，消灭。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迅速横掠而过。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"全，尽，尽其所有。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结束，了结。");
