INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"羡慕；向往：西安成了世人瞩目的地方，不少中外旅游者纷纷慕名而来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"向往；思念：他望着秀芬苗条的背影，那慕恋的眼光情不自禁地随着她的背影慢慢远去了。");
