INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"烹调方法，把食物放进加热的锅里并随时翻动使其熟：炒中国菜非常讲究火候。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻倒卖：他很喜欢炒股");
