INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言，差，欠：总数还争多少？");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"怎么，如何：争不。");
