INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/2/代_dài.mp3", "当代 代表 代替 朝代 历代 时代 近代 年代,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"代理：上级临时给工厂任命了一位代厂长。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"世代；年代；时代：我们的下一代生活会过得更美好。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"整个地质年代划分为五个代，即太古代、元古代、古生代、中生代和新生代：直到现在，人们仍无法解开恐龙在中生代末期突然灭绝之谜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"替换：《木兰诗》共三百多字，描述了一位女扮男装，代父从军的女英雄木兰。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/42664_临_20020.gif","9","左右","丨","临","Pro","http://cdn.ococci.com/dict_ali/2022-02-25/1645774677766963401_b910b61e-dd92-43d5-1152-f5f40ce3546e.mp3");
