INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指具有共同起源和共同遗传特征的人群：种族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"聚居而有血统关系的人群的统称：宗族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指在历史上形成的人群的稳定共同体，他们有共同的语言，经济生活以及变现与共同文化上的心理素质：民族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物有共同属性的一大类：芳香族。6封建时代的一种残酷刑罚，一人有罪，把全家或包括母亲，妻家的人都杀死：灭族。7聚合，集中：云气不待族而雨。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亲属，泛指同亲之亲：族规。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/15081_民_27665.gif","5","独体","氏","民","Min","http://cdn.ococci.com/dict_ali/2022-02-24/1645686212708169719_afecc068-b6dc-2c12-3138-62ccd5459e54.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mín", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/75/民_mín.mp3", "人民 民主 民族 牧民 民兵 民间,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"以劳动群众为主体的社会基本成员。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"劳动大众的，非官方的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指人或人群。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"某族的人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“苠”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从事不同职业的人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"非军事的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57022_度_24230.gif","9","半包围","广","度","Degree","http://cdn.ococci.com/dict_ali/2022-02-25/1645754813316659211_85a6c60e-5871-eebd-a387-a387e503551e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/度_dù.mp3", "长度 广度 宽度 限度 速度 幅度 精度 亮度,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"限度：妈妈劳累过度，加上孩子多，生活艰苦，老病又复发了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"器具：战国时期，各国的度量衡都不一样。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一度等于60分：这山的坡度已达到60度。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哲学上指一定事物保持自己质的数量界限：掌握事物的度，既要注意决定事物质量的数量界限，又不能把事物的度绝对化。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表示程度。用于名词、动词或形容词之后，构成名词性后缀：毛泽东同志高度赞扬了\"曾经是自由主义或民主个人主义者\"的闻一多、朱自清等。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"所打算或计较的：无数革命先烈为了新中国的建立，早已将个人的生死置之度外。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经度或纬度：这座城市位于北纬38度。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"duó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/度_duó.mp3", "揣度 测度 审度 度德量力,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"估计；推测：平时他沉默寡言，很难揣度其内心世界。");
