INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧时汉语标音的一种方法，用两个字，取上一字的声母与下一字的韵母拼成一个音。亦称“反切”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"密合，贴近：亲切。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10/切_qiē.mp3", "切除 切磋 切断,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"直线，圆或面等与圆、弧或球只有一个交点时叫做切。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用刀从上往下用力：切菜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/74245_躲_36530.gif","13","左右","身","躲","Hide","http://cdn.ococci.com/dict_ali/2022-02-25/1645741845905345593_051442fc-2a26-f467-f6cb-f7668f995af9.mp3");
