INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"避开；避让：犀牛发起脾气来，连大象都得远远地躲着它。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"隐藏；躲藏：那段时间，他躲没处躲，藏没处藏。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/21318_桔_26708.gif","10","左右","木","桔","Tangerine","http://cdn.ococci.com/dict_ali/2022-02-23/1645620122872732346_f3d94668-4de9-0082-8703-77ce4f1642cd.mp3");
