INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"桔槔：古代的一种井上汲水工具，是架在水边的杠杆，一端挂水桶，一端坠大石块。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"直木。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"桔梗，一种多年生草本植物。叶卵形或卵状披针形，花暗蓝色或紫色，供观赏。根可入药。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"桔档儿：高粱秆的顶端细的部分。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/桔_jú.mp3", "桄桔 桔皋 桔桀 桔柣 锁桔,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"“橘”俗作“桔”。");
