INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不可思议的，特别希奇的：神秘");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"心思，心力，注意力：劳神。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表情：神色。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不平凡的，特别高超的：神勇。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"精神：神清气爽。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迷信的人称天地万物的创造者和所崇拜的人死后的精灵：神仙。");
