INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"家畜。哺乳动物。躯体肥大，四肢短小，头大，耳大，眼睛小，鼻子和口吻都长，脚短身肥。肉可食，皮可制革，毛可制刷子或做其他工业原料：革未革曷族原居住在黑龙江、松花江和乌苏里江流域，他们放牧猪群。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55022_纳_32435.gif","7","左右","纟","纳","Na","http://cdn.ococci.com/dict_ali/2022-02-24/1645708844339329764_ae8243a5-3204-1e15-eef7-5347ff6b8942.mp3");
