INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接纳别人给的东西：接受。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"忍耐某种遭遇：忍受。");
