INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"说谎话、用假象、耍花招、使诡计(让人上当)：我说有人嘛，还能骗你?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用欺骗的手段取得钱、财等：她常常用“家里穷，不能完成学业”等谎话在这里骗钱。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/9518_借_20511.gif","10","左右","亻","借","Borrow","http://cdn.ococci.com/dict_ali/2022-02-25/1645768609859115981_273e91a9-7598-da99-c64d-40c4b7860c7c.mp3");
