INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"暂时使用别人的钱物：他到图书馆借书去了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把自己的钱物暂时提供别人使用：这份资料先借给你看。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凭借；依靠：我国远洋事业正在飞速发展，可借此锤炼海员。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"假托：男家催过几次，却被外婆借故拖延了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/6871_筝_31581.gif","12","上下","竹","筝","Zheng","http://cdn.ococci.com/dict_ali/2022-02-23/1645614662375210345_78d47259-5ecf-1b90-9e1c-3ea9bdde82db.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/114/筝_zhēng.mp3", "古筝 风筝 琴筝 断线风筝,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弦乐器，木制长形。古代十三或十六根弦，现为二十五根弦。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/22465_鼠_40736.gif","13","上下","鼠","鼠","Rat","http://cdn.ococci.com/dict_ali/2022-02-24/1645695378715721685_e404dd6f-cfec-fa81-1488-3aaf88b0dc7c.mp3");
