INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"老鼠。哺乳动物，体小尾长，门齿发达，能传播疫病，繁殖力极强，又叫耗子：老鼠是危害人类的动物之一。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/74679_折_25240.gif","7","左右","扌","折","Fold","http://cdn.ococci.com/dict_ali/2022-02-25/1645766718529879023_bcd167b8-cb7f-0746-aade-d33034269278.mp3");
