INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"亏损：折本生意。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"断，绳子折了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
