INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"幼年死亡：夭折。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"减少：折寿");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抵作，对换，以此代彼：折合。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"返转，回转：折返。");
