INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"piào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/82/漂_piào.mp3", "漂亮 漂亮话 漂漂亮亮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"漂亮。A.好看；美：节目里，孩子们打扮得真漂亮。B. 出色：这一仗打得真漂亮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指事情、账目等没有着落，没有达到目的或目标：那笔钱没有什么指望，漂了。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"piǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/82/漂_piǎo.mp3", "漂洗 漂白 漂白粉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用水和药物浸洗，使退色或变白：漂白。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用水淘洗：漂洗。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"piāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/82/漂_piāo.mp3", "漂泊 漂浮 漂流 漂移 浮漂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"东奔西走；不固定；不安定：解放前，劳动人民经常过着颠沛流离、漂泊异乡的生活。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浮在液体表面不下沉：菱角开着小小的金黄的花朵，星星点点的，漂在水面上。");
