INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"宠爱：宠幸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指封建帝王到达某地：巡幸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"意外地得到成功或免去灾害：幸运。");
