INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"两个：他们哥俩一个搞文艺，一个搞体育。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指一点点，形容数量少的：他手中没俩钱，还想高消费。");
