INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"手段；花招。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/69353_但_20294.gif","7","左右","亻","但","But","http://cdn.ococci.com/dict_ali/2022-02-25/1645770189603757863_91b76e2d-731e-e143-1fd7-0f4abc92248b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/3/但_dàn.mp3", "但凡 但是 但愿 不但 岂但 非但 但愿如此,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词：这次他病得很重，但愿能好起来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。表示转折关系，相当于\"但是\"、\"不过\"、\"可是\"、\"然而\"：错字问题，同学们并不陌生，但这篇文章中所谈到的错字，却和同学们笔下常常出现的那些不尽相同。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29543_愿_24895.gif","14","上下","心","愿","Wish","http://cdn.ococci.com/dict_ali/2022-02-24/1645713651946540499_8bdb1736-e96a-9378-77a8-0ea22dd1d4e9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yuàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/愿_yuàn.mp3", "情愿 心愿 愿望 愿意 但愿 如愿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迷信的人对神佛许下的酬谢，泛指许给别人的好处：她这次是到报国寺烧香还愿的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"希望：把想做的事做好，这是我的平生之愿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"乐意：各国商人都愿乘坐和使用南宋的海船。");
