INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哭_kū.mp3", "哭泣 哭叫 哭诉 啼哭 哭鼻子 哭哭啼啼,");
