INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸟类的一属，全身白色或灰色，生活在水边，吃鱼、昆虫或植物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36070_鸽_40509.gif","11","左右","鸟","鸽","Pigeon","http://cdn.ococci.com/dict_ali/2022-02-25/1645757655885998752_a7e3bad9-ef0e-e6c3-a162-324a637ea679.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/202/鸽_gē.mp3", "家鸽 鸽子 信鸽 白鸽,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸠鸽科鸽属鸟的通称。形像鸠，羽毛有白、灰或酱紫色，飞行力极强，训练后可用来送信：成群的信鸽在草地上寻找食物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94794_羚_32666.gif","11","左右","羊","羚","Antelope","http://cdn.ococci.com/dict_ali/2022-02-17/1645105361364236754_ff1f2a3b-127f-0f7a-6a37-fc37d79c87cd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"líng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/124/羚_líng.mp3", "羚羊,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔羚羊〕哺乳动物，种类很多，角可入药，如“羚羊挂角”（传说羧羊夜晚睡觉时，以角挂于树上，脚不着地，猎人难以找寻它的踪迹。喻诗文奥妙超脱，不露雕琢痕迹）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/49804_蚯_34479.gif","11","左右","虫","蚯","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚯_qiū.mp3", "蚯蚓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚯蚓。环节动物，身体柔软，体圆而细长，环节上有刚毛，生活在土壤中，能疏松土壤，它的粪便能使土壤肥沃，是益虫。通称曲蟮。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/8415_蚓_34451.gif","10","左右","虫","蚓","Earthworm","http://cdn.ococci.com/dict_ali/2022-02-15/1644903906378961607_3bb43dbe-6341-9229-2203-1d751826e1f4.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚓_yǐn.mp3", "蚯蚓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚯蚓。俗名“曲蟮”。环节动物，身体长而软，生活在泥土中并能翻松土壤。是益虫：现在钓鱼一般不用蚯蚓作鱼饵，而用专门的鱼食。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/16639_螃_34691.gif","16","左右","虫","螃","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"páng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/144/螃_páng.mp3", "螃蟹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～蟹〕见“蟹”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/89363_蟹_34809.gif","19","上下","虫","蟹","Crab","http://cdn.ococci.com/dict_ali/2022-02-24/1645703607710570713_19adc3fd-7d69-414d-a9dd-d7c922f19f50.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/146/蟹_xiè.mp3", "河蟹 螃蟹 蟹粉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔螃～〕节肢动物，水陆两栖。全身有甲壳，足有五对，前双足成钳状，称“螯”，横着爬。腹部分节，俗称“脐”，雄性脐呈长尖形，雌性脐呈椭圆形。简称“蟹”，如“河～”，“海～”，“～黄”，“～青”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52970_虾_34430.gif","9","左右","虫","虾","Shrimp","http://cdn.ococci.com/dict_ali/2022-02-24/1645716547291365868_4da5e185-9896-b096-a3e6-585660987b0d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"há", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/虾_há.mp3", "虾蟆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"虾蟆，同“蛤蟆”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/虾_xiā.mp3", "虾子 虾王 虾仁 虾皮 虾米 虾须 龙虾 海虾 河虾 虾兵蟹将,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"节肢动物。身体长，分头、胸和腹部。体表有透明软壳，腹部由多个环节构成，有许多附肢。生活在水中，会跳跃，捕食小虫。种类很多，如对虾、龙虾、青虾等，均可食。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/83504_蚕_34453.gif","10","上下","虫","蚕","Silkworm","http://cdn.ococci.com/dict_ali/2022-02-24/1645716760284200065_c27a2a08-ab44-81ba-d906-0df2f7c69d29.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚕_cán.mp3", "蚕子 蚕种 蚕纸 蚕蛹 蚕丝 蚕食 蚕山 蚕农,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫，有“家蚕”和“柞蚕”，通常指“家蚕”，吃桑叶，吐丝做茧。丝可织绸缎。“柞蚕”吃柞树叶，丝可织茧绸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46664_莺_33722.gif","10","上中下","艹","莺","Warbler","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/135/莺_yīng.mp3", "黄莺 莺簧 莺娇 莺啼,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻春日景物");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"本义：鸟羽有文彩的样子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"黄鹂。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/25282_拂.gif","8","左右","扌","拂","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/拂_fú.mp3", "拂去,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拭，掸去；轻轻擦过；甩动，抖动；违背，不顺。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38189_堤_22564.gif","12","左右","土","堤","Dike","http://cdn.ococci.com/dict_ali/2022-02-20/1645360316784203339_9352fe2d-1b7c-e590-9f34-439075a6459c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/25/堤_dī.mp3", "堤防 堤坝 堤围 堤岸 堤埂 堤埝 堤堰 河堤 海堤 溃堤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"沿江河湖海用土石等修筑的防水建筑物：前边的那道堤坝有800米长。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59222_柳_26611.gif","9","左右","木","柳","Liu","http://cdn.ococci.com/dict_ali/2022-02-24/1645699718771204282_bfaed781-252a-f5d0-32f1-1e51d596b73b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/柳_liǔ.mp3", "柳树 柳芽 柳枝 柳条 柳眉 柳琴 柳絮 垂柳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"木名。落叶乔木或灌木。枝条柔韧，叶狭长，种子有毛。其种类很多，常见的有垂柳、迎皮柳和旱柳：在两岸的堤上，新植的杨柳迎风吐翠。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50294_醉_37257.gif","15","左右","酉","醉","Drunk","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zuì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/醉_zuì.mp3", "醉汉 沉醉 陶醉 麻醉 酒醉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"饮酒太多致使神志不清：阿Q午间喝了两碗空肚酒，愈加醉得快。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"酒浸制的食品：他们其实只吃了半支醉虾或呷几口醉虾的醋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"爱好：小学五年级时，他就醉心于电脑了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"注射麻药，暂时失去知觉：麻醉。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/17317_咏_21647.gif","8","左右","口","咏","Yong","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǒng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/咏_yǒng.mp3", "歌咏 咏唱 咏叹 佳咏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用诗词等来描述，抒发感情。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"唱，声调有抑扬地念。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指诗词。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84807_妆_22918.gif","6","左右","女","妆","Makeup","http://cdn.ococci.com/dict_ali/2022-02-22/1645533635569399860_3baee122-a273-5252-9731-79a7b57d6423.mp3");
