INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"修饰、打扮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"女子出嫁时陪送的衣物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"供打扮用的物品，演员的衣装服饰。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"修饰，打扮的式样。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90409_丝_19997.gif","5","上下","一","丝","Silk","http://cdn.ococci.com/dict_ali/2022-02-25/1645765760633164539_d2a8fab2-05fb-b53c-9e9b-837884385532.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/丝_sī.mp3", "丝绸 蚕丝 抽丝 粉丝 钢丝 铁丝 蛛丝马迹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细如丝的东西：一只蜘蛛正专心致志地吐丝织网。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形容细微，极小：对待工作，他一丝不苟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蚕丝。蚕吐的像线的东西，是绸缎的原料：丝绸衣服穿着舒适柔软，很受人们喜爱。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/14236_绦_32486.gif","10","左右","纟","绦","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/绦_tāo.mp3", "绦带 丝绦 绦虫,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用丝线编织成的花边或扁平的带子，可以装饰衣物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59039_裁_35009.gif","12","半包围","衣","裁","Cut","http://cdn.ococci.com/dict_ali/2022-02-25/1645766617548750001_7f693892-d707-e939-8fbc-d4b2e6d870bd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cái", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/148/裁_cái.mp3", "制裁 总裁 体裁 裁剪 裁判 裁纸 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用刀、剪等把物体分开：把这张纸对裁一下就行了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"削减：我们主张实行有效的裁军和军控。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文学、艺术方面的取舍：这篇文章的构思别出心裁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"衡量：请法庭做出公正的裁决。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抑制：联合国制裁了伊拉克对科威特的入侵。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/14155_剪_21098.gif","11","上下","刀","剪","Cut","http://cdn.ococci.com/dict_ali/2022-02-25/1645766617548750001_7f693892-d707-e939-8fbc-d4b2e6d870bd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/11/剪_jiǎn.mp3", "剪贴 夹剪 修剪 剪纸 剪彩 剪刀,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"剪刀：她用这把快剪，制作出一幅幅精美的贴花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状像剪刀的东西：小燕子飞呀飞，一把剪子身上背。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"除掉：我们行侠仗义，理应济困扶危，剪恶除奸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用剪刀铰：小小宝帮着把灯心草剪成细末子。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/9327_脱_33073.gif","11","左右","月","脱","Take off","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tuō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/128/脱_tuō.mp3", "脱离 逃脱 超脱 推脱 脱产 脱节,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)取下；除去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)脱离。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)本义：肉去皮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"漏掉(文字)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)〈书〉轻慢。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(连)〈书〉倘若；或许。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)(皮肤、毛发等)脱落。");
