INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代指贤者，特指熟悉掌故的人：文献。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恭敬庄严地送给：奉献。");
