INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/117/糕_gāo.mp3", "糕点 糕饼 年糕 蛋糕 蜂糕,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用各种粉质制成的食品：宋庆龄奶奶拿起刀子，把蛋糕切成了二十四块。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/87848_特_29305.gif","10","左右","牜","特","Te","http://cdn.ococci.com/dict_ali/2022-02-25/1645775358553513041_f8d67ed9-60f4-0cf0-c18f-b3190393d023.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/特_tè.mp3", "特产 特色 特点 特务 特技 模特 特别,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)特殊；超出一般。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(名)指特务。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)〈书〉只；但。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)特地。");
