INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mɑ", "https://ota.aidoor.net/scan_pen/content/audio/d5a08140-a926-11ec-bb89-c147036f73d1.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"助词，表示很明显，事理就是如此：不会不要紧，边干边学嘛。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43293_买_20080.gif","6","上下","乙","买","Buy","http://cdn.ococci.com/dict_ali/2022-02-25/1645767037249712521_3b5434c1-e6d2-c1e0-4326-245fb53d6126.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/买_mǎi.mp3", "购买 买卖 收买 买进 买账 买主 买通,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用金钱收买以达到自己的目的：在旧社会，有钱买得鬼推磨，穷汉子有理无处说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"购进；拿钱换东西。跟“卖”相反：他用平时节省下来的钱买画笔。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37653_粉_31881.gif","10","左右","米","粉","Powder","http://cdn.ococci.com/dict_ali/2022-02-22/1645506318198900906_8d7ce660-a608-c9ee-e2f5-cff469aed374.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fěn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/117/粉_fěn.mp3", "粉丝 粉红 花粉 粉末 粉碎 粉蝶 粉墙 粉刷 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用豆粉或其他淀粉做成的食品，多指粉条：他们心满意足地吃着鱼蛋粥和牛肉炒粉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使破灭：我们成功地粉碎了敌人的四次围剿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"颜色稍微浅、淡：果园里开满了粉红色的桃花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细末状物：变质的奶粉不能食用。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90365_糖_31958.gif","16","左右","米","糖","Sugar","http://cdn.ococci.com/dict_ali/2022-02-24/1645707463097670240_093351d4-cba7-6c29-61af-a4f884413d2b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"táng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/117/糖_táng.mp3", "糖衣 糖瓜 糖果 糖浆 糖精 原糖 蜜糖 水果糖 糖衣炮弹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从甘蔗、米、麦、甜菜等提炼出来的供食用的甜的物质：有一个卖药糖的，他的吆喝很讲究。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有机化合物的一类，分为单糖、双糖和多糖三种，是人体内产生热能的主要物质：糖原存在于动物体内，是动物能量的来源。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/61261_蔗_34071.gif","14","上下","艹","蔗","Sugarcane","http://cdn.ococci.com/dict_ali/2022-02-17/1645103989046751905_f5325d3d-cdbe-27f6-6332-4cd89429ef8a.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/138/蔗_zhè.mp3", "甘蔗 竿蔗 都蔗 噉蔗 啖蔗 竹蔗,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"甘蔗：多年生草本植物，茎直立，有节，含甜汁很多，可生吃。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46036_汁_27713.gif","5","左右","氵","汁","Juice","http://cdn.ococci.com/dict_ali/2022-02-25/1645772276385292577_b7f940ec-a0bf-574f-8bf9-990171014190.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/75/汁_zhī.mp3", "汁液 奶汁 肉汁 豆汁 果汁 胆汁 橘汁 乳汁 墨汁 绞尽脑汁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"含有某种物质的液体：正是枣熟掉枣的时候，满路上都是渍出蜜汁来的红枣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/60327_菜_33756.gif","11","上下","艹","菜","Dish","http://cdn.ococci.com/dict_ali/2022-02-25/1645754315883024480_e41a8bfd-1d1f-259e-6764-3de90f25916d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/135/菜_cài.mp3", "白菜 蔬菜 名菜 饭菜 生菜 油菜 菜花 菜肴,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指经过烹调拿来下饭下酒的一切副食。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蔬菜：他靠种菜而走上了富裕之路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"专指菜油：菜油的食用价值很高。");
