INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“嗷”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"久煮：熬粥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"忍受，耐苦支持：煎～。");
