INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/销_xiāo.mp3", "销毁 销路 销售 供销 销量 撤销,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消融；溶化：阎长宫满肚子的勇气，被郭宗汾的这席话说得冰销云散了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"取消：那些人见吴吉昌不低头，就撤销了他大队长的职务。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"开支，花费：这几年家里花销太大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"出卖货物：他们的一些产品还远销日本、东南亚和美国。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91252_劳_21171.gif","7","上下","力","劳","Lao","http://cdn.ococci.com/dict_ali/2022-02-24/1645705204029328806_485e37e0-912d-4a44-150d-b05dbf9f72e3.mp3");
