INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/应_yìng.mp3", "应酬 应付 应邀 答应 适应 响应,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"顺应；适应：得心应手。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"应付：应接不暇。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"回答：呼应。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"满足要求；允许；接受：有求必应。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yīng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/应_yīng.mp3", "应该 应当 应届 应得 应声 应允 应许,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"该：只要一个人是全心全意去做了他所应做的事情，他就是尽了自己的一份责任。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"允许；答应：这件事我应下来的。");
