INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/168/郊_jiāo.mp3", "郊游 郊区 市郊 荒郊 城郊 郊外,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"城市周围的地方：郊外有一处四面环水的小森林，风景特好。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37940_泛_27867.gif","7","左右","氵","泛","Pan","http://cdn.ococci.com/dict_ali/2022-03-02/1646187347455695069_50acf4c6-1e36-6a31-2540-9ef6fed8e570.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/77/泛_fàn.mp3", "泛滥 泛舟 广泛 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)漂浮：泛舟湖上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)透出；往上冒：脸上泛红。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)广泛，一般。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)泛滥：黄泛区。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85659_波_27874.gif","8","左右","氵","波","Bo","http://cdn.ococci.com/dict_ali/2022-02-25/1645771994850041883_c6583d8b-bdc0-dea9-8718-12e5fa2c1b36.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/77/波_bō.mp3", "波动 波及 波折 微波 奔波 长波 海波,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物理学名词。振动在一定物体或空气中的传播过程，一种能量的形式。如物理学上的声波、光波、电磁波、冲击波等：由隧道弧形反射壁聚集后传播出去的声波被这片云层反射到地面。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水浪：大海里，闪烁着一片鱼鳞似的银波。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻事情的意外变化：小巷里真是一波未平一波又起，忙得她晕头转向。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"影响：他担心这件事会波及到自己。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39147_纹_32441.gif","7","左右","纟","纹","Grain","http://cdn.ococci.com/dict_ali/2022-02-24/1645669454396035883_edf78c4b-09c3-1096-5b69-b314b826bd41.mp3");
