INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/137/葱_cōng.mp3", "大葱 青葱 葱茏 洋葱 倒栽葱,");
