INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"青色：那里原是不毛之地，现在一片葱绿，俨然成为绿洲。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/14289_软_36719.gif","8","左右","车","软","Soft","http://cdn.ococci.com/dict_ali/2022-02-25/1645769274244845051_bbf42e00-7ff5-a273-1901-55fa25613f28.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ruǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/164/软_ruǎn.mp3", "柔软 松软 疲软 酥软 心软 软弱 软和,");
