INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～菜〕一年生或二年生草本植物，叶子略呈三角形，根红色，含甜味，根和茎、叶均可食，〔～萝〕ａ．多年生草本植物。果实密集在一起，外部呈麟片状，果肉甜酸，产于热带；ｂ．这种植物的果实，亦称“凤梨”。");
