INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/155/记_jì.mp3", "记住 记者 记载 记忆犹新 记忆力 记忆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把印象保持在脑子里。把事物写下来。记载事物的书册或文字。符号，标识。古时的一种公文。皮肤上的生下来就有的深色斑。量词，指打一下。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32291_屁_23617.gif","7","半包围","尸","屁","Fart","http://cdn.ococci.com/dict_ali/2022-02-24/1645709767720313623_b3f760e5-1060-be6e-5926-794ea394b8af.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/屁_pì.mp3", "屁事 屁话 屁滚尿流,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从肛门排出的臭气：放屁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指任何事物，相当于“什么”：狗屁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻没用或不足道的事物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/71124_股_32929.gif","8","左右","月","股","Shares","http://cdn.ococci.com/dict_ali/2022-02-24/1645702565592393183_674ca20b-40c4-cc09-18b4-88048a0ad4a1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/127/股_gǔ.mp3", "股份 股东 股票 合股 一股,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大腿：脱却布袴，双股泥污。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。A. 用于成条的东西：这毛线是四股合成的。B. 用于气味：山风一吹，飘起一股青草的香味。C. 用于成批的人（多指匪徒或敌军）：这股敌人化装成山民，隐蔽到丛林里去了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"机关团体：小明的父亲在宣传股工作。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"资金财产中的一份");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/2742_昏_26127.gif","8","上下","日","昏","Dizzy","http://cdn.ococci.com/dict_ali/2022-02-21/1645453979730535729_de136cdd-5b2f-b98b-4a42-aff92431a1a2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hūn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/60/昏_hūn.mp3", "昏暗 昏黄 发昏 昏庸 昏乱 昏君 头昏 昏沉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"光线暗；模糊：无处鸡鸣，但屋内还是有些昏暗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"傍晚；天快黑的时候：每日黄昏的游泛，舟轻如羽。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"失去知觉：与歹徒搏斗时，他流血过多，昏过去了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(目)不明：大娘老眼昏花，耳朵也听不见了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"神志不清：他感到头昏，口里非常渴燥。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/19574_尿_23615.gif","7","半包围","尸","尿","Urine","http://cdn.ococci.com/dict_ali/2022-02-22/1645532122357855458_f2e9a172-5f06-e313-d137-3ebd185c442b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"niào", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/尿_niào.mp3", "尿脬 尿泡 尿尿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排泄小便。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小便，肾脏的排泄液。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"suī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/尿_suī.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"义同“尿(niào)”，小孩子又(niào)了一泡尿(suī)。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/33085_茸_33592.gif","9","上下","艹","茸","Velvet","http://cdn.ococci.com/dict_ali/2022-02-21/1645436345111427808_2a3955c9-3087-fd46-96cd-cffc8aa6bdd8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"róng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/134/茸_róng.mp3", "茸毛 鹿茸 参茸 毛茸茸 绿茸茸,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"草初生纤细柔软的样子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指“鹿茸”（带细毛的才生出来的鹿角，可入药）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细柔的毛、发。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85072_醒_37266.gif","16","左右","酉","醒","Wake up","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xǐng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/170/醒_xǐng.mp3", "醒目 醒事 醒酒 醒眼 醒豁 苏醒 惊醒 觉醒 唤醒 提醒 清醒 猛醒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"明显、清楚：醒目。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指头脑由迷糊而清楚：醒悟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"睡眠状态结束或尚未入睡：如梦方醒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"酒醉、麻醉或昏迷后神志恢复正常状态：醒酒。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10691_晃_26179.gif","10","上下","日","晃","Shake","http://cdn.ococci.com/dict_ali/2022-02-24/1645716750322379084_4c75472e-ad93-7c31-0854-9ad1a1adfa33.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/60/晃_huàng.mp3", "晃荡 晃动 晃悠 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摇动。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/60/晃_huǎng.mp3", "明晃晃 晃眼 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"明亮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"照耀：太阳晃得眼睛都睁不开。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"很快闪过：她在我眼前一晃就不见了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63824_免_20813.gif","7","上下","刀","免","Free","http://cdn.ococci.com/dict_ali/2022-02-24/1645702090886037012_4a4d0c87-da6a-4088-27ac-ff3a7da9fff5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"miǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/免_miǎn.mp3", "免除,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"去掉，除掉；不被某种事物所涉及；不可，不要。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wèn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/8/免_wèn.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物之新生、稚弱者。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代丧服。去冠括发，以布缠头。如：免服（古代丧服）；免袒（古代丧服。袒露左臂，以麻布缠头）；免麻（居丧者，缠麻带于首、腰以示哀）");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46188_费_36153.gif","9","上下","贝","费","Fee","http://cdn.ococci.com/dict_ali/2022-02-25/1645783640298170495_99016cf1-c90f-bf62-d0e1-d859132b5633.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/159/费_fèi.mp3", "费用 公费 费钱 费力 花费 费劲 消费 运费 费解,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"损耗；消耗。跟“省”相对：这种机械太费电了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"费用；经费：他为求生活之费，仆仆奔波。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地名。费县，在山东省。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
