INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"排成一行：罗列。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"名，众：列强。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摆出：列举。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"安排到某类事务之中：列席。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，用于成行列的事物：一列火车。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"类：不在此列。");
