INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/屎_shǐ.mp3", "屎壳郎 耳屎 眼屎,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"粪，大便：猪屎可以喂鱼，也可入肥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"眼、耳等器官的分泌物：这人大概还没洗脸，眼屎还在脸上呢！");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35843_撞_25758.gif","15","左右","扌","撞","Hit","http://cdn.ococci.com/dict_ali/2022-02-25/1645751633243490519_a2e13871-9282-93a4-d063-2cd499ceaaf8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhuàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/56/撞_zhuàng.mp3", "撞击 碰撞 顶撞 冲撞 撞破 撞车 撞见,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"运动着的物体跟别的物体相碰：赵女士转过身去，刚好和正走过来的小王撞个正着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"碰上：不想见他，却偏偏又在路上撞着。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敲；去：俗话说\"当一天和尚撞一天钟\"，你连钟都不撞一下。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54418_贪_36138.gif","8","上下","贝","贪","Greed","http://cdn.ococci.com/dict_ali/2022-02-20/1645358733779120954_04cc5911-7cc8-aaa2-5fa2-ee7a01d820f7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/159/贪_tān.mp3", "贪心 贪杯 贪吃 贪玩 贪污 贪赃 贪图 贪婪 贪财好利,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"纳赃受贿：贪污盗窃、投机倒把、行贿受贿、走私贩毒等犯罪活动严重破坏了社会主义经济建设。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对欲望总不满足：即使是马其诺防线，也是可以被自己的贪欲攻破的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98276_脾_33086.gif","12","左右","月","脾","Spleen","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/脾_pí.mp3", "脾气 脾胃 脾脏 脾性 脾寒 醒脾 健脾 脾胃相投 沁人心脾,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人和动物内脏之一，在胃的左下侧，是重要的贮藏血液的器官和最大的淋巴器官。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中医学指五脏之一。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/56944_婶_23158.gif","11","左右","女","婶","Aunt","http://cdn.ococci.com/dict_ali/2022-02-25/1645761278217546635_bb460cfa-3bdc-c7a8-4ffc-9926d330d3d0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shěn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/31/婶_shěn.mp3", "婶母 婶婆 婶娘 大婶 二婶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对与母亲同辈而年纪较小的妇女的尊称：在我们这条街上，李婶是众所周知的热心人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"叔叔的妻子：四婶不管四叔的皱眉，将她留下了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/4099_陀_38464.gif","7","左右","阝","陀","Tuo","");
