INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"山冈。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"陀螺：一种儿童玩具，呈圆椎形，用绳绕上，然后一拉，使其在地上旋转起来，用鞭抽打旋转不停。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/6706_螺_34746.gif","17","左右","虫","螺","Snail","http://cdn.ococci.com/dict_ali/2022-02-23/1645615506589085086_762e6e6a-648c-92ae-7582-8c1d4dcf28f0.mp3");
