INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qiāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/64/枪_qiāng.mp3", "枪毙 枪弹 枪法 枪杆 枪决 枪杀 枪手 枪械 枪支 刀枪 打枪 黑枪 枪林弹雨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像枪的东西：他拿着焊枪，聚精会神地焊接着裂缝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"口径在两厘米以下、发射子弹的武器，如手枪、步枪、机关枪等：枪一响，连长率先冲了上去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刺杀用的长矛：儿童团员手拿红缨枪站岗放哨。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91654_橡_27233.gif","15","左右","木","橡","Oak","http://cdn.ococci.com/dict_ali/2022-02-24/1645705256382276376_bf3c55e0-a88f-fccd-120c-7f3fd2a5b4b1.mp3");
