INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～树〕即“栎（lì）树”。简称“橡”，如“～子”（橡树的果实）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～胶树〕常绿乔木，枝细长，三个椭圆形小叶构成复叶，开白花，结球形蒴果。简称“橡”，如“～皮”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3843_板_26495.gif","8","左右","木","板","Board","http://cdn.ococci.com/dict_ali/2022-02-25/1645765592179814574_be6502bc-b998-35d1-b74e-80c5f38359b6.mp3");
