INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表情严肃：自打进门来，爸爸就一直板着脸不说话。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结成硬块：农田或花盆里的土壤，常常板结，形成硬壳。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"片状的较硬的物体：窥探舱里，不很分明，她像是捆了躺在船板上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拍板。我国民族乐器中用来打拍子的乐器。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不灵活或少变化：在辞章拙劣的文章中间，人们所读到的永远只是干瘪的词汇，刻板的句法、章法。");
