INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"操纵；驾驭：那时许多县的行政权都由土匪遥控，不少县长也被迫离职。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"告发：有人向罗教廷控告布鲁诺是“异端”。");
