INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"平而宽广：沙漠地区地势平坦，但风力却很强。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"直率；开朗：这是一双清得像泉水似的眼睛，带着惊讶，坦率地看着每一个人。");
