INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。A. 表示并列关系，相当于\"和\"、\"与\"、\"又\"等：这是一项伟大而艰苦的任务。B. 表示转折关系，相当于\"可是\"、\"但是\"、\"然而\"、\"却\"等：他人小而志气大。C. 插在主谓语之间，相当于\"如果\"、\"假如\"等：依靠个人，而不依靠人民大众，历史不可能发展。D. 将前面的目的、对象、原因、依据的状语连接到动词上，与前面的\"为\"、\"因为\"、\"为了\"、\"由于\"等相呼应：千万不要为玩弄技巧而写诗。E. 连接修饰语与动词：为人民利益而死，就比泰山还重。F. 把时间或成分与动词连在一起：在这紧急关头，刘胡兰挺身而出。");
