INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)〈书〉完全。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10444_竟_31455.gif","11","上中下","立","竟","Unexpectedly","http://cdn.ococci.com/dict_ali/2022-02-24/1645707038729616670_26420d96-6c08-565d-a72c-45d040f8d41f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/112/竟_jìng.mp3", "毕竟 究竟 竟日 竟然 竟自 竟到 未竟之业,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"完毕；终了：我们是祖国的未来，父辈未竟的事业，将由我们去完成。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"竟然；出乎意外地：文清吓昏了头，昏沉沉地竟拿着烟枪走出来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"全；自始至终：瑞雪盈墀一尺高，霏霏竟日又连宵。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/5302_映_26144.gif","9","左右","日","映","Ying","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yìng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/60/映_yìng.mp3", "放映 反映 衬映 映射 映现 映山红 掩映 辉映 映带,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"反照，照射而显示：反映。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"照射：映照。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64869_绝_32477.gif","9","左右","纟","绝","Absolutely","http://cdn.ococci.com/dict_ali/2022-02-24/1645663662724143203_8795812e-da82-8a2b-c282-c3b081206c63.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jué", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/绝_jué.mp3", "断绝 绝对 杜绝 绝顶 绝句 绝妙,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"极端：一只普普通通的烟斗便变成了一件绝妙的艺术品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"断：这个认识，使我受到空前绝后的感动。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"杜绝；我实在没有绝她的理由。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"独一无二的；我怎么也没想到，这个老头子还有这么一手绝招儿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"穷尽：革命的火种是不会绝的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧诗体裁之一，绝句。一般分为五绝或七绝：王之涣的《登鹤雀楼》是一首脍炙人口的五绝。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一定：这可绝不是件容易的事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"走不通的；没有出路的：松树不怕高，把根扎在悬崖绝壁的缝隙里。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/51543_鹂_40514.gif","12","左右","鸟","鹂","Oriole","http://cdn.ococci.com/dict_ali/2022-02-14/1644821538025016010_4974a051-89b6-e722-51c0-ea3ae0cb3897.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/202/鹂_lí.mp3", "黄鹂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"黄鹂〕鸟，羽毛黄色，从眼边到头后部有黑色斑纹，嘴淡红色。鸣声动听悦耳。亦称“黄莺”、“仓庚”、“黄鸟”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/12361_鸣_40483.gif","8","左右","鸟","鸣","Ming","http://cdn.ococci.com/dict_ali/2022-02-25/1645774323609264812_5ff85cde-b9b2-7f40-b64c-d735c2367b76.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"míng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/201/鸣_míng.mp3", "鸣谢 雷鸣 鸣笛 鸣锣开道 鸣金收兵 百家争鸣 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸟兽或昆虫叫：露浸衣被夏犹寒，树间唧唧鸣知了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"表达意见、主张等：百家争鸣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"发出声音：泉水和雨水混在一起，顺着斜坡，流进山洞，潺潺的水声变成訇訇的雷鸣。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使物发声：点起我们的火距，鸣起我们的金钲。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/21719_含_21547.gif","7","上下","口","含","Contain","http://cdn.ococci.com/dict_ali/2022-02-24/1645701706196110107_c3e386b8-7eba-a7b6-cd92-38cf33759720.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/15/含_hán.mp3", "含羞 含怒 含笑 含苞 含糊 含蓄 含义 含混 含量,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"藏在里面，包容在里面：她眼含热泪，听妈妈讲她过去的故事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"东西放在嘴里，不吞也不吐出：呷了口汤，觉得恶心，在口中含了半天，才勉强咽了下去。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/2861_岭_23725.gif","8","左右","山","岭","Ridge","http://cdn.ococci.com/dict_ali/2022-02-23/1645590348360831090_4c33ddcc-2ac6-852a-6bd7-d6a57baf105c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lǐng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/37/岭_lǐng.mp3", "岭外 岭南 岭隘 山岭 海岭 分水岭 崇山峻岭,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"上边有路可走的山：红军翻山越岭、长途跋涉最后到达延安。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高大的山脉：瑶山，地图上叫越城岭。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/45237_泊_27850.gif","8","左右","氵","泊","Poo","http://cdn.ococci.com/dict_ali/2022-02-25/1645757326053754300_e43cc515-9128-91c5-c4cf-058f6d22b4fa.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/77/泊_bó.mp3", "停泊 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停船靠岸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"安静。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"停留。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/77/泊_pō.mp3", "湖泊 水泊 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"湖。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98969_压_21387.gif","6","半包围","厂","压","Press","http://cdn.ococci.com/dict_ali/2022-02-25/1645751361021019335_320ad74d-36a9-5884-ced0-0fefc2bd3792.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/14/压_yà.mp3", "压根儿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"压根儿〕根本，从来。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/14/压_yā.mp3", "压板 积压,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"控制，使稳定，使平静：压价。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用威力制服、镇服：镇压。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从上面加力：压住。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"搁置：积压。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"逼近：大兵压境。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赌博时在某一门上下注：压宝。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/18887_蝉_34633.gif","14","左右","虫","蝉","The Cicada","http://cdnmu.gurobot.cn/saodubi/dict/audio/The_Cicada.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/144/蝉_chán.mp3", "蝉联 蝉叫 蝉鸣 蝉蜕 秋蝉 寒蝉 噤若寒蝉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫名，俗称知了：蝉在树上不停地鸣叫。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76413_垂_22402.gif","8","独体","土","垂","Hang down","http://cdnmu.gurobot.cn/saodubi/dict/audio/Hang_down.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chuí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/24/垂_chuí.mp3", "垂下 垂直 垂手 垂线 垂青 垂危 垂死,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬辞，表示对方高于自己：导师在百忙之中还不忘垂询我的论文进展情况。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"物体的一头向下而悬空：春光明媚，垂柳轻拂，一派大好春色。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/4316_哗_21719.gif","9","左右","口","哗","Whoa","http://cdn.ococci.com/dict_ali/2022-02-22/1645539359839607142_7dd94047-8433-ee43-b7b7-efaa8b10f51d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huá", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哗_huá.mp3", "喧哗 哗嚣 哗乱 哗笑 哗然 哗变,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人声嘈杂，喧闹：哗然而骇者。——唐·柳宗元《捕蛇者说》");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浮夸：哗众取宠。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哗_huā.mp3", "哗啦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象声词。形容流水声：顷刻间，雷电交加，哗啦哗啦地下起暴雨来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27850_户_25143.gif","4","独体","户","户","Household","http://cdn.ococci.com/dict_ali/2022-02-25/1645754445168816201_2a7eb000-0e69-7437-ab66-c6be1bfb9300.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/户_hù.mp3", "窗户 户外 户口 户主 农户 住户 账户 用户,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于人家，住户：我们村近百户人家，多数都已住进了小洋楼。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"门第：她看来倒是门当户对。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"门：古人读书，提倡专心致志，足不出户。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在银行存款的户头：随着人民群众收入的增多，银行的存户也越来越多。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人家；住户：他挨家挨户地了解情况。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59568_扑_25169.gif","5","左右","扌","扑","Pow","http://cdn.ococci.com/dict_ali/2022-02-23/1645614627404577240_543840e3-6b47-45d7-77dd-71f2892f8303.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扑_pū.mp3", "扑向 扑打 扑空 扑克 扑灭 扑腾 扑籁 猛扑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"猛力向前冲，使全身突然伏在物体上：小华高兴得一下扑到奶奶怀里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"进攻；解放军直扑敌人的巢穴。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"将所有心思放到学习、工作、事业等上面：周老师一心扑在教学上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"直冲：和风吹来，香味扑鼻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"轻打；轻拍：海鸥扑着翅膀，直冲海空。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76519_乌_20044.gif","4","独体","丿","乌","Wu","http://cdn.ococci.com/dict_ali/2022-02-25/1645767540997153954_f024770d-8311-5cc3-23d9-3cfb5d49eb76.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/wù.mp3", ",");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/乌_wū.mp3", "乌黑 乌云 乌鸦 乌龟 乌江 乌金 乌有 乌鱼 乌头,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"黑色，乌云在移动着，太阳一阵露出来，一阵又藏进去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸟名。乌鸦，俗称老鸹或老鸦：喜鹊报喜，乌鸦惹祸，都是民间迷信传说，并无科学根据。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3697_慌_24908.gif","12","左右","忄","慌","Panic","http://cdn.ococci.com/dict_ali/2022-02-25/1645773028046226797_66e8eb6c-3480-7a2b-b56b-419377891cee.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/慌_huǎng.mp3", "慌荒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"模糊；不真切。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"<方>眯。眼皮微合貌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引申为迷乱。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/48/慌_huāng.mp3", "慌忙 慌乱 慌神 慌张 心慌 发慌 惊慌 恐慌 意乱心慌,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"惊恐；害怕：秦二世得知起义军入关，非常恐慌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"急迫；忙乱：当激情冲动过后，他又不慌不忙地开始讨论问题。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huang", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/慌_huang.mp3", "闹得慌,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用作补语，表示难以忍受。用在闷、闲、困、累、急、烫、愁、咸、闹、烦、干、涩、苦、挤、呛、憋、气、热、堵、难受等词的后面。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36776_辨.gif","16","左中右","辛","辨","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"biàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/辨_biàn.mp3", "辨别 明辨 辨认,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"区分；判别：对上下文中相关的词句的明辨，可以使我们深入地理解作品。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/23312_忠_24544.gif","8","上下","心","忠","Loyalty","http://cdn.ococci.com/dict_ali/2022-02-22/1645483934229835233_013e3acf-023b-f0a2-f580-ef83b33b041d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhōng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/45/忠_zhōng.mp3", "忠心 忠臣 忠孝 忠良 忠直 忠厚 忠信 忠烈 忠诚 忠勇 尽忠 效忠 精忠 竭忠 忠心耿耿 忠言逆耳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"诚心尽力：忠心。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/13900_实_23454.gif","8","上下","宀","实","Reality","http://cdn.ococci.com/dict_ali/2022-02-24/1645697647795241785_ce7738f3-3073-b77f-1c5b-c70fb49ad47d.mp3");
