INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"客观存在的：实际。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"的确：确实。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使成为事实：实现。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"种子，果子：果实。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"施，执行，推行：实施。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"真，诚恳，不狡猾：真实。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于加强语气：实难从命。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"满，充满：这是个实心球。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/86165_导_23548.gif","6","上下","寸","导","Guide","http://cdn.ococci.com/dict_ali/2022-02-24/1645717043291367104_d038773b-5829-9f40-4822-9c61c6e17868.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/导_dǎo.mp3", "领导 导航 导体 开导 引导 传导 导论 导游 倡导 主导,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"传导：这条线导电，得小心检测。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"开导：马克思、恩格斯、列宁、斯大林教导我们认真地研究情况，从客观的真实的情况出发。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指此：这里人民的热情，还没有导入集体行动的洪流，这是憾事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引导：电线老化是这场火灾的导火线。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99094_盏_30415.gif","10","上下","皿","盏","Lamp","http://cdn.ococci.com/dict_ali/2022-02-25/1645764475553667927_d45d5fd4-750f-b4b0-5255-c444a1aab57b.mp3");
