INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指油灯盛油的浅盆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小杯子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，指灯。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/95723_永_27704.gif","5","独体","水","永","Yong","");
