INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水流长：“江之永矣”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"久远：永远。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“咏”，以诗词等来叙述。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/61647_闯_38383.gif","6","半包围","门","闯","Chuang","http://cdn.ococci.com/dict_ali/2022-02-21/1645448564599892261_934d749f-3b7a-a41d-8b84-773a3f3cc454.mp3");
