INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"猛烈冲击：山风在峡谷中呼啸着直闯过来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闯荡：他在江湖上闯荡了多年，颇有经验。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"招来，惹来：他老爱闯祸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30896_碰.gif","13","左右","石","碰","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/碰_pèng.mp3", "碰见 碰杯 碰壁 碰倒 碰到 碰巧 碰头 磕磕碰碰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)");
