INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多而密：这个县地窄人稠，制约了经济的发展。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"液体中所含的固体成分多：这稀饭熬得很稠。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50301_稀_31232.gif","12","左右","禾","稀","Thin","http://cdn.ococci.com/dict_ali/2022-02-25/1645773708298949094_40f9e491-87a2-51c3-49cc-b46673c6fcf7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/110/稀_xī.mp3", "稀少 稀薄 古稀 依稀 稀烂 稀疏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"少：稀少。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用在“烂”、“松”等形容词前面，表明程度深：稀烂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浓度小，含水分多的，与“稠”相对：稀薄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物中间距离远、空隙大，与“密”相对，稀疏。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/28192_渠.gif","11","上下","氵","渠","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/渠_qú.mp3", "渠道 渠魁,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水道，特指人工开的河道或水沟：渠道。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大：渠帅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言，他：渠侬。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"车辋，古代车轮的外圈");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55543_积_31215.gif","10","左右","禾","积","Product","http://cdn.ococci.com/dict_ali/2022-02-25/1645760674635053406_325f0694-631b-fc87-d8ff-63e2be0ced02.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/110/积_jī.mp3", "积肥 积极 积累 积木 积攒 沉积 乘积 容积 面积,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"聚集；累积：老两口儿省吃俭用，用积下的钱买了一套房子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"堆子；垛子：他决计从那里拿一株带火的大树来点芦柴积。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"长时间形成的：不料积习又从沉静中抬起头来，写下了以下那些字。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数学名词：2乘3的积是6。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64988_航_33322.gif","10","左右","舟","航","Hang","http://cdn.ococci.com/dict_ali/2022-02-24/1645716075693929564_65428d85-0b2f-1761-73ad-2bcfff6b86d9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"háng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/131/航_háng.mp3", "航行 航标 护航 民航 宇航 起航 航海 巡航,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在水中或空中行驶：这艘万吨巨轮即将远航。");
