INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古往今来所有的时间：宇宙。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/6552_稳_31283.gif","14","左右","禾","稳","Steady","http://cdn.ococci.com/dict_ali/2022-02-24/1645700592428296965_5f97b4c1-7e55-68c3-5114-4e4d37f71041.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wěn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/111/稳_wěn.mp3", "稳定 稳重 平稳 稳固 稳当 沉稳 安稳 稳步 稳健,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稳固；不易移动或变化：他想他在这儿原是稳如泰山的，谁敢动他?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"使稳定：你一定要把局面稳住。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有分寸：那青年坐在炕边上，笑着点点头，显得又稳重，又自信。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有把握；准确可靠：不是十拿九稳的事我从不去做。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/44267_固_22266.gif","8","全包围","囗","固","Solid","http://cdn.ococci.com/dict_ali/2022-02-21/1645451786980336825_0cbe88c6-11aa-778a-b3ba-ab3195f98d63.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/固_gù.mp3", "固然 固守 固执 固有 加固 牢固 顽固 坚固 固定,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坚固；稳定(指地形险要)：阎锡山吹嘘的固若金汤的城防，被撕裂开几个大口子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"原来；本来：各个天体按照自然界固有的规律都有自己起源与发展的历史。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"结实：防洪指挥部再三强调，河堤该加高的要加高，该加固的要加固。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坚强地。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/69974_舱_33329.gif","10","左右","舟","舱","Cabin","http://cdn.ococci.com/dict_ali/2022-02-25/1645768619946572401_41c4ffd3-0a8b-b6da-d158-d726754f5f83.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/131/舱_cāng.mp3", "舱房 舱位 机舱 货舱 船舱 前舱,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"船或飞机中隔开用来装人或装东西的部分：船主将舱收拾得干干净净的。");
