INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bēi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/63/杯_bēi.mp3", "酒杯 茶杯 杯子 奖杯 烧杯 银杯 碰杯 玻璃杯,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"盛酒、水、茶等的器皿。");
