INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/72691_饮_39278.gif","7","左右","饣","饮","Drink","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yìn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/190/饮_yìn.mp3", "饮马 饮牛,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"给马、牛等牲畜喝水：饮牛。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/190/饮_yǐn.mp3", "饮水 饮恨 饮料 饮弹 饮食 饮泣 冷饮 畅饮 痛饮 豪饮 酣饮 饮水思源,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喝：动物需要饮水，这不过是一种无意识的本能。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"饮料：这家商店夏天专卖冷饮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"含；存：他父亲是在一场冤案中饮恨死去的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10793_件_20214.gif","6","左右","亻","件","Pieces","http://cdn.ococci.com/dict_ali/2022-02-25/1645763442539996892_27fd4208-9265-89f3-b3b0-f5b6ce7dc92f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/2/件_jiàn.mp3", "工件 部件 软件 文件 物件 元件 条件,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指可以计算的事物：这台车床专门加工精密配件。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文件：这份急件速送市府办公厅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。用于个体事物：秦始皇陵兵马俑、人物俑每件高两米，个性鲜明，形态逼真。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/78930_题_39064.gif","12","左右","页","题","Question","http://cdn.ococci.com/dict_ali/2022-02-25/1645773287275508797_fa43b330-7f47-f577-eb80-dbca2101bb45.mp3");
