INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"写作、讲演等的总名目：题目。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"练习、考试等要求解答的问：问题。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"评议：品题。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"写上，签署：题名。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/47489_密_23494.gif","11","上下","宀","密","Secret","http://cdn.ococci.com/dict_ali/2022-02-25/1645755272516101022_a84bb377-6965-13dc-d3fb-818bce678ac8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/34/密_mì.mp3", "密切 浓密 精密 严密 泄密 密布 密集 秘密,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物之间距离近；间隔小，跟\"稀\"或\"疏\"相对：语汇联系人们的生活最为紧密，因而变化最快，最显著。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闭藏；封闭：她给了我一盒密封的甜汁。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"贴近；亲密：姚家有个极密的内亲，叫周少溪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稳秘；秘密：事情要密些，倘若声张起来，不是玩儿的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"周密；精细：精密观察，料事如神。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75168_浴_28020.gif","10","左右","氵","浴","Bath","http://cdn.ococci.com/dict_ali/2022-02-24/1645717418896384979_78fcaa0f-7607-cbc0-29a9-7fb28db91f7e.mp3");
