INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/13/博_bó.mp3", "赌博 渊博 广博 物博 博爱 博大 博古通今 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"获取；得到：他在想怎样才能博得来宾和同学们的称赞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大；多；丰富：唐文化博大精深。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"渊博；知道得多：三味书屋的先生是一位学问渊博的宿儒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代的一种棋戏，后泛指赌博：昨天晚上，警方破获了一赌博团伙。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84564_馆_39302.gif","11","左右","饣","馆","Museum","http://cdn.ococci.com/dict_ali/2022-02-25/1645766155577994040_0c14bf95-2df8-c69f-bb76-acf707f781eb.mp3");
