INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接待客人的房屋：中国乒乓球队队员下榻在本市最好的宾馆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"商店：吃完饭后，两人还到照相馆去照了相。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文化活动：北京图书馆是中国最大的图书馆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一个国家的外交人员在另一个国家常驻的地方：大使馆馆舍不可侵犯。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/96389_览_35272.gif","9","上下","见","览","View","http://cdn.ococci.com/dict_ali/2022-02-25/1645749729529680337_470192b4-a2d3-8704-bf93-86291060c5de.mp3");
