INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"看；观赏：车站最高跨两省，览尽蜀水秦云。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"阅读：即使与专业毫无关系的书，他也要浏览。");
