INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"警戒、防守、巡逻的岗位：西沙群岛是我国的海防前哨。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用口或笛吹出的尖叫声：孩子们兴奋地跳着，跑着，尖声地打着唿哨。");
