INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"医治：他受了伤，我自然要想法子替他诊好的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"号脉察视；判断病情：结论要等今天专家会诊后才知道。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"整治：最好把那个兔崽子也诊他一诊，给他点王法看看。");
