INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细长的棍子：小猫放下钓鱼竿就去捉蜻蜓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/70166_舞_33310.gif","14","上下","夕","舞","Dance","http://cdn.ococci.com/dict_ali/2022-02-25/1645771537783878121_496b863a-7ff3-7d32-cb07-19a72d84c49e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/131/舞_wǔ.mp3", "跳舞 舞蹈 歌舞 舞姿 舞剑 舞弊 舞伴 舞场 舞池,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"耍弄：写碑的人偏要舞文弄墨，短短几行字，用了一整天。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跳舞；表演舞蹈：寂寞嫦娥舒广袖，万里长空且为舞。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"舞蹈。以经过组织和美化的人体动作来反映生活，表达思想感情的一种艺术。这歌舞为人民群众喜闻乐见。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挥动；摇动：张阿新站在一个垃圾堆上舞着臂膊狂呼。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91824_痛_30171.gif","12","半包围","疒","痛","Pain","http://cdn.ococci.com/dict_ali/2022-02-24/1645706841497600450_70dafa84-c42c-1d09-8ffe-b411b6d4b468.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/100/痛_tòng.mp3", "痛苦 疼痛 痛楚 痛快 痛切 沉痛 痛斥 痛处 痛恨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疾病、创伤等引起的难受的感觉：头痛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悲伤：悲痛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"尽情地，深切地，彻底地：痛击。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91140_烦_28902.gif","10","左右","火","烦","Annoying","http://cdn.ococci.com/dict_ali/2022-02-25/1645760968614868798_8ce30e9a-7cc6-54be-ec28-57f1a6590cf6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/87/烦_fán.mp3", "烦恼 麻烦 烦闷 烦躁 心烦 烦琐 烦杂 腻烦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬辞。表示请；托：烦你带个口信给我家。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"苦闷；不愉快；不平静：鲁家现在才吃完晚饭，每个人的心情都很烦。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多而乱：这本书要言不烦，百读不厌。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32689_店_24215.gif","8","半包围","广","店","Store","http://cdn.ococci.com/dict_ali/2022-02-25/1645762950836304539_c45eedf2-6791-dc9f-5780-b78d128f5e65.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"diàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/店_diàn.mp3", "店主 店员 店铺 分店 书店 饭店 客店 旅店 商店,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"客栈：由贝聿铭大师设计的香山饭店，素雅、纯净。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"买卖货物的场所：村里只有一家很小的杂货店。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/63442_蹲_36466.gif","19","左右","足","蹲","Squat","http://cdn.ococci.com/dict_ali/2022-02-12/1644636416952324845_bcb3b33e-2df7-bc34-11b3-695307d44d8c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cún", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹲_cún.mp3", "蹲蹲 蹲脚,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"[方]腿、脚猛然落地，因震动而受伤：蹲了腿");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"[蹲蹲]，行为稳重而合乎礼节：遂臻阴宫，穆穆肃肃，蹲蹲如也。——《汉书》；[蹲蹲]，丛聚茂密的：荆棘郁蹲蹲。——南朝宋·鲍照《拟行路难十八首》。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dūn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹲_dūn.mp3", "蹲点 蹲班 蹲苗 蹲点跑面,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"虚坐，两腿弯曲如坐，而臀部不着地：一个年轻人正蹲在桌边翻看杂志。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻闲居或呆着：这么大热天的，你一个人蹲在家里做什么?");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10009_寂_23490.gif","11","上下","宀","寂","Silence","http://cdn.ococci.com/dict_ali/2022-02-23/1645603974518685910_5c3c133c-dbd2-e288-a020-b43050d31ca4.mp3");
