INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"a、扬糠除秽、清理垃圾的器具，用竹篾、柳条或铁皮制成，三面有边沿，一面敞口；ｂ、簸箕形的指纹。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǒ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/116/簸_bǒ.mp3", "簸谷 颠簸 簸动,");
