INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32632_箕_31637.gif","14","上下","竹","箕","A dustpan","http://cdnmu.gurobot.cn/saodubi/dict/audio/A_dustpan.mp3");
