INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88902_璃_29827.gif","14","左右","王","璃","Glass","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647481202751.mp3");
