INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔玻璃〕a.一种质地硬而脆的透明物品，一般用细纱、石灰石、碳酸钠等混合起来，加高温熔解，冷却后制成，主要成分是二氧化碳、氧化钠和氧化钙。b.俗称某些透明的像玻璃的质料，如“玻璃丝袜”（“璃”读轻声）。");
