INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57111_纪_32426.gif","6","左右","纟","纪","Ji","http://cdn.ococci.com/dict_ali/2022-02-25/1645759529938409884_c27784eb-d03e-1379-09a5-fc65b332396b.mp3");
