INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"纪律：这种腐败行径，是党纪国法所不容的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用于\"纪年、纪元、纪传、纪念\"等：今天是辛亥革命60周年的纪念日。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"记年的单位。古代以12年为一纪，今以一百年为一世纪：几个世纪后，造纸术传到了朝鲜、日本、印度和阿拉伯。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"划分地质年代分散的单位，次于\"代\"。一代包括若干纪，如寒武纪、石炭纪、侏罗纪等；在纪的年代里形式的地层叫\"系\"，如寒武系、奥陶系等。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/纪_jǐ.mp3", ",");
