INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64674_钩_38057.gif","9","左右","钅","钩","Hook","http://cdn.ococci.com/dict_ali/2022-02-24/1645702692662739206_ca64a4bd-a7d3-3856-1a98-d4e3f2976698.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gōu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/钩_gōu.mp3", "钩边 钩子 衣钩 吊钩 挂钩 挠钩 秤钩 钩针,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用钩子挂住：他一不小心被路旁的树枝钩住了衣服。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事先设下的圈套：如果当时我们上了他的钩，就会被迫进入他们的集团。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用带钩的针编织：这条围巾是她亲手钩织的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悬挂器物的器具：我们把蚯蚓掘来穿在铜丝做的小钩上。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/1563_铲_38130.gif","11","左右","钅","铲","Shovel","http://cdn.ococci.com/dict_ali/2022-02-19/1645258276233272224_281f2ed3-bbe7-35d9-c8e4-29189df414b8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/铲_chǎn.mp3", "铲除 铲煤 铁铲 锅铲,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"清除；撮取：用铁锹把他铲平。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种铁制的工具，像平板或簸箕，带长把：我在商店里买了一把锅铲。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99287_梅_26757.gif","11","左右","木","梅","May","http://cdn.ococci.com/dict_ali/2022-03-17/5423641000000194_1647481218387.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"méi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/梅_méi.mp3", "梅花 腊梅 梅树 杨梅 刺梅 梅花鹿 梅雨 梅子,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"节候名称。初夏时节，江、淮流域的雨季较长，正值梅子黄熟时期，故称这时期为\"梅雨时节\"。又因这时期空气潮湿，器物易霉，故又称\"霉雨时节\"：上海刚刚出梅，即连日大热。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"梅树。落叶乔木，耐寒，叶子卵形，早春开花，花以白色、淡红色为主，气味清香，品种多果实叫\"梅子\"，成熟后由青转黄，味酸可食，也可加工成蜜饯和果酱等。未熟果可加工成乌梅，供药用：园林中几株松、梅格外招人喜爱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"梅树结的果实：用梅子制成的酸梅汤，具有清热消暑、解渴等功效。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/31545_柿_26623.gif","9","左右","木","柿","Persimmon","http://cdn.ococci.com/dict_ali/2022-02-19/1645257990319736300_810bf4de-b4ee-c151-1a07-cb6ebe234bc0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/柿_shì.mp3", "柿子 柿饼,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"落叶乔木，果实为扁圆形或圆椎形浆果，黄或橙红色，可食：～子。～饼。～霜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/14259_源_28304.gif","13","左右","氵","源","Source","http://cdn.ococci.com/dict_ali/2022-02-25/1645720810737852605_78ca6408-b261-ebc5-db28-cb8f9a7fa75e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yuán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/81/源_yuán.mp3", "源泉 源流 发源 来源 起源 河源 资源 病源 本源 根源 能源 渊源 源源不断 源远流长 左右逢源,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水流开始的地方：据文字记载，\"难老泉\"是晋水的主要源头。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"事物的根由：肥沃的田地，给我们衣食之源。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/37117_涨_28072.gif","10","左中右","氵","涨","Up","http://cdn.ococci.com/dict_ali/2022-02-25/1645769167511757668_89b87aa9-4665-0ce8-9c6d-0cea730561d9.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/79/涨_zhàng.mp3", "涨红,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"体积增大：豆子泡涨了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因情绪激动致面部充血：他涨红了脸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多出来：涨出十块钱。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/79/涨_zhǎng.mp3", "涨价 涨落 涨溢 涨潮 飞涨 上涨 升涨 暴涨 高涨 初涨 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水位升高：外面的河涨了水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"价格提高：今年的物价比较稳，没有涨。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/96536_炬_28844.gif","8","左右","火","炬","Torch","http://cdn.ococci.com/dict_ali/2022-02-19/1645255352491512982_c79e90f4-2bf1-1ca0-069c-84e676b2c1c3.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/87/炬_jù.mp3", "炬烛 炬炭 炬焰 火炬 蜡炬 目光如炬 付之一炬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"火把：晚上要举行火炬游行。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30930_灿_28799.gif","7","左右","火","灿","Chan","http://cdn.ococci.com/dict_ali/2022-02-25/1645760758826588653_c8c90d5e-b6b4-038c-6432-2d06a5e09bc0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"càn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/86/灿_càn.mp3", "灿烂 灿然 光灿灿 金灿灿 灿烂辉煌,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"光彩鲜明：灿烂的阳光洒满校园。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/78744_垮_22446.gif","9","左右","土","垮","Collapse","http://cdn.ococci.com/dict_ali/2022-02-23/1645618545478916162_653c50b6-c0db-5e07-c0fe-fd54e74ed72d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/24/垮_kuǎ.mp3", "垮台 打垮 冲垮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"坏：不要把身体给累垮了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"倒塌，崩溃：洪水再大也冲不垮这坚固的大坝。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/21511_坟_22367.gif","7","左右","土","坟","Grave","http://cdn.ococci.com/dict_ali/2022-02-25/1645757554617646238_cd5be712-38de-14e4-bfa4-e586acb4a353.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fén", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/23/坟_fén.mp3", "古坟 上坟 坟墓 坟头 坟地 土坟 祖坟,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"“三坟”的简称(三坟、五典泛指古代典籍)：章炳麟《再与刘光汉书》：自顷车舟张，退息坟典，匈(胸)怀相契，独有黄生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"埋葬死人筑起的土堆：他手上托着军帽，站在战友的坟前默哀。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/69418_坝_22365.gif","7","左右","土","坝","Dam","http://cdn.ococci.com/dict_ali/2022-02-25/1645746805826891312_aea1a074-764e-288e-d317-a29929194839.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/23/坝_bà.mp3", "堤坝 大坝 丁坝 顺坝 坝基 坝埽 坝趾,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"截住河流的建筑物。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90190_汉_27721.gif","5","左右","氵","汉","Han","http://cdn.ococci.com/dict_ali/2022-02-25/1645769822705217976_a557bba6-a5e8-d954-88ee-38eec095b5a7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/75/汉_hàn.mp3", "好汉 英雄汉 男子汉 大汉 硬汉 醉汉 庄稼汉 汉奸 汉族,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指天河：万木霜天红烂漫，天兵怒气冲霄汉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"男人，男子：我看见过去穷苦的庄稼汉，现在成了致富的能手。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水名。指汉水，源出陕西南部，下流到汉口入长江。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"汉族：这里居住着汉、藏、蒙各个民族。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"汉语的简称：他买了一本英汉词典。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"朝代名。公元前206ー公元220年，刘邦所建。公元前206年刘邦灭秦，前202年称帝，国号汉。公元前206ー公元25年，自刘邦称帝到刘玄更始三年止，史称西汉或前汉。建都长安。公元25ー220年，自光武帝刘秀建武元年到献帝刘协延康元年止，史称东汉或后汉。建都洛阳。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代国名。A. 蜀汉，三国之一。公元221ー263年。公元221年刘备在成都称帝，国号汉。B. 五代之一。公元947ー950年。公元947年，刘知远在太原称帝，建都汴(今河南开封)，国号汉。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85379_艳_33395.gif","10","左右","色","艳","Yan","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/艳_yàn.mp3", "艳丽 浓艳 鲜艳 红艳  明艳 娇艳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"色彩鲜亮明丽：有了这场春雨，花会开得更艳，香会蓄得更浓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"羡慕：艳羡");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧时指关于爱情方面的：鸳鸯蝴蝶派的作家都擅长写艳情小说。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54548_扮_25198.gif","7","左右","扌","扮","Dress up","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扮_bàn.mp3", "扮演 打扮 装扮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"化装成(某种人物)：传说她扮做男孩子，在满洲军队里做冒险的士兵工作。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(通过化装等方式)改变面部容貌：你别扮鬼脸吓唬他！");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/74644_扬_25196.gif","6","左右","扌","扬","Young","http://cdn.ococci.com/dict_ali/2022-02-25/1645771821602410084_664ade4b-72bf-4b6d-dd05-b61f5333b085.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扬_yáng.mp3", "表扬 发扬 飞扬 激扬 颂扬 宣扬 赞扬 扬长避短 导扬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高举，向上：～手。～帆。趾高气～。～眉吐气。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在空中飘动：飘～。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"簸动，向上播散：～水。～场。～汤止沸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"称颂，传播：～言。～威。颂～。～弃。～名。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48499_读_35835.gif","10","左右","讠","读","Read","http://cdn.ococci.com/dict_ali/2022-03-17/5423671000000086_1647505157891.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/读_dú.mp3", "读书 阅读 朗读 读音 读报 读物 攻读 借读 宣读,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"依照文字念：～数。～经。～书。宣～。朗～。范～。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"看书，阅览：阅～。速～。默～。～者。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"求学：走～。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"字的念法：～音。～破。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/读_dòu.mp3", "句读,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧指文章里一句中间念起来要稍稍停顿的地方：句～。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/66401_摔_25684.gif","14","左右","扌","摔","Fall","http://cdn.ococci.com/dict_ali/2022-02-25/1645762764110730097_608c0568-7511-ef70-4707-2e4855c4af64.mp3");
