INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"掉下：花瓶摔坏了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跌倒：摔倒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用力扔：他把书往桌上一摔。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/16842_跤_36324.gif","13","左右","足","跤","Fall","http://cdn.ococci.com/dict_ali/2022-02-25/1645762764110730097_608c0568-7511-ef70-4707-2e4855c4af64.mp3");
