INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/凤_fèng.mp3", "凤藻 凤毛麟角 凤凰衣 凤凰,");
