INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/89701_洁_27905.gif","9","左右","氵","洁","Jai","http://cdn.ococci.com/dict_ali/2022-02-24/1645700918888481474_8155c106-db12-137c-664b-adb383f8891d.mp3");
