INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高傲；自高自大，轻敌自傲。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88777_君_21531.gif","7","半包围","口","君","Jun","http://cdn.ococci.com/dict_ali/2022-02-24/1645714578269876335_6f2692a4-370c-9694-8b49-c270321f633a.mp3");
