INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"封建时代指帝王、诸侯等：明日酿到他弑父弑君，你们才不劝不成?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬词。后死诸君多努力，捷报飞来当纸钱。");
