INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"橙树结的果实。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"红和黄混合的一种：这套沙发是橙色的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"果树名。常绿乔木或灌木，叶椭圆形，果实圆形，果皮红黄色，汁多，味酸甜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/83167_橘_27224.gif","16","左右","木","橘","Tangerine","http://cdn.ococci.com/dict_ali/2022-02-23/1645620122872732346_f3d94668-4de9-0082-8703-77ce4f1642cd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/71/橘_jú.mp3", "橘子 橘柑 橘膛 柑橘 蜜橘,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"橘树。常绿乔木，春末夏初开花，果实为红黄色的扁球，味酸甜不一，可食，果皮、种子、树叶可入中药：雾为柑橘创造了一个舒适的生活环境。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73251_洼_27964.gif","9","左右","氵","洼","Depression","http://cdn.ococci.com/dict_ali/2022-02-24/1645693894339150821_9948881f-2d7d-00e4-1362-9bd98e442236.mp3");
