INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"低凹，深陷：洼地。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凹陷的地方：水洼儿。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/92915_印_21360.gif","5","左右","卩","印","Seal","http://cdn.ococci.com/dict_ali/2022-02-25/1645765352685845995_bb24a9be-2bd3-4445-513a-87115a6361dd.mp3");
