INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"图章：这个证件没盖钢印。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"痕迹：雪地里全是野鹿的脚印。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用油墨、染料之类把文字或图画留在纸、布、器皿等材料上：我国的人民币纸币印有五个民族的文字。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"彼此符合：甲骨文里的有些内容可以和《史记》相印证。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/76253_凌_20940.gif","10","左右","冫","凌","Ling","http://cdn.ococci.com/dict_ali/2022-02-25/1645771981864015211_8b8b7f8b-fbc8-ab5c-cc5a-4c584b9c0323.mp3");
