INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"棕榈叶鞘的纤维，简称“棕”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物，体大，毛棕褐色。掌和肉可食，皮可制皮褥，胆可入药。亦称“马熊”、“罴”；通称“人熊”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"常绿乔木，茎直立不分枝，叶大，木材可制器具，通称“棕树”。");
