INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指身体的某一部分弯曲：母亲们勾着背、跛着脚，牵着牛羊和驴子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"钩形物：他用一只脚勾来张板凳，顺势坐下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"引起：看到这一切，勾起了自己辛酸的事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"删除或截取：他随手抓起一支笔，将钱、桂二人的名字勾去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"粘糊：出去弄了一些玉米面，勾了一锅玉米糊。");
