INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～叭〕a.一种管乐器，铜制。b.喇叭筒状，有扩音作用的东西。〔～嘛教〕佛教的一派，传播于中国藏族、蒙古族地区。〔～嘛〕中国藏语，喇嘛教的僧人，原意“上人”、“师傅”。");
