INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"扁平物体上下两个面的距离。扁平物体上下两个面距离较大的，与“薄”相对。深，重，，浓，多。不刻薄，待人好。重视，推崇。姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/71874_曲_26354.gif","6","独体","曰","曲","Qu","");
