INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"歌的乐调：曲调。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"能唱的文词，一种艺术形式：曲艺。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/62/曲_qū.mp3", "曲解 曲线,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弯转，与“直”相对：弯曲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"酿酒或制酱时引起发醇的东西：酒曲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弯曲的地方：河曲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不公正，不合理：曲说。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"偏僻的地方：乡曲。");
