INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鹦鹉。也叫“鹦哥”。头部圆，上嘴大，下嘴短，呈弯钩状，羽毛美丽，有白、赤、黄、绿等色。生活在热带树林、吃果实。舌圆而柔软，能模仿人说话。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75400_鹉_40521.gif","13","左右","鸟","鹉","","");
