INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸟名。鹦鹉，又称\"鹦哥\"，头部圆，上嘴长而弯曲，下嘴短，舌圆而柔软，能模仿人说话的声音。多生活在热带或亚热带森林。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57890_悄_24708.gif","10","左右","忄","悄","Quiet","http://cdn.ococci.com/dict_ali/2022-02-25/1645766856104336815_1fb4c8c1-a8ee-1bdb-8131-586c8d75b517.mp3");
