INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/8934_蝌_34636.gif","15","左右","虫","蝌","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/144/蝌_kē.mp3", "蝌蚪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蛙、蟾蜍、蝾螈等两栖动物的幼体。黑色，椭圆形，像小鱼，有鳃和尾巴。生活在水中，用尾巴运动，逐渐发育生出前后肢，尾巴渐短至消失，最后变成成体：许多小朋友都喜欢听\"小蝌蚪找妈妈\"的童话故事。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94101_蚪_34474.gif","10","左右","虫","蚪","Pole","http://cdn.ococci.com/dict_ali/2022-02-25/1645753280884282147_21652388-13d4-f84a-ecb8-9d00cd0f77b6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/142/蚪_dǒu.mp3", "蝌蚪,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蝌蚪。蛙或蟾蜍的幼体。黑色，体椭圆，有长尾，生活在水中，逐渐发育生出前肢和后肢，尾巴消失，最后变成蛙或蟾蜍：一群群小蝌蚪在水里游来游去。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/46297_蛾_34558.gif","13","左右","虫","蛾","Moth","http://cdn.ococci.com/dict_ali/2022-02-24/1645699130159914613_98283002-c1a0-1ced-b2a0-cefaa992d356.mp3");
