INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"昆虫，与蝴蝶相似，体肥大，触角细长如丝，翅面灰白，静止时，翅左右平放，常在夜间活动，有趋光性。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/10001/yǐ.mp3", ",");
