INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/197/鲤_lǐ.mp3", "鲤簰 鲤子 鲤庭 乘鲤 赪鲤 鲈鲤 赤鲤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鲤鱼：生活在淡水中，体侧扁，嘴边有长短触须各一对，肉可食。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鲤庭：指受父训之处，亦借指父训。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"书信的代称，因中国唐代传递的书信以尺素结成双鲤鱼形。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/24173_鲫_40107.gif","15","左右","鱼","鲫","Crucian carp","http://cdnmu.gurobot.cn/saodubi/dict/audio/Crucian_carp.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/198/鲫_jì.mp3", "鲫鱼 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(名)鲫鱼，身体侧扁，头部尖尾部较窄，生活在淡水中是常见食用鱼。");
