INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鱼名，有的种类头上有一喷水孔，性凶猛，捕食其他鱼类。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"也作“沙鱼”，又叫“鲛”。");
