INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"草本植物，种类很多，有“大麻”、“苎麻”、“苘麻”、“亚麻”等。茎皮纤维通常亦称“麻”，可制绳索、织布：麻袋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指“芝麻”：麻油。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"感觉不灵，或丧失感觉，引申为思想不敏锐：麻醉");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像腿、臂被压后的那种不舒服的感觉：脚麻了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"面部痘瘢，引申指物体表面粗糙：麻子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"带细碎斑点的：麻雀。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻纷乱：麻乱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
