INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"miǎo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/110/秒_miǎo.mp3", "秒表 秒针 分秒 分秒必争,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弧和角的计算单位，六十秒为一分，六十分为一度。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计算时间的最小单位：真正有理想的人，必定珍惜一分一秒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经纬度的计算单位，六十秒为一分。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/4999_陈_38472.gif","7","左右","阝","陈","Chen","http://cdn.ococci.com/dict_ali/2022-02-25/1645765850431323279_fb6e265b-8803-2f80-fbcd-6a71af23df79.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chén", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/182/陈_chén.mp3", "陈设 陈规 陈旧 陈列,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旧。与\"新\"相对：小王的发言完全是陈词滥调。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"摆放：卧室里陈列着整齐的家具和一些日常生活用品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"时间久远的：这是一坛陈年老酒。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90292_曼_26364.gif","11","上中下","曰","曼","Man","http://cdn.ococci.com/dict_ali/2022-02-25/1645773105450849485_ce388b3b-8b8d-ba38-1f29-c588f920e02c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"màn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/62/曼_màn.mp3", "曼声 曼延 曼妙 曼靡 曼谷,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"美，柔美。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"长，延长。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/61566_联_32852.gif","12","左右","耳","联","Couplet","http://cdn.ococci.com/dict_ali/2022-02-24/1645707520001149213_df9efa5e-11b1-653f-ef90-69b33c9199d8.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lián", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/126/联_lián.mp3", "联合 对联 联盟 联系 联络 春联 联欢 联邦 联结,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"春节将至，家家门上都贴上了春联。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"联结，结合：刘备采纳了诸葛亮联孙抗曹的建议。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连接：远处看去，天地已经联成一线。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27165_缸_32568.gif","9","左右","缶","缸","Cylinder","http://cdn.ococci.com/dict_ali/2022-02-18/1645189811451615952_cc15b6b9-b51c-2f70-e91e-af45af234405.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/缸_gāng.mp3", "水缸 酒缸 汽缸 大缸 鱼缸 缸子 浴缸 缸盖,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形状像缸一样的器物：他平时很不注意小节，抽完烟后烟头不放进烟灰缸里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"底小口大，一般用陶、瓷制成的盛东西的器物：花园里假山下面有一口大水缸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/17172_粱_31921.gif","13","上下","米","粱","Liang","http://cdn.ococci.com/dict_ali/2022-02-24/1645694912497299389_c2ca0d48-52de-fd01-6d81-d1d03e0cc067.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/117/粱_liáng.mp3", "高粱 黄粱一梦,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈古〉指粟的优良品种，视为美食。与膏（肥肉）并称：粱膏美酒。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"[高粱]一年生草本，杆高。子实供食用或酿酒，杆可造纸、编席等。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99347_顿_39039.gif","10","左右","页","顿","Dun","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dùn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/187/顿_dùn.mp3", "顿时 安顿 整顿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)略停：顿了一下。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)跺(脚)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)处理、安排。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(副)忽然、立刻。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(动)叩(头)。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)疲乏。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(量)表示次数：一天三顿饭。");
