INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"鸳鸯：水鸟，比鸭小，栖息于池沼之上，雌雄常在一起。民间传说和文学上用来喻夫妻。又用来称成偶的东西，如“鸳鸳剑”。简称“鸳”，如“鸳侣”（喻夫妻）。");
