INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恩惠；好处：他常常施惠于人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"给人好处：各集团公司根据互惠的原则，建立新的贸易关系。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬辞。用于对方施于自己的行为：日前惠临，失迎为歉。");
