INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"狮子。哺乳动物，身体约长3米，四肢强壮，有钩爪，掌部有肉块，毛黄褐色，雄狮的颈部有长鬣，吼声大，生活在林中，以捕其他动物为食。产于非洲和亚洲西部。");
