INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物名称。A. 紫苏。一年生草本植物，茎、叶紫色，茎、叶、籽都可药用。B. 白苏，也叫荏。一年生草本植物，花白色，唇形，籽可榨油。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"醒过来：春天来了，万物复苏。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"江苏省或苏州市的简称：苏绣受到人们的喜爱。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指须头下垂物：红色的锦旗下垂着金灿灿的流苏，美丽耀眼。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
