INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计量单位。A.长度单位：沙漠在十厘米以下，水分含量逐渐增大。B.重量单位：一分等于十厘，一厘等于十毫。C.面积(地积)单位：一亩等于十分，一分等于十厘。D.存款、借贷的利率：年利率一厘是每年百分之一，月利率一厘是每月千分之一。");
