INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"繁多：在浩如烟海的弹词唱本中，这个孤本被珍藏了下来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
