INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/143/蜗_wō.mp3", "蜗牛 蜗居 涡旋,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～蠃〕软体动物，壳淡玳瑁色，壳口边缘略翻出，生活于湖溪中。亦称“螺蛳”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～居〕喻窄小的住所。〔～螺〕软体动物，壳如笋状，螺层长，壳顶尖，生活于湖池中。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～牛〕软体动物，有螺旋形扁圆的硬壳，头部有两对触角。吃嫩叶，对农作物有害。某些种类可供食用。");
