INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细长而尖的毛。指毛笔。中国的秤或戥子上的提绳。中国市制计量单位，十毫等于一厘（长度、地积、重量单位）；一百平方毫等于一平方厘（面积单位）。方言，货币单位，角、毛。数量极少，一点儿（限用于否定式）。与某一物理量的单位连用时，表示该量的千分之一。");
