INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"皇帝：1368年，朱元璋在应天(今南京市)称帝，建立明朝，年号洪武。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"帝国主义的简称：文章通过对当时中国和世界上反帝反侵略的革命形势的分析，有力地论证了美帝侵华政策必将失败。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代指天神：当人们对一个问题认识不清时，说一句\"这是上帝安排的\"，实在是容易极了。");
