INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比较浓的液体。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29176_塌_22604.gif","13","左右","土","塌","Collapse","http://cdn.ococci.com/dict_ali/2022-02-23/1645618545478916162_653c50b6-c0db-5e07-c0fe-fd54e74ed72d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/26/塌_tā.mp3", "塌掉 塌方 塌陷 塌心 塌台,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"下垂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"倒（dǎo），下陷。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"安定，镇定。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/3306_颂_39042.gif","12","左右","页","颂","Song","http://cdn.ococci.com/dict_ali/2022-02-25/1645768811861623329_c994dbd3-63c9-532c-272f-d73bfe057aa6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sòng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/187/颂_sòng.mp3", "颂词 颂扬 颂歌 称颂 祝颂 歌颂 敬颂 赞颂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国周代祭祀时用的舞曲，配曲的歌词有些收在《诗经》里面，分“周颂”、“鲁颂”和“商颂”三类。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"赞扬：歌颂；颂词；赞颂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"以颂扬为内容的文章或诗歌：祖国颂；青春颂。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"祝愿：祝颂。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/83054_绩_32489.gif","11","左右","纟","绩","Achievement","http://cdn.ococci.com/dict_ali/2022-02-25/1645756998176903539_1bdf1444-81e8-51f5-8ace-3769c7a08358.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/绩_jì.mp3", "成绩 功绩 业绩 战绩 政绩 丰功伟绩 劳绩 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"功业，成果：献身于共产主义事业的人们，其英名和业绩将永远留在人民心中。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把麻捻成线或绳：后面是一座荒村野店，有一少女在那里纺绩。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35092_圃_22275.gif","10","全包围","囗","圃","Nursery","http://cdn.ococci.com/dict_ali/2022-02-23/1645628365298247657_014a70ae-d7da-bc3e-06de-4d49577f8b34.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/圃_pǔ.mp3", "东圃 书圃 井圃 仙圃 具圃 农圃 圃泽 圃田 圃畦 场圃,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"种植菜蔬、花草、瓜果的园子：圃田；菜圃；花圃；苗圃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指种植园圃的人：吾不如老圃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻某些事物丛集之处：文圃；图书之圃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"繁茂，茂盛：圃草（茂盛之草）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75200_卉_21321.gif","5","上下","十","卉","Hui","http://cdn.ococci.com/dict_ali/2022-02-25/1645766604234670211_d5e3bce5-b0f0-9493-b5fb-82896abc3c43.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/13/卉_huì.mp3", "花卉 卉木,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"本义：草的总称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓氏。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7108_蕾_34174.gif","16","上下","艹","蕾","Ray","http://cdn.ococci.com/dict_ali/2022-02-24/1645714257659504629_c72d6c65-596a-b8e5-5b86-cacc1a3e6f35.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lěi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/139/蕾_lěi.mp3", "花蕾 蓓蕾,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"含苞未放的花朵：他仿佛看见一片鲜花在自己面前破蕾开放。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93155_蕊_34122.gif","15","上下","艹","蕊","Rui","http://cdn.ococci.com/dict_ali/2022-02-24/1645678824552267568_42d869d7-d2b5-a92c-a0b5-17f76844a511.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ruǐ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/139/蕊_ruǐ.mp3", "花蕊 雌蕊 雄蕊,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"草木丛生。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"植物生殖器官的一部分：花蕊。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84143_玫_29611.gif","8","左右","攵","玫","Mei","http://cdn.ococci.com/dict_ali/2022-02-24/1645702950780732065_3f6efce1-c40a-8022-a4cb-70bcda550df5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"méi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/94/玫_méi.mp3", "玫瑰,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔～瑰〕a.美玉；b.落叶灌木，枝上有刺，花有紫红色、白色等多种，香味很浓，可做香料，花和根可入药。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/8966_茉_33545.gif","8","上下","艹","茉","Mo","http://cdn.ococci.com/dict_ali/2022-02-25/1645763033690617847_54c2f3be-6704-55ee-6627-891495ce37e6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mò", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/133/茉_mò.mp3", "茉莉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"茉莉：a.常绿灌木，叶卵形，花白色，很香，常用来熏制茶叶。b.一年生或多年生草本植物，花有红、白、黄、紫各色，果实圆形，成熟时黑色。根和种子可入药。花供观赏，可制化妆品。亦称“草茉莉”、“紫茉莉”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/83487_莉_33673.gif","10","上下","艹","莉","Li","http://cdn.ococci.com/dict_ali/2022-02-25/1645763930763864892_af48c24a-56a0-168f-5ca8-54259250e2bb.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"lì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/134/莉_lì.mp3", "茉莉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"人名用字。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"茉莉：植物名。常绿灌木。木犀科。夏季开白花，有浓香。花可薰制茶叶，又为提取芳香油的原料。亦指这种植物的花。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/83257_牡_29281.gif","7","左右","牜","牡","Mu","http://cdn.ococci.com/dict_ali/2022-02-25/1645763388140832933_265850ab-4baa-54f1-dbd8-eb6322517037.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/91/牡_mǔ.mp3", "牡蛎 牡丹 牡麻,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"雄性的鸟或兽，亦指植物的雄株，与“牝”相对：牡牛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"锁匙：牡钥。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丘陵。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/43824_丹_20025.gif","4","独体","丿","丹","Dan","http://cdn.ococci.com/dict_ali/2022-02-25/1645767195020147329_c98c5385-3035-08c2-2114-49c4d72240ef.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/丹_dān.mp3", "丹青 丹田 丹心 山丹 牡丹 仙丹 丹桂 炼丹 丹砂,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从前道家炼药多用朱砂，所以称为\"丹\"：毛泽东同志告诫全党同志不应该把马克思列宁主义书本上的某些个别字句看作现存的灵丹圣药。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"红色；赤色：道士常用丹砂炼药，想求长生不老。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/26848_棠.gif","12","上下","小","棠","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"táng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/棠_táng.mp3", "棠阴 棠梨 棠棣 海棠,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"木名。棠梨树。落叶乔木，约10米高，叶呈长圆形或菱形，叶柄、叶背及花序均有绒毛，开白花，果实小，呈球形，可做嫁接各种梨树的砧木。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93094_嗅_21957.gif","13","左右","口","嗅","Smell","http://cdn.ococci.com/dict_ali/2022-02-25/1645766845722167546_bbe42f23-8a27-7525-b3a0-53a127f27c8f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/19/嗅_xiù.mp3", "嗅觉 嗅神经,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"闻，用鼻子辨别气味：他嗅了嗅，感觉味道不对。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57709_奈_22856.gif","8","上下","大","奈","Nai","http://cdn.ococci.com/dict_ali/2022-02-23/1645621445419557636_819d3db9-1a16-73f5-9d16-820fb3dc7a6e.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/28/奈_nài.mp3", "奈何 百般无奈,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对付；处置：星离成恨事，云散奈愁何?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"无奈；怎奈：想回家，奈事未毕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"奈何，相当于\"怎样、怎么办、如何\"。A. 他从心底发出一声无可奈何的喟叹。B. 不管你怎么说，他就是不听，你又其奈他何?");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/26694_拯_25327.gif","9","左右","扌","拯","Zheng","http://cdn.ococci.com/dict_ali/2022-02-23/1645614662375210345_78d47259-5ecf-1b90-9e1c-3ea9bdde82db.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhěng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/52/拯_zhěng.mp3", "拯救,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"援救，救助：拯民于水火之中。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/97159_嘶_22070.gif","15","左中右","口","嘶","Hiss","http://cdn.ococci.com/dict_ali/2022-02-19/1645245567024391106_022f11bb-3a6c-f5f7-9d87-b9c1564dbbc0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/20/嘶_sī.mp3", "嘶叫 嘶哑 声嘶力竭,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"马叫：人喊马嘶，场面很是壮观。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"声音沙哑：连续上了三天课，老师的声音已有些嘶哑了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象声词：细微的嘶嘶声在空中流荡。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55675_哑_21713.gif","9","左右","口","哑","Dumb","http://cdn.ococci.com/dict_ali/2022-02-24/1645663683038765394_5ba96e36-e2a6-a036-46aa-c447c913935f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǎ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哑_yǎ.mp3", "哑巴 哑然 哑剧 哑谜 哑铃 哑巴亏 沙哑 嘶哑 哑口无言 哑然失笑 哑然无声 装聋作哑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因疾病或生理缺陷口不能说话：她在聋哑学校教书。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"嗓子干涩而发不出声音或发音困难：他把声音都喊哑了。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"炮弹、子弹等因故障打不响：不知什么原因，今天早上打出的都是哑炮。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"笑声：听了这话，大家不觉哑然失笑。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/哑_yā.mp3", "哑哑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"相当于现代汉语的“呀”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/27039_庞_24222.gif","8","半包围","广","庞","Pang","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"páng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/41/庞_páng.mp3", "庞大 庞杂 面庞 脸庞 庞然大物,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脸：花好比人的面庞，树好比人的姿态。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"大：这是一个庞大的家庭，儿女太多，又都成年。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多而杂乱：这本书的内容太庞杂。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/72499_级_32423.gif","6","左右","纟","级","Level","http://cdn.ococci.com/dict_ali/2022-02-25/1645743169394554936_12392b0c-6075-2bfa-e789-4c99714263b2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/级_jí.mp3", "级别 班级 上级 县级,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"等级：高级。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"年级：留级。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词，用于台阶、楼梯灯：十多级台阶。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"台阶：石级。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10479_链_38142.gif","12","左右","钅","链","Chain","http://cdn.ococci.com/dict_ali/2022-02-25/1645767473017983922_fa4163a5-0169-b9dd-bf95-c0ef7d2617e1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/178/链_liàn.mp3", "链子 链条 链环 手链 项链 铁链 锁链,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。计量海洋上距离的长度单位。1链等于185.2米，10链为1海里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用金属环连接起来的长条：石级上的铁链，似乎是从天上挂下来的。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/50785_攀_25856.gif","19","上下","手","攀","Pan","http://cdn.ococci.com/dict_ali/2022-03-02/1646187347455695069_50acf4c6-1e36-6a31-2540-9ef6fed8e570.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/57/攀_pān.mp3", "攀登 攀附 攀谈,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把着：他一把攀住我的肩膀，使劲拽我走。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拉关系：他还喜欢和不相干的人攀亲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"抓住东西往上爬：面前一道绝壁，几乎险不可攀。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"想办法接触：他想方设法与王处长攀谈。");
