INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小孩淘气；顽皮：几个小顽童，有的嬉皮笑脸，有的抹着眼泪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不易改变或动摇：他的顽固不化，你是明白的。");
