INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"见“胳膊”，上肢，近肩的部分。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bó", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/129/膊_bó.mp3", "赤膊 胳膊 臂膊,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"胳膊；膀子：韩麦尔先生踱来踱去，胳膊底下挟着那怕人的铁戒尺。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64735_瓶_29942.gif","10","左右","瓦","瓶","Bottle","http://cdn.ococci.com/dict_ali/2022-02-25/1645750142038870668_7189ded3-3f2f-0d84-b41b-a06e9c9c579c.mp3");
