INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一种容器，用以盛液体，一般口较小，颈细肚大，多用陶瓷或玻璃制成：瓶嘴上有一个很亮的钢盖子，可以打开一半盖。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词：老师手里拿着一瓶墨水。");
