INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"害怕；惊惶：她脸上显出恐怖的神色。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/23338_凭_20973.gif","8","上下","几","凭","With","http://cdn.ococci.com/dict_ali/2022-02-25/1645773747003256000_62cb4cf6-f514-8ded-a8cc-84488ce5579c.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"píng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/9/凭_píng.mp3", "凭证 任凭 凭借 凭空 凭信 听凭,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"证据：你空口无凭，诬陷好人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"身子靠在东西上：岳飞凭栏远眺祖国的大好河山，不由仰天长叹。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"帝国主义凭什么来欺压中国老百姓呢?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词。任意；随便；与\"任凭\"相同：郭全海站起来说：\"好吧，咱们都把马牵到这儿来，听凭她挑选。\"");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"介词，根据：请凭票入场。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/31094_欺_27450.gif","12","左右","欠","欺","Deceive","http://cdn.ococci.com/dict_ali/2022-02-11/1644546896718355058_b01f9502-edc3-8e4a-6646-aebce2e2ce77.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/73/欺_qī.mp3", "欺负 欺凌 欺压 欺骗 欺侮 自欺欺人 欺人太甚 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"欺压；欺凌：祖国受欺凌，人民的生命财产就得不到保障。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"骗；蒙混：他态度和蔼，童叟无欺。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/60515_掐_25488.gif","11","左右","扌","掐","Pinch","http://cdn.ococci.com/dict_ali/2022-02-10/1644435597133290811_6c73f568-e718-8ed3-cb3e-cb19908b3525.mp3");
