INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用指甲刻入截断或用拇指和另一个指头使劲捏、夹、按、切断：叶嫩绿色，仿佛掐得出水似的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言。量词。拇指和另一个指尖相对握着的数量：妈妈让杏叶去割一掐儿小白菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用手掌的虎口处紧紧卡住或按住：小战士一把掐住鬼子的喉咙。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93978_囊_22218.gif","22","上下","口","囊","Pouch","http://cdn.ococci.com/dict_ali/2022-02-24/1645672869175155934_4e1eefac-d121-fe6c-6a5c-d888e5da6fcd.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"náng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/囊_náng.mp3", "囊肿 囊括 囊空如洗 囊中物,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"口袋。〔～生〕藏语，中国西藏农奴主家的奴隶。亦称“朗生”。像口袋的东西。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"nāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/22/囊_nāng.mp3", "囊膪 囊揣 
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"猪的乳部肥而松软的肉，囊膪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"虚弱，懦弱，囊揣。");
