INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"黑红色");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yīn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/74/殷_yīn.mp3", "殷实 殷切 殷墟 殷勤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"富裕，富足。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"盛，大。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"深厚，恳切。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国朝代名，商代的后期，由盘庚起称“殷”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"众，多。");
