INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"平着扔出去。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"装；摆出。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用嘴表示鄙夷、不以为然或激动的一种表情。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"piē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/56/撇_piē.mp3", "撇开 撇弃,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丢开，抛弃。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"由液体表面舀取。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/65931_霉_38665.gif","15","上下","雨","霉","Mold","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"méi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/184/霉_méi.mp3", "霉天 霉雨 霉变 霉烂 霉斑 霉头 发霉 黑霉 倒霉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"低等植物，真菌的一类，常寄生在食物和衣服的表面，呈细丝状，有分枝，没有叶绿素霉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔倒（dǎo）霉〕遇事不利，遭遇不好。亦作“倒楣”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"食品、衣物等受了潮热长霉菌。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/53004_亏_20111.gif","3","上下","二","亏","Deficit","http://cdn.ococci.com/dict_ali/2022-02-11/1644558006071868805_3bee1ab3-b0cb-c22c-3f41-20b60ebbaf83.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/亏_kuī.mp3", "亏心 亏欠 亏本 亏空 亏损 亏待 亏折 亏耗 吃亏 多亏 幸亏 盈亏 理亏 哑巴亏,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"损耗；损失：这事吃亏的还是你自己。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"缺少，缺欠：这很自然，理亏胆怎么会壮?");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"侥幸之词：那事多亏了你，否则后果肯定不堪设想。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"反语。表示斥责或讥讽：亏你还是董事长，真不知道你是怎么\"懂事\"的!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"对不起：我一定不会亏了你。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/90242_拙_25305.gif","8","左右","扌","拙","Clumsy","http://cdn.ococci.com/dict_ali/2022-02-25/1645749533047484967_5fa96a72-5abb-0b38-8f22-a0ef39b151c0.mp3");
