INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"笨，不灵巧：笨拙。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"谦辞，称自己的：拙作。");
