INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"情形；状况。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36133_败.gif","8","左右","贝","败","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/败_bài.mp3", "失败 打败 腐败 战败 败仗 挫败 兵败如山倒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(事情)不成功，达不到预期目的：一篇文章成败，常常有很重要的关系。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"在战争或竞赛中失败。与\"胜\"相对：我们做不到知己知彼，就要打败仗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"取胜对方：在争夺战中，赵武灵王击败了胡人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"把事情搞砸：他这个人啊，成事不足，败事有余。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"消除：你应该煎几付中药来败一下火。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"凋残：寺庙年久失修，破败不堪。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/65758_恨_24680.gif","9","左右","忄","恨","Hate","http://cdn.ococci.com/dict_ali/2022-03-29/5423671000000093_1648539419454.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hèn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/46/恨_hèn.mp3", "愤恨 怀恨 仇恨 怨恨 憎恨 懊恨 可恨 雪恨 饮恨 遗恨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"怨；仇视：我恨那种把幸福建立在别人痛苦之上的小人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"悔恨；遗憾：我要尽全力去完成这件事，否则我将抱恨终身。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64128_帅_24069.gif","5","左右","巾","帅","Handsome","http://cdn.ococci.com/dict_ali/2022-02-25/1645770586000462653_776ce2e0-caa3-a132-4094-2742fcbfcdb6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shuài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/40/帅_shuài.mp3", "挂帅 将帅 统帅 元帅 主帅 帅才 帅气,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"军队中最高的指挥官：五代的皇帝和十国的统治者，原先都是手握重兵的将帅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"有气派：小秋子长得真帅。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
