INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"肌肉组织因腐烂而破了口。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"散乱，垮台。");
