INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30255_丑_19985.gif","4","独体","一","丑","Ugly","http://cdn.ococci.com/dict_ali/2022-02-25/1645743519065711188_407dec83-871a-7439-7b02-789fac810775.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/0/丑_chǒu.mp3", "丑态 丑恶 丑化 丑陋 家丑 献丑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"丑时，指夜里一点到三点。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"相貌难看；不好看：他忌讳别人说他长得丑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"地支的第二位：他儿子是辛丑年出生的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"戏剧角色名称：他是川剧界的名丑。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恶劣；令人厌恶：她的表演丑态百出。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/56845_豪_35946.gif","14","上下","豕","豪","Howe","http://cdn.ococci.com/dict_ali/2022-02-23/1645620028570297233_8323d801-bccb-8bfe-8a14-591ef35c5f8f.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"háo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/157/豪_háo.mp3", "豪爽 富豪 豪门 豪气 豪杰 豪华 豪壮 豪放 豪强 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)气魄大；直爽痛快，没有拘束的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(形)强横。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(名)具有杰出才能的人。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38893_韭.gif","9","独体","一","韭","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/韭_jiǔ.mp3", "韭菜 韭黄,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"韭菜。多年生草本植物，叶细长而扁，开白花。是一种普通蔬菜：她错把麦苗当韭菜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/94741_芥_33445.gif","7","上下","艹","芥","Mustard","http://cdn.ococci.com/dict_ali/2022-02-21/1645445866014159452_d35192ed-938f-4153-d1a7-1d3a21b13287.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"gài", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/芥_gài.mp3", "芥蓝 芥蒂 山芥 石芥 芥蓝 芥菜 土芥,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"一年生草本植物，芥菜的变种，叶大，表面多皱纹，叶脉显著，可食。亦作“盖菜”。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/芥_jiè.mp3", "草芥 芥子 毫芥 纤芥 浮芥 埃芥 芥舟,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"芥菜：一年或二年生草本植物，种子黄色，味辛辣，磨成粉末，称“芥末”，作调味品。按用途分为叶用芥菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"小草，喻轻微纤细的事物：草芥；纤芥；芥舟。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88871_芹_33465.gif","7","上下","艹","芹","Celery","http://cdn.ococci.com/dict_ali/2022-02-19/1645256294265036243_933f67ff-98f1-22bd-dfa4-37ebae3d0e89.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qín", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/芹_qín.mp3", "芹菜 药芹,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"芹菜：一年生或二年生草本植物，羽状复叶，小叶卵形，叶柄肥大，绿色或黄白色，花绿白色，果实扁圆形，是普通蔬菜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84254_蒜_33948.gif","13","上下","艹","蒜","Garlic","http://cdn.ococci.com/dict_ali/2022-02-22/1645529508862225213_67114910-9e24-5a5e-5cf9-566c86b89bff.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"suàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/137/蒜_suàn.mp3", "大蒜 蒜苗 蒜头,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多年生草本植物，地下鳞茎分瓣，按皮色不同分为紫皮种和白皮种。味辣，有刺激性气味，可食用或供调味，亦可入药（通称“大蒜”）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/84432_椒_26898.gif","12","左右","木","椒","Pepper","http://cdn.ococci.com/dict_ali/2022-02-25/1645749657058121981_241a92b0-8cf3-5870-044f-14ee9d22bce7.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jiāo", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/67/椒_jiāo.mp3", "椒盐 辣椒 菜椒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔花～〕ａ．落叶灌木或小乔木，果实球形，暗红色，种子黑色，可供药用或调味；ｂ．这种植物的果实，简称“椒”，如“～盐”。“～酒”。“～桂”（常用来喻贤人）。〔胡～〕ａ．常绿藤本植物，果实球形，红色，成熟后红黑色，味辛辣，可供药用或调味；ｂ．这种植物的果实。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/48252_藕_34261.gif","18","上下","艹","藕","Lotus root","http://cdnmu.gurobot.cn/saodubi/dict/audio/Lotus_root.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ǒu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/140/藕_ǒu.mp3", "藕丝 藕煤 藕花 藕粉 藕断丝连,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"莲的地下茎，肥大有节，中间有管状小孔，折断后有丝，可食。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34223_薯.gif","16","上中下","艹","薯","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/薯_shǔ.mp3", "薯蓣 薯莨 薯莨绸 甘薯 红薯 马铃薯,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"甘薯、马铃薯等薯类作物的统称：那时，能吃一顿红薯稀饭，就觉得很高兴了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/95650_芋_33419.gif","6","上下","艹","芋","Taro","http://cdn.ococci.com/dict_ali/2022-02-21/1645433721554354070_b41a7a70-aee8-952a-cde6-391775d0bdd2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/132/芋_yù.mp3", "薯芋 土芋 煨芋 轩芋 芋母 芋艿 芋子 芋奶 洋芋 芋尹 芋妳 芋头,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多年生草本植物之一。块茎呈椭圆形或卵形，含有丰富的淀粉，可做菜。又名“芋艿”，通俗“芋头”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指甘薯、马铃薯等某些书类植物：山芋（甘薯）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88107_塞_22622.gif","13","上中下","土","塞","Plug","http://cdn.ococci.com/dict_ali/2022-02-24/1645700991428709913_d883f31d-6040-5f28-54c9-05f3df049524.mp3");
