INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"边界上险要之处。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"sāi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/26/塞_sāi.mp3", "瓶塞 塞住 耳塞 塞车 塞尺 塞子 活塞 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"堵住器物口的东西。");
