INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"远行；远去：红军不怕远征难，万水千山只等闲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"访求：按照征稿启事的地址，他寄去了自己的作品。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用武力制服：六月天兵征腐恶，万丈长缨要把鲲鹏缚。");
