INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"统治者认为维持正常秩序的必不可少的行为规范：纲纪；纲常（“三纲”、“五常”的简称，是一种封建道德）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"网上的总绳。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻事物的主要部分：当时，决定工作方针，颁发每周工作大纲，都是由三厅总负责。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"生物学中将同一门的生物按照彼此相似的特征和亲缘关系再分成若干群，每一群就叫做一纲：脊椎动物亚门分为鱼、鸟、哺乳等纲。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"中国从唐代起转运大批货物所行的办法：一纲（把货物分批运行，每批车辆船只的计数编号）；生辰纲。");
