INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/73401_埋_22475.gif","10","左右","土","埋","Bury","http://cdn.ococci.com/dict_ali/2022-02-23/1645605180129122030_d88114a7-58f6-06a9-367b-4c349313b880.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mái", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/24/埋_mái.mp3", "埋伏 埋名 埋没 埋汰 埋葬 埋藏 掩埋,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"特指葬：埋忠骨。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〈喻〉专心，下功夫：埋头苦干。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"埋没：a.掩埋：这儿的草地，已被流沙～没了。b.使人才、功绩、作用等显露不出来：～没人才。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"将东西放在坑里用土盖上：埋藏。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"隐藏：隐姓埋名。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/埋_mán.mp3", "埋怨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因不如意而对人或事物不满，责怪他人：他自己错了，反而埋怨别人。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38231_澎_28558.gif","15","左中右","氵","澎","Peng","http://cdn.ococci.com/dict_ali/2022-02-24/1645708570473995404_c466456b-a591-1289-ea5f-b79a032d9b81.mp3");
