INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30869_湃_28227.gif","12","左右","氵","湃","Pai","http://cdn.ococci.com/dict_ali/2022-02-23/1645617318517600628_89bf0125-7dc5-6331-5883-21d7615d71de.mp3");
