INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"形容波涛撞击，如“奔腾澎湃”；");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"喻声势浩大，气势雄伟，如“热情澎湃的诗篇”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔澎湃〕");
