INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不锋利，不快，引申为不顺利。笨，不灵活。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/35587_描_25551.gif","11","左右","扌","描","Trace","http://cdn.ococci.com/dict_ali/2022-02-23/1645609860358131976_6105daf5-8327-772f-bdf6-a7c8f5db31a9.mp3");
