INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"道路，特指门内当中的路。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"旋转：“若磨石之～”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"郊外的地方：“鲁人三郊三隧”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古同“燧”，边塞设置的守望烽火的亭子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"隧道：在山中或地下凿成的通路。亦称“隧洞”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/6762_衍_34893.gif","9","左中右","行","衍","Yan","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yǎn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/147/衍_yǎn.mp3", "繁衍 博衍 衍变 衍生 敷衍,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"延长，开展：衍绎；衍生；推衍；展衍；敷衍；衍生物。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"多余的（指文字）：衍文（书籍中因缮写、刻板、排版错误而多出来的字句）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"低而平坦之地：衍沃（土地平坦肥美，亦作“沃衍”）。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29453_吨_21544.gif","7","左右","口","吨","Tons","http://cdn.ococci.com/dict_ali/2022-02-25/1645763151052063943_10a99b03-f8c0-7073-62cf-d6dcd3155016.mp3");
