INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"重量单位，公制一吨等于1000公斤。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"83立方米（合100立方英尺）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"计算船只容积的单位，一吨等于");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/86631_颅_39045.gif","11","左右","页","颅","Cranium","");
