INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脑盖，亦指头：他颅内出血需要及时做手术。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/72487_膨_33192.gif","16","左中右","月","膨","Bulge","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"péng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/130/膨_péng.mp3", "膨大 膨胀,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"膨胀。a.物体的体积增大：气体受热膨胀。b.比喻数量增加：外债数额急剧膨胀。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/34693_捷_25463.gif","11","左右","扌","捷","Jie","http://cdn.ococci.com/dict_ali/2022-02-24/1645709855454462157_c6382c0c-fbc7-435a-dd7c-2e381825ec3d.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/53/捷_jié.mp3", "捷讯 捷径 捷报 靠捷 捷足先登 矫捷 敏捷 迅捷,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"快速；灵活：他十分敏捷地越过了1.85米的横杆。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"便捷；方便：只有赶快学用结合，才是排除一切障碍的最捷的路径。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"获胜；成功：后死诸君多努力，捷报飞来当纸钱。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/36767_辟.gif","13","左右","辛","辟","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/辟_pì.mp3", "辟谣 精辟 开辟,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"开拓；开创；开发：你到电视台后，还可以另辟栏目。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"透彻：文中的议论和抒情，也极为精辟和感人。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"驳斥；他站出来辟谣，说明真相。");
