INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chòu", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/130/臭_chòu.mp3", "臭虫 发臭 臭味 臭气 臭球 臭骂一顿,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"狠狠地：臭骂一通。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"不好闻的气味，与“香”相对：臭味儿；恶臭。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指子弹、炮弹坏，失效：臭火。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"惹人厌恶的：臭美；臭名远扬。");
