INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"tàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/碳_tàn.mp3", "碳化 碳酸 一氧化碳 二氧化碳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"非金属元素。符号C，无臭无味的固体。是构成有机物的主要成分，在工业和医药上用途都很广：碳族元素原子的最外电子层上有四个电子。");
