INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"疼痛：当他知道儿子犯了罪，痛心疾首地说：\"都怪我太宠他了。\"");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恨：这个疾恶如仇的姑娘，最见不得邪恶和阴谋。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"快，迅速：人民解放军如疾风扫落叶一般，消灭了国民党的残余部队。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"病；身体不舒适：身上生一点小疮……而最后变成了致命之疾。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"苦；痛苦。");
