INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水大无边无际的样子：浩瀚的大海漫无边际。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"因水过满而溢出：水漫过堤坝，冲出山谷，直逼山庄。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"覆盖：她突然想起了家，于是眉头皱了一下，阴云漫上了她的脸。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"副词。你这种作法，漫说群众不满，连领导班子内也有意见。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"到处都是：漫山遍野的山茶花开得真繁啊!");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"红军在漫长的长征路上，英勇顽强，终于取得了胜利。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"铺设：他说着，一头躺在砖漫的地上，四肢用力一伸展，真是舒服极了。");
