INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/78/浙_zhè.mp3", "浙江,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浙江省的简称：大运河南越长江，流经江、浙；北越黄河，流经鲁、冀，烟波浩渺几千里。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"水名。即钱塘江，是浙江省第一大河流：百姓就在宫门外欢呼，声音正好像浙水的涛声一样。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/26324_簇_31751.gif","17","上下","竹","簇","Cluster","http://cdn.ococci.com/dict_ali/2022-02-22/1645506186159398078_7910dc60-7798-92e3-c78b-fece35c1f8f4.mp3");
