INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(量)用于聚集成团的东西。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(名)聚拢在一块儿，聚成一团。");
