INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"屁股。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/88161_漆_28422.gif","14","左右","氵","漆","Lacquer","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/82/漆_qī.mp3", "漆工 漆黑 朱漆 雕漆 黑漆漆 漆黑一团 如胶似漆,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"木名。落叶乔木，羽状形复叶，初夏开花，果实扁圆，树汁可为涂料。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用漆树汁或其他物质制成的涂料：汉朝铸铜和制漆工艺传到了朝鲜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用漆涂：他把大门修好并漆成红色。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/23211_蜿_34623.gif","14","左右","虫","蜿","","");
