INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蛇爬行的样子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"弯弯曲曲地延伸。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/85387_蜒_34578.gif","12","左右","虫","蜒","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/143/蜒_yán.mp3", "海蜒 蜿蜒 蚰蜒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蜒蚰。虫名。又名\"鼻涕虫\"、\"蛞蝓\"。蛞蝓科。形像去壳蜗牛，有触角。身体能分泌沾液，爬行后留下银白色的痕迹。对农作物有害。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"龙蛇曲折爬行的样子：她自己带着娃子，从渭北爬蜒到这南山根儿来了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/42359_恭_24685.gif","10","上下","小","恭","Gong","");
