INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qín", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/12/勤_qín.mp3", "勤奋 勤俭 勤恳 勤苦 勤快 勤劳 勤勉 勤务 勤学 勤杂 勤务兵 出勤 地勤 后勤 考勤 空勤 内勤 缺勤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"上班，事务：勤务。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"担心，忧虑：勤恤。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"经常：勤密。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"做事尽力，不偷懒：勤劳。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"帮助：勤王。");
