INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文言语气助词，表示肯定的语气：有厚望焉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"与介词“于”加代词“是”相当：心不在焉；不复出焉。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"连词，乃，才：必知乱之所自起，焉能治之。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"文言疑问代词，怎么，哪儿：且焉置土石？");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/80354_卒_21330.gif","8","上中下","十","卒","Pawn","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cù", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/13/卒_cù.mp3", "卒卒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"同“猝”。仓促，急速：卒倒；卒暴；卒然（忽然，突然）。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/13/卒_zú.mp3", "暴卒 吏卒 卒然 卒读 卒业 戎卒 出卒,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"完毕，终了：卒岁（度过一年）；卒业（毕业）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"终于：卒胜敌军。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"死亡：病卒；生卒年月。");
