INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wū", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/16/呜_wū.mp3", "呜咽 呜呼 呜咿 呜哨 咪呜 喑呜 呜呼哀哉 呜呜啕啕,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"呜呼。A. 叹词：呜呼!古之临民者，一独夫也。B. 借指死亡：他想，如果他这样熬到天亮，就是不一命呜呼，也会半死。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"象声词：\"呜\"的一声，火车进了山洞。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/82203_糠_31968.gif","17","左右","米","糠","Chaff","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kāng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/118/糠_kāng.mp3", "糠壳 糠秕 糠油 糠面 米糠 秕糠 筛糠 糟糠,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"稻、麦、谷子等作物子实脱下的皮或壳：那时候，人民常常是吃糠咽菜。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"空，质地松而不实：糠心萝卜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/10240_栓_26643.gif","10","左右","木","栓","Bolt","http://cdn.ococci.com/dict_ali/2022-02-12/1644650799945291726_fc0989d6-ee9a-d96b-9c7e-5376f087d6f1.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shuān", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/65/栓_shuān.mp3", "栓子 栓剂 栓皮 栓塞 枪栓 消火栓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"器物上可以开关的机件：他拉开枪栓，准备射击。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"塞子，泛指形状像塞子一样的东西：栓剂。");
