INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用绳把东西缠紧打结。他被绳子捆着手，肩上流着血，脸上有着一块块搏斗的伤痕。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"量词。相当于\"束\"：这捆旧报纸没用了，把它拿去卖了吧!");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/52418_绑_32465.gif","9","左中右","纟","绑","Tie","http://cdn.ococci.com/dict_ali/2022-02-25/1645771685060297873_2806239a-564a-7052-9d41-e5ec1894846b.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bǎng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/122/绑_bǎng.mp3", "绑扎 绑架 绑匪 绑票 绑缚 松绑 捆绑 五花大绑 绳捆索绑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用绳、带等捆扎或缠绕：像这样的货，连有经验的老水手也绑不好。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/55329_劫_21163.gif","7","左右","力","劫","Robbery","http://cdn.ococci.com/dict_ali/2022-02-20/1645369038453643532_eae324ea-7eed-f5a9-ab70-c657ad69af63.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"jié", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/11/劫_jié.mp3", "劫寨 劫狱 劫营 劫洗 劫后余生 劫夺,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"威逼，胁制。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"灾难。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"强取，掠夺。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/21314_毙_27609.gif","10","上下","比","毙","Shoot","http://cdn.ococci.com/dict_ali/2022-02-24/1645711718233000151_1d29f0d8-2e5d-30aa-89ce-05c3e0f195b6.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bì", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/74/毙_bì.mp3", "毙命 击毙 枪毙,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"死：隋炀帝使用几十万民工修运河，很多人倒毙在路上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用枪打死：柔石和其他23人，已于二月七日夜或八日晨，在龙华警备司令部被枪毙了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38004_扒_25170.gif","5","左右","扌","扒","Pick","http://cdn.ococci.com/dict_ali/2022-02-25/1645764004479702405_0f8c7d4b-c563-3934-c6a7-2b126eb497b5.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"pá", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/51/扒_pá.mp3", "扒草 扒痒 扒羊肉,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"用耙搂，聚拢。搔，抓。炖烂，煨烂。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"bā", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/扒_bā.mp3", "扒开 扒掉 扒皮,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"依附、靠着某物：扒在桌子上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"刨；挖；拆（东西）：从泥堆里扒出来。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"拨动：扒开草丛。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"脱掉；剥（bāo）：扒掉衣服、扒皮。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/59210_尸_23608.gif","3","独体","尸","尸","Corpse","http://cdn.ococci.com/dict_ali/2022-02-24/1645704286477930071_89d02c12-a9fc-db94-449a-ec0731a56231.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/36/尸_shī.mp3", "尸体 尸骨 尸检 尸身 尸首 尸骸 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"死人的身体。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔尸位〕空占着职位而不做事。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"古代祭祀时，代表死者受祭的人。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99243_徽_24509.gif","17","左中右","彳","徽","Emblem","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"huī", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/44/徽_huī.mp3", "徽帜 徽章 徽墨 徽剧 徽号,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"标志，符号。美好的。〔～州〕旧地名，在今中国安徽省歙县。简称“徽”，如“～墨”。系琴弦的绳，后用做抚琴标记的名称，古琴全弦共十三徽。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93587_谜_35868.gif","11","左右","讠","谜","Enigma","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mèi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/谜_mèi.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"方言。谜语:猜谜儿；破谜儿。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/156/谜_mí.mp3", "谜团 谜语 谜面 谜底 字谜 猜谜 哑谜 诗谜 藏谜,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"谜语。暗射事物或文字等供人猜测的隐语：她是一个猜谜专家。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"比喻还没有弄明白或难以理解的事物：当时的人们，到底用什么巧手段把棺材悬挂到峭壁，如今还是个谜。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/16205_唇_21767.gif","10","半包围","口","唇","Lips","http://cdn.ococci.com/dict_ali/2022-02-24/1645715602212730166_39370f23-be3a-b6e9-1af6-52341e1dcad0.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"chún", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/17/唇_chún.mp3", "下唇 嘴唇 唇舌 唇齿 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(名)人或某些动物口的周围的肌肉部分。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/93379_尚_23578.gif","8","上下","小","尚","Shang","http://cdn.ococci.com/dict_ali/2022-02-28/1646032951872580733_8020d180-3f05-60fe-ff3f-05e12675b4d2.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"shàng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/35/尚_shàng.mp3", "崇尚 风尚 高尚 时尚 尚方宝剑 尚且,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"尊崇；崇尚：在近代，梁启超等人高倡尚武精神。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/38161_荤_33636.gif","9","上下","艹","荤","Meat","http://cdn.ococci.com/dict_ali/2022-02-25/1645764983788312269_6dde587c-367c-7c50-47b0-495e211abc60.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"hūn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/134/荤_hūn.mp3", "荤菜 荤素 吃荤 开荤,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"佛教徒称葱蒜等有特殊气味的菜：五荤（有几种说法，大致指葱、蒜、韭、薤、芫荽等。亦称“五辛”）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"肉食：荤菜；荤素；吃荤；开荤。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指低级、粗俗的语言：这人说着说着就带上了荤字儿。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64252_倔_20500.gif","10","左右","亻","倔","Stubborn","http://cdn.ococci.com/dict_ali/2022-02-19/1645279502528587142_9cc6d15d-082a-c5a5-a546-d9700f6dac78.mp3");
