INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(性情)顽强；固执：你这个人太骄傲，太倔强。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"juè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/5/倔_juè.mp3", "倔头 倔巴 倔脾气 倔头倔脑,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"性格耿直执拗，言语行动生硬不随和：莲妞是个倔性子人。");
