INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔嘹亮〕声音响亮，如“歌声嘹亮”、“嘹亮的军号声”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔嘹唳〕响亮而漫长的声音，如“远而听之，若游鸳翔鹤，嘹唳飞空。”");
