INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dèng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹬_dèng.mp3", "蹭蹬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蹭蹬:路途险阻难行。比喻困顿不顺利。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"dēng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/162/蹬_dēng.mp3", "蹬踏 踢蹬,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"踩，踏：小王蹬在阳台上想伸手摘朵玫瑰花。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"穿（鞋、裤子等）：蹬上裤子。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"腿或脚向脚底方向狠狠用力：翠鸟蹬开苇杆，像箭一样飞过去叼起小鱼。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/75863_妨_22952.gif","7","左右","女","妨","Just in case","http://cdn.ococci.com/saodubi/dict/hanzi_fanyi_audio/J/Just in case.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"fáng", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/29/妨_fáng.mp3", "妨害 妨碍,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"阻碍，伤害。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"迷信的人指某人或某物对人不利。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/97797_搓_25619.gif","12","左右","扌","搓","Rub","http://cdn.ococci.com/dict_ali/2022-02-25/1645742644294801630_0c8c4efb-19e6-4fec-98a6-409208dd4414.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"cuō", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/55/搓_cuō.mp3", "搓手 搓澡 搓板 搓绳子 ,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"双手摩擦：孩子们搓呀、洗呀，可认真了。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/89379_葵_33909.gif","12","上下","艹","葵","Aoi","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"kuí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/137/葵_kuí.mp3", "葵花 葵扇 葵花子 海葵 蒲葵 向日葵,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔向日葵〕一年生草本植物，茎很高，开大黄花，花常朝向太阳，子可食，亦可榨油。简称“葵”，如“葵花”，“葵心”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔冬葵〕一年生草本植物，果实扁圆形。种子、根、茎、叶均可入药。简称“葵”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔蒲葵〕常绿乔木，叶大，大部分掌状分裂，裂片长披针形，木材可制器具，叶可做蓑、笠及扇。简称“葵”，如“葵扇”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔蜀葵〕多年生草本植物，花有红、紫、白等色，根可入药。亦称“胡葵”、“吴葵”、“一丈红”。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔锦葵〕一年生或多年生草本植物，夏季开淡紫色或白色花，供观赏。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/99788_祈_31048.gif","8","左右","礻","祈","Pray","http://cdn.ococci.com/dict_ali/2022-02-24/1645703941838190940_82ae1bc6-9225-a054-23e4-ed7ece902367.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"qí", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/108/祈_qí.mp3", "祈求 祈望 祈祷 仰祈,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"请求：祈求。");
