INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"给予;馈赠：相遗以水。——《韩非子·五蠹》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"送交;交付：遗赵王书。——《史记·廉颇蔺相如列传》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"输送：强国之民，父遗其子，兄遗其弟，妻遗其夫，皆曰:“不得，无返!”——《商召书》。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"加给：王事敦我，政事一埤遗我。——《诗·邶风》");
