INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔汹涌〕水势很大，向上涌。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔汹汹〕ａ．波涛声，如“波声汹汹”。ｂ．形容喧扰，如“天下汹汹”，“议论汹汹”；ｃ．形容声势很大（含贬义），如“气势汹汹”，“来势汹汹”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/30604_维_32500.gif","11","左右","纟","维","V","http://cdn.ococci.com/dict_ali/2022-02-25/1645770455228950025_68409557-bc3e-88e0-7f49-ce31e5f78851.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wéi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/123/维_wéi.mp3", "思维 维护 维持 维修 纤维 维系 恭维 维生素 维纶,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"系；连接：政治想维系现状使它统一，文艺促进社会进化使它渐渐分离。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"语助词。齐白石画虾，每一笔都经过无数次细心观察，反复练习，到了维妙维肖的境界。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"保持：联合国为维护世界和平，缓和国际紧张局势发挥了积极的作用。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"姓。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"数学名词。几何学及空间理论的基本观点：直线是一维的，平面是二维的，普通空间是三维的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"阿婆中断的思维被稚气的声音唤醒。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/42391_酣_37219.gif","12","左右","酉","酣","Mighty","http://cdn.ococci.com/dict_ali/2022-02-23/1645615708406332023_40e1f963-31e0-be26-49c7-826db82c839f.mp3");
