INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"尽量，痛快：酣畅；酣眠。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"酒喝得很畅快：酣醉；酒酣耳热。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"浓，盛：酣春（春色正浓）。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"（战斗）激烈：奔腾急，万马战犹酣。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/47184_械_26800.gif","11","左右","木","械","Weapons","http://cdn.ococci.com/dict_ali/2022-02-23/1645547159723097112_395ba4b3-0d09-e0cd-7a96-d3bbdbb81053.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"xiè", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/66/械_xiè.mp3", "械斗 械具 械器 军械 机械 枪械 器械 缴械,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"器具；器械：他们从敌人手中夺得机械，并能熟练地掌握运用。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"武器：要不然，我们就会自己缴自己的械。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/57131_岗_23703.gif","7","上下","山","岗","Gang","http://cdn.ococci.com/dict_ali/2022-02-22/1645526745423140153_04be0177-7088-a974-6df3-1c940d6e6bc6.mp3");
