INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"像山一样高起的土石坡：前年，他们在四平作战的时候，工事就修在这个山岗上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"岗哨，岗卡：她在站暗岗。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"泛指职位：马连福在队长的岗上站了好几年，当然也有一定的群众基础。");
