INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/29427_亩_20137.gif","7","上下","亠","亩","Mu","http://cdn.ococci.com/dict_ali/2022-02-25/1645763388140832933_265850ab-4baa-54f1-dbd8-eb6322517037.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"mǔ", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/1/亩_mǔ.mp3", "亩产 亩数 公亩 田亩 市亩,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"我国土地面积单位。一亩为六十平方丈，合十五分之一公顷：只要有水源，单新疆尚有一亿亩荒地可以开垦。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/98785_吩_21545.gif","7","左右","口","吩","Phenol","");
