INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"指派；嘱告：萧队长吩咐把所有的子弹收集拢来。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/7221_榨_27048.gif","14","左右","木","榨","Squeeze","http://cdn.ococci.com/dict_ali/2022-02-24/1645678234170827849_6eaf581f-253f-8c84-6ac5-267df42db553.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"zhà", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/69/榨_zhà.mp3", "榨取 榨油 榨菜 压榨 油榨 酒榨,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挤压汁液的器具：这是一间榨油厂，屋里放了几台榨油机。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"挤压汁液：我们用桐子榨油来点灯。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/64955_榴_27060.gif","14","左右","木","榴","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"liú", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/69/榴_liú.mp3", "榴火 榴弹炮 石榴,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"石榴。A. 果树名。落叶灌木或小乔木。种子肉质层，可鲜食，也可以加工成清凉饮料。其花鲜红似火，可观赏。果皮可入药。B. 这种树结果实：四川会理盛产石榴。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/20998_矮_30702.gif","13","左右","矢","矮","Short","http://cdn.ococci.com/dict_ali/2022-02-25/1645774745028396386_316bef11-ad74-7e2e-01cd-a08df365c9cb.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"ǎi", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/105/矮_ǎi.mp3", "低矮 矮子 矮小 矮墙 矮胖 高矮 矮凳,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"高度低：他坐在一个矮凳子上。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"身材短：他长得又矮又瘦。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"(级别、地位)低：我们同在一个学校，他比我矮两个年级。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/39740_箩_31657.gif","14","上下","竹","箩","Basket","http://cdn.ococci.com/dict_ali/2022-02-25/1645764890864196754_15758b5f-0ae0-7964-84ef-7f67dd3a6a96.mp3");
