INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/60417_蔓_34067.gif","14","上下","艹","蔓","Vine","http://cdn.ococci.com/dict_ali/2022-02-24/1645677565544456647_d8a45316-037c-24a1-33a3-5bc5e0267722.mp3");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"màn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/138/蔓_màn.mp3", "蔓延 蔓生 蔓草,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蔓生植物的枝茎，木本曰藤，草本曰蔓：就在草蔓丛生，土石杂错的隙里，淌出碗口大一股泉水。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蔓延，滋生：一支红梅横斜过来，不枝不蔓，随意点染。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wàn", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/138/蔓_wàn.mp3", "藤蔓 瓜蔓,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"细长能缠绕的茎：藤蔓；瓜蔓。");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"wán", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/191/蔓_wán.mp3", ",");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"蔓菁：芜箐。");
