INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"〔柜柳〕落叶乔木，羽状复叶，小叶长椭圆形，枝韧，可以编筐。性耐湿、耐碱，可固沙，多栽植在路旁做行道树。亦称“元宝枫”、“杞柳”。");
