INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"跟随在一起，在旁边做伴。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"增加的，非主要的。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"从旁协助，辅佐。");
