INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"恭敬地用手捧着送上：他对老人又是端茶，又是奉烟。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"信奉；推崇：大家都乐于得到他编写的书，并奉为典型。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"敬辞。用于自己的言行涉及到对方时：如果先生愿意去，我当然可以奉陪。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"伺候：奉养老人是我们的传统美德。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"接受：队伍奉命开赴前线。");
