INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"芝草，即灵芝。菌盖肾脏形，赤褐色或暗紫色，有环纹、光泽，生枯木上，中医入药，有滋补作用：古人认为芝草一年三秀，食之可以延年益寿。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"香草，即白芷。");
