INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物，形状像鹿，毛较粗，头上无角，雄的有长牙露出嘴外。皮可制革（亦称“牙獐”）");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/91504_猕_29461.gif","11","左中右","犭","猕","","");
