INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物，猴的一种，上身皮毛灰褐色，腰部以下澄黄色，面部微红色，尾短，四肢都像人。以野果、野菜等为食物。古亦称“母猴”、“沐猴”。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/54610_猿_29503.gif","13","左右","犭","猿","Ape","http://cdn.ococci.com/dict_ali/2022-02-24/1645674065557860007_03938111-5dff-1e86-0f42-59f5c7c5248b.mp3");
