INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"哺乳动物，与猴相似，比猴大，颊下没有囊，没有尾巴，猩猩、大猩猩、长臂猿等都是。");
INSERT INTO hanzi_dict (copy, strokesNum, structure, radicals, hz, en_word, en_audio_url) VALUES ("http://cdnmu.gurobot.cn/saodubi/dict/gif1/gif/32822_耶.gif","8","左右","耳","耶","","");
INSERT INTO polyphone (hanzi_id, pinyin, audio, CombineWords) VALUES (@id,"yē", "http://cdnmu.gurobot.cn/saodubi/danzi_audio/audio/103/耶_yē.mp3", "耶稣 耶和华 耶稣教,");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"耶稣：基督教徒所信奉的救世主，即基督。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"耶和华：希伯来语Jehovah的音译。希伯来人的最高的神。基督教《旧约》中用做上帝的别称。");
INSERT INTO polyphone_explanations (polyphone_id, explanation) VALUES (@id,"耶稣教：我国对基督教新派的称呼，即新教。耶稣教于十九世纪初年传入中国。");
